-- Poems batch 20
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('f35edd89-6a81-46b6-b734-cb2db5918609','春寢','白居易','唐','唐诗','tang','','[]','何處春暄來？微和生血氣。',72,'全唐诗/poet.tang.22000.json','["何處春暄來？微和生血氣。", "氣熏肌骨暢，東窗一昏睡。", "是時正月晦，假日無公事。", "爛熳不能休，自午將及未。", "緬思少健日，甘寢常自恣。", "一從衰疾來，枕上無此味。"]'),
('ed2ffe0c-5054-45a5-847f-b62a61260316','睡起晏坐','白居易','唐','唐诗','tang','','[]','後亭晝眠足，起坐春景暮。',72,'全唐诗/poet.tang.22000.json','["後亭晝眠足，起坐春景暮。", "新覺眼猶昏，無思心正住。", "澹寂歸一性，虛閑遺萬慮。", "了然此時心，無物可譬喻。", "本是無有鄉，亦名不用處。", "行禪與坐忘，同歸無異路。"]'),
('ee84636a-1c29-4967-9a08-951d69408a35','詠懷','白居易','唐','唐诗','tang','','[]','盡日松下坐，有時池畔行。',48,'全唐诗/poet.tang.22000.json','["盡日松下坐，有時池畔行。", "行立與坐臥，中懷澹無營。", "不覺流年過，亦任白髮生。", "不爲世所薄，安得遂閑情。"]'),
('ba68e8da-a3c1-41de-b093-58d624de3765','春遊二林寺','白居易','唐','唐诗','tang','','["\u5e90\u5c71"]','下馬二林寺，翛然進輕策。',132,'全唐诗/poet.tang.22000.json','["下馬二林寺，翛然進輕策。", "朝爲公府吏，暮作靈山客。", "二月匡廬北，冰雪始消釋。", "陽叢抽茗芽，陰竇洩泉脈。", "熙熙風土暖，藹藹雲嵐積。", "散作萬壑春，凝爲一氣碧。", "身閑易飄泊，官散無牽迫。", "緬彼十八人，古今同此適。", "是年淮寇起，處處興兵革。", "智士勞思謀，戎臣苦征役。", "獨有不才者，山中弄泉石。"]'),
('691aeeaf-8447-480f-8d17-4a973d0c51a8','出山吟','白居易','唐','唐诗','tang','','[]','朝詠遊仙詩，暮歌采薇曲。',48,'全唐诗/poet.tang.22000.json','["朝詠遊仙詩，暮歌采薇曲。", "臥雲坐白石，山中十五宿。", "行隨出洞水，迴別緣巖竹。", "早晚重來遊，心期瑤草綠。"]'),
('5bafab5b-a689-405d-b2d2-00b1a82e6a3e','歲暮','白居易','唐','唐诗','tang','','[]','已任時命去，亦從歲月除。',48,'全唐诗/poet.tang.22000.json','["已任時命去，亦從歲月除。", "中心一調伏，外累盡空虛。", "名宦意已矣，林泉計何如。", "擬近東林寺，溪邊結一廬。"]'),
('ca63a7bb-4df6-4377-9084-762bfbced7a9','聞早鶯','白居易','唐','唐诗','tang','','[]','日出眠未起，屋頭聞早鶯。',84,'全唐诗/poet.tang.22000.json','["日出眠未起，屋頭聞早鶯。", "忽如上林曉，萬年枝上鳴。", "憶爲近臣時，秉筆直承明。", "春深視草暇，旦暮聞此聲。", "今聞在何處，寂莫潯陽城。", "鳥聲信如一，分別在人情。", "不作天涯意，豈殊禁中聽。"]'),
('61506a5d-2957-4a72-9861-7dc54564020f','栽杉','白居易','唐','唐诗','tang','','[]','勁葉森利劒，孤莖挺端標。',96,'全唐诗/poet.tang.22000.json','["勁葉森利劒，孤莖挺端標。", "纔高四五尺，勢若干青霄。", "移栽東窗前，愛爾寒不凋。", "病夫臥相對，日夕閑蕭蕭。", "昨爲山中樹，今爲檐下條。", "雖然遇賞玩，無乃近塵囂。", "猶勝澗谷底，埋沒隨衆樵。", "不見鬱鬱松，委質山上苗。"]'),
('23bdea01-88fa-4e89-9923-747bdb79e3b5','過李生','白居易','唐','唐诗','tang','','[]','蘋小蒲葉短，南湖春水生。',144,'全唐诗/poet.tang.22000.json','["蘋小蒲葉短，南湖春水生。", "子近湖邊住，靜境稱高情。", "我爲郡司馬，散拙無所營。", "使君知性野，衙退任閑行。", "行攜小榼出，逢花輒獨傾。", "半酣到子舍，下馬扣柴荆。", "何以引我步，繞籬竹萬莖。", "何以醒我酒，吳音吟一聲。", "須臾進野飯，飯稻茹芹英。", "白甌青竹箸，儉潔無羶腥。", "欲去復裴回，夕鴉已飛鳴。", "何當重遊此，待君湖水平。"]'),
('b79cf708-4274-414c-ace1-1caba388e708','詠意','白居易','唐','唐诗','tang','','[]','常聞南華經，巧勞智憂愁。',144,'全唐诗/poet.tang.22000.json','["常聞南華經，巧勞智憂愁。", "不如無能者，飽食但遨遊。", "平生愛慕道，今日近此流。", "自來潯陽郡，四序忽已周。", "不分物黑白，但與時沈浮。", "朝餐夕安寢，用是爲身謀。", "此外即閑放，時尋山水幽。", "春遊慧遠寺，秋上庾公樓。", "或吟詩一章，或飲茶一甌。", "身心一無繫，浩浩如虛舟。", "富貴亦有苦，苦在心危憂。", "貧賤亦有樂，樂在身自由。"]'),
('ef18d8a8-27b3-4568-a8bb-bc19d1b3d9b2','食筍','白居易','唐','唐诗','tang','','[]','此州乃竹鄉，春筍滿山谷。',96,'全唐诗/poet.tang.22000.json','["此州乃竹鄉，春筍滿山谷。", "山夫折盈抱，抱來早市鬻。", "物以多爲賤，雙錢易一束。", "置之炊甑中，與飯同時熟。", "紫籜坼故錦，素肌擘新玉。", "每日遂加餐，經時不思肉。", "久爲京洛客，此味常不足。", "且食勿踟躕，南風吹作竹。"]'),
('c61e2df8-6875-48d5-9634-8ca77111bb23','遊石門澗','白居易','唐','唐诗','tang','','[]','石門無舊徑，披榛訪遺跡。',84,'全唐诗/poet.tang.22000.json','["石門無舊徑，披榛訪遺跡。", "時逢山水秋，清輝如古昔。", "常聞慧遠輩，題詩此巖壁。", "雲覆莓苔封，蒼然無處覓。", "蕭疎野生竹，崩剝多年石。", "自從東晉後，無復人遊歷。", "獨有秋澗聲，潺湲空旦夕。"]'),
('12da86e7-43f4-42cd-b5f8-ccbb19b995e7','招東鄰','白居易','唐','唐诗','tang','','[]','小榼二升酒，新簟六尺牀。',24,'全唐诗/poet.tang.22000.json','["小榼二升酒，新簟六尺牀。", "能來夜話否，池畔欲秋涼。"]'),
('99286590-d563-4a57-8995-712647d24536','題元十八溪亭','白居易','唐','唐诗','tang','','[]','怪君不喜仕，又不遊州里。',96,'全唐诗/poet.tang.22000.json','["怪君不喜仕，又不遊州里。", "今日到幽居，了然知所以。", "宿君石溪亭，潺湲聲滿耳。", "飲君螺杯酒，醉臥不能起。", "見君五老峰，益悔居城市。", "愛君三男兒，始歎身無子。", "余方鑪峰下，結室爲居士。", "山北與山東，往來從此始。"]'),
('a0f510b7-ec97-41f3-8809-5bb8f7606e46','香鑪峰下新置草堂即事詠懷題於石上','白居易','唐','唐诗','tang','','[]','香鑪峰北面，遺愛寺西偏。',228,'全唐诗/poet.tang.22000.json','["香鑪峰北面，遺愛寺西偏。", "白石何鑿鑿，清流亦潺潺。", "有松數十株，有竹千餘竿。", "松張翠繖蓋，竹倚青琅玕。", "其下無人居，悠哉多歲年。", "有時聚猨鳥，終日空風煙。", "時有沈冥子，姓白字樂天。", "平生無所好，見此心依然。", "如獲終老地，忽乎不知還。", "架巖結茅宇，斵壑開茶園。", "何以洗我耳，屋頭飛落泉。", "何以淨我眼，砌下生白蓮。", "左手攜一壺，右手挈五弦。", "傲然意自足，箕踞於其間。", "興酣仰天歌，歌中聊寄言。", "言我本野夫，誤爲世網牽。", "時來昔捧日，老去今歸山。", "倦鳥得茂樹，涸魚返清源。", "舍此欲焉往，人間多險艱。"]'),
('7cae1dc9-23b8-4611-938d-27d143c3781b','草堂前新開一池養魚種荷日有幽趣','白居易','唐','唐诗','tang','','[]','淙淙三峽水，浩浩萬頃陂。',72,'全唐诗/poet.tang.22000.json','["淙淙三峽水，浩浩萬頃陂。", "未如新塘上，微風動漣漪。", "小萍加泛泛，初蒲正離離。", "紅鯉二三寸，白蓮八九枝。", "繞水欲成徑，護堤方插籬。", "已被山中客，呼作白家池。"]'),
('8fcb644c-b9a5-43f3-9314-b9eb9df82ce8','白雲期','白居易','唐','唐诗','tang','','[]','三十氣太狀，胷中多是非。',72,'全唐诗/poet.tang.22000.json','["三十氣太狀，胷中多是非。", "六十身太老，四體不支持。", "四十至五十，正是退閑時。", "年長識命分，心慵少營爲。", "見酒興猶在，登山力未衰。", "吾年幸當此，且與白雲期。"]'),
('f80596cf-ca88-4264-8ce1-6ad185759789','登香爐峰頂','白居易','唐','唐诗','tang','','[]','迢迢香鑪峰，心存耳目想。',120,'全唐诗/poet.tang.22000.json','["迢迢香鑪峰，心存耳目想。", "終年牽物役，今日方一往。", "攀蘿蹋危石，手足勞俛仰。", "同遊三四人，兩人不敢上。", "上到峰之頂，目眩神怳怳。", "高低有萬尋，闊狹無數丈。", "不窮視聽界，焉識宇宙廣。", "江水細如繩，湓城小於掌。", "紛吾何屑屑，未能脫塵鞅。", "歸去思自嗟，低頭入蟻壤。"]'),
('1c6df717-e2d0-4f9d-9924-fc2f5ffd47ae','荅崔侍郎錢舍人書問因繼以詩','白居易','唐','唐诗','tang','','[]','旦暮兩蔬食，日中一閑眠。',216,'全唐诗/poet.tang.22000.json','["旦暮兩蔬食，日中一閑眠。", "便是了一日，如此已三年。", "心不擇時適，足不揀地安。", "窮通與遠近，一貫無兩端。", "常見今之人，其心或不然。", "在勞則念息，處靜已思喧。", "如是用身心，無乃自傷殘。", "坐輸憂惱便，安得形神全。", "吾有二道友，藹藹崔與錢。", "同飛青雲路，獨墮黃泥泉。", "歲暮物萬變，故情何不遷？", "應爲平生心，與我同一源。", "帝鄉遠於日，美人高在天。", "誰謂萬里別，常若在目前。", "泥泉樂者魚，雲路遊者鸞。", "勿言雲泥異，同在逍遙間。", "因君問心地，書後偶成篇。", "慎勿說向人，人多笑此言。"]'),
('c51202ed-3ea2-4e06-bc74-015a50dcaa61','烹葵','白居易','唐','唐诗','tang','','[]','昨臥不夕食，今起乃朝飢。',108,'全唐诗/poet.tang.22000.json','["昨臥不夕食，今起乃朝飢。", "貧廚何所有，炊稻烹秋葵。", "紅粒香復輭，綠英滑且肥。", "飢來止於飽，飽後復何思。", "憶昔榮遇日，迨今窮退時。", "今亦不凍餒，昔亦無餘資。", "口既不減食，身又不減衣。", "撫心私自問，何者是榮衰。", "勿學常人意，其間分是非。"]'),
('a4f3937b-b536-4ab4-a1b9-3579663b75f3','小池二首 一','白居易','唐','唐诗','tang','','[]','晝倦前齋熱，晚愛小池清。',36,'全唐诗/poet.tang.22000.json','["晝倦前齋熱，晚愛小池清。", "映林餘景沒，近水微涼生。", "坐把蒲葵扇，閑吟三兩聲。"]'),
('dab2a9b2-6c75-4116-bbaa-b3621b68d164','小池二首 二','白居易','唐','唐诗','tang','','[]','有意不在大，湛湛方丈餘。',36,'全唐诗/poet.tang.22000.json','["有意不在大，湛湛方丈餘。", "荷側瀉清露，萍開見游魚。", "每一臨此坐，憶歸青溪居。"]'),
('734a53c9-abf5-4684-b5c2-e47e183b38be','閉關','白居易','唐','唐诗','tang','','[]','我心忘世久，世亦不我干。',84,'全唐诗/poet.tang.22000.json','["我心忘世久，世亦不我干。", "遂成一無事，因得長掩關。", "掩關來幾時，髣髴二三年。", "著書已盈帙，生子欲能言。", "始悟身向老，復悲世多艱。", "迴顧趨時者，役役塵壤間。", "歲暮竟何得，不如且安閑。"]'),
('5ba27eec-9098-4f77-887b-b23649dc427d','弄龜羅','白居易','唐','唐诗','tang','','[]','有姪始六歲，字之爲阿龜。',108,'全唐诗/poet.tang.22000.json','["有姪始六歲，字之爲阿龜。", "有女生三年，其名曰羅兒。", "一始學笑語，一能誦歌詩。", "朝戲抱我足，夜眠枕我衣。", "汝生何其晚，我年行已衰。", "物情小可念，人意老多慈。", "酒美竟須壞，月圓終有虧。", "亦如恩愛緣，乃是憂惱資。", "舉世同此累，吾安能去之。"]'),
('bf293c1d-448f-45f2-ae6f-c5f8853caa68','截樹','白居易','唐','唐诗','tang','','[]','種樹當前軒，樹高柯葉繁。',120,'全唐诗/poet.tang.22000.json','["種樹當前軒，樹高柯葉繁。", "惜哉遠山色，隱此蒙籠間。", "一朝持斧斤，手自截其端。", "萬葉落頭上，千峰來面前。", "忽似決雲霧，豁達覩青天。", "又如所念人，久別一款顏。", "始有清風至，稍見飛鳥還。", "開懷東南望，目遠心遼然。", "人各有偏好，物莫能兩全。", "豈不愛柔條，不如見青山。"]'),
('26d55abb-3959-4e39-b584-667ca99b90a1','望江樓上作','白居易','唐','唐诗','tang','','[]','江畔百尺樓，樓前千里道。',72,'全唐诗/poet.tang.22000.json','["江畔百尺樓，樓前千里道。", "憑高望平遠，亦足舒懷抱。", "驛路使憧憧，關防兵草草。", "及茲多事日，尤覺閑人好。", "我年過不惑，休退誠非早。", "從此拂塵衣，歸山未爲老。"]'),
('bf3e94d7-a59b-4662-b9fa-0029f9270ff0','題座隅','白居易','唐','唐诗','tang','','[]','手不任執殳，肩不能荷鋤。',156,'全唐诗/poet.tang.22000.json','["手不任執殳，肩不能荷鋤。", "量力揆所用，曾不敵一夫。", "幸因筆研功，得升仕進途。", "歷官凡五六，祿俸及妻孥。", "左右有兼僕，出入有單車。", "自奉雖不厚，亦不至飢劬。", "若有人及此，傍觀爲何如。", "雖賢亦爲幸，況我鄙且愚。", "伯夷古賢人，魯山亦其徒。", "時哉無奈何，俱化爲餓殍。", "念彼益自媿，不敢忘斯須。", "平生榮利心，破滅無遺餘。", "猶恐塵妄起，題此於座隅。"]'),
('73df8fc0-6c14-48f6-8e6c-8089eaaa9efb','昔與微之在朝日同蓄休退之心迨今十年淪落老人追尋前約且結後期','白居易','唐','唐诗','tang','','[]','往子爲御史，伊余忝拾遺。',156,'全唐诗/poet.tang.22000.json','["往子爲御史，伊余忝拾遺。", "皆逢盛明代，俱登清近司。", "予繫玉爲佩，子曳繡爲衣。", "從容香煙下，同侍白玉墀。", "朝見寵者辱，暮見安者危。", "紛紛無退者，相顧令人悲。", "宦情君早厭，世事我深知。", "常於榮顯日，已約林泉期。", "況今各流落，身病齒髮衰。", "不作臥雲計，攜手欲何之。", "待君女嫁後，及我官滿時。", "稍無骨肉累，粗有漁樵資。", "歲晚青山路，白首期同歸。"]'),
('e552449d-5ad2-43b4-9954-2fe152c2ab5d','垂釣','白居易','唐','唐诗','tang','','[]','臨水一長嘯，忽思十年初。',48,'全唐诗/poet.tang.22000.json','["臨水一長嘯，忽思十年初。", "三登甲乙第，一入承明廬。", "浮生多變化，外事有盈虛。", "今來伴江叟，沙頭坐釣魚。"]'),
('d1dd16f4-eb61-4f25-b50c-fcd7cbd175ca','晚鷰','白居易','唐','唐诗','tang','','[]','百鳥乳雛畢，秋鷰獨蹉跎。',48,'全唐诗/poet.tang.22000.json','["百鳥乳雛畢，秋鷰獨蹉跎。", "去社日已近，銜泥意如何。", "不悟時節晚，徒施工用多。", "人間事亦爾，不獨鷰營窠。"]'),
('bd12aaa0-07f2-4b69-8fd4-7dd56c37415b','贖雞','白居易','唐','唐诗','tang','','[]','清晨臨江望，水禽正諠繁。',156,'全唐诗/poet.tang.22000.json','["清晨臨江望，水禽正諠繁。", "鳧鴈與鷗鷺，游颺戲朝暾。", "適有鬻雞者，挈之來遠村。", "飛鳴彼何樂，窘束此何冤。", "喔喔十四雛，罩縛同一樊。", "足傷金距蹜，頭搶花冠飜。", "經宿廢飲啄，日高詣屠門。", "遲迴未死間，飢渴欲相吞。", "常慕古人道，仁信及魚豚。", "見茲生惻隱，贖放雙林園。", "開籠解索時，雞雞聽我言。", "與爾鏹三百，小惠何足論。", "莫學銜環雀，崎嶇謾報恩。"]'),
('cf004d7f-6739-4a65-8651-e901393c3cfd','秋日懷杓直','白居易','唐','唐诗','tang','','[]','晚來天色好，獨出江邊步。',144,'全唐诗/poet.tang.22000.json','["晚來天色好，獨出江邊步。", "憶與李舍人，曲江相近住。", "常云遇清景，必約同幽趣。", "若不訪我來，還須覓君去。", "開眉笑相見，把手期何處。", "西寺老胡僧，南園亂松樹。", "攜持小酒榼，吟詠新詩句。", "同出復同歸，從朝直至暮。", "風雨忽消散，江山眇回互。", "潯陽與涔陽，相望空雲霧。", "心期自乖曠，時景還如故。", "今日郡齋中，秋光誰共度。"]'),
('9ef9c4fd-e53a-4093-97e5-4c5f768fafa0','食後','白居易','唐','唐诗','tang','','[]','食罷一覺睡，起來兩甌茶。',48,'全唐诗/poet.tang.22000.json','["食罷一覺睡，起來兩甌茶。", "舉頭看日影，已復西南斜。", "樂人惜日促，憂人厭年賒。", "無憂無樂者，長短任生涯。"]'),
('e1e28db1-6af3-4753-ae9a-1358e42ba146','齊物二首 一','白居易','唐','唐诗','tang','','[]','青松高百尺，綠蕙低數寸。',48,'全唐诗/poet.tang.22000.json','["青松高百尺，綠蕙低數寸。", "同生大塊間，長短各有分。", "長者不可退，短者不可進。", "若用此理推，窮通兩無悶。"]'),
('ee6e17ac-f156-411d-81e9-e8b9cc0b1c75','齊物二首 二','白居易','唐','唐诗','tang','','[]','椿壽八千春，槿花不經宿。',48,'全唐诗/poet.tang.22000.json','["椿壽八千春，槿花不經宿。", "中間復何有，冉冉孤竹生。", "竹身三年老，竹色四時綠。", "雖謝椿有餘，猶勝槿不足。"]'),
('f69bf612-06cc-4b2c-8677-19fcfaed3e72','山下宿','白居易','唐','唐诗','tang','','[]','獨到山下宿，靜向月中行。',24,'全唐诗/poet.tang.22000.json','["獨到山下宿，靜向月中行。", "何處水邊碓，夜舂雲母聲。"]'),
('6dc848eb-e121-4402-ad54-3c18430df5f9','題舊寫真圖','白居易','唐','唐诗','tang','','[]','我昔三十六，寫貌在丹青。',108,'全唐诗/poet.tang.22000.json','["我昔三十六，寫貌在丹青。", "我今四十六，衰顇臥江城。", "豈比十年老，曾與衆苦幷。", "一照舊圖畫，無復昔儀形。", "形影默相顧，如弟對老兄。", "況使他人見，能不昧平生。", "羲和鞭日走，不爲我少停。", "形骸屬日月，老去何足驚。", "所恨凌煙閣，不得畫功名。"]'),
('3bd5568d-d3eb-49ae-bf85-53b1662959dd','閑居','白居易','唐','唐诗','tang','','[]','肺病不飲酒，眼昏不讀書。',48,'全唐诗/poet.tang.22000.json','["肺病不飲酒，眼昏不讀書。", "端然無所作，身意閑有餘。", "雞棲籬落晚，雪映林木疎。", "幽獨已云極，何必山中居。"]'),
('4952eb9d-2e38-4209-b8c2-1dc296b44555','對酒示行簡','白居易','唐','唐诗','tang','','[]','今旦一尊酒，歡暢何怡怡。',156,'全唐诗/poet.tang.22000.json','["今旦一尊酒，歡暢何怡怡。", "此樂從中來，他人安得知。", "兄弟唯二人，遠別恆苦悲。", "今春自巴峽，萬里平安歸。", "復有雙幼妹，笄年未結褵。", "昨日嫁娶畢，良人皆可依。", "憂念兩消釋，如刀斷羈縻。", "身輕心無繫，忽欲凌空飛。", "人生苟有累，食肉常如飢。", "我心既無苦，飲水亦可肥。", "行簡勸爾酒，停杯聽我辭。", "不歎鄉國遠，不嫌官祿微。", "但願我與爾，終老不相離。"]'),
('78f506f9-3807-4524-9c5d-e8841924b5d0','詠懷','白居易','唐','唐诗','tang','','[]','冉牛與顏淵，卞和與馬遷。',144,'全唐诗/poet.tang.22000.json','["冉牛與顏淵，卞和與馬遷。", "或罹天六極，或被人刑殘。", "顧我信爲幸，百骸且完全。", "五十不爲夭，吾今欠數年。", "知分心自足，委順身常安。", "故雖窮退日，而無戚戚顏。", "昔有榮先生，從事於其間。", "今我不量力，舉心欲攀援。", "窮通不由己，歡戚不由天。", "命即無奈何，心可使泰然。", "且務由己者，省躬諒非難。", "勿問由天者，天高難與言。"]'),
('67ea017d-2d17-4386-9620-3c53ede786df','夜琴','白居易','唐','唐诗','tang','','[]','蜀[桐]木性實，楚絲音韻清。',50,'全唐诗/poet.tang.22000.json','["蜀[桐]木性實，楚絲音韻清。", "調慢彈且緩，夜深十數聲。", "入耳澹無味，愜心潛有情。", "自弄還自罷，亦不要人聽。"]'),
('1a5033fe-52b7-44ef-b084-0fb7ac479bdd','山中獨吟','白居易','唐','唐诗','tang','','[]','人各有一癖，我癖在章句。',108,'全唐诗/poet.tang.22000.json','["人各有一癖，我癖在章句。", "萬緣皆已消，此病獨未去。", "每逢美風景，或對好親故。", "高聲詠一篇，恍若與神遇。", "自爲江上客，半在山中住。", "有時新詩成，獨上東巖路。", "身倚白石崖，手攀青桂樹。", "狂吟驚林壑，猿鳥皆窺覰。", "恐爲世所嗤，故就無人處。"]'),
('4c63f9e1-bfdf-40e2-babe-4122158ad06a','達理二首 一','白居易','唐','唐诗','tang','','[]','何物壯不老，何時窮不通。',96,'全唐诗/poet.tang.22000.json','["何物壯不老，何時窮不通。", "如彼音與律，宛轉旋爲宮。", "我命獨何薄，多悴而少豐。", "當壯已先衰，暫泰還長窮。", "我無奈命何，委順以待終。", "命無奈我何，方寸如虛空。", "瞢然與化俱，混然與俗同。", "誰能坐自苦，齟齬於其中。"]'),
('5d05c117-d8f0-44c3-a7d4-f1a468de4520','達理二首 二','白居易','唐','唐诗','tang','','[]','舒姑化爲泉，牛哀病作虎。',96,'全唐诗/poet.tang.22000.json','["舒姑化爲泉，牛哀病作虎。", "或柳生肘間，或男變爲女。", "鳥獸及水木，本不與民伍。", "胡然生變遷，不待死歸土。", "百骸是己物，尚不能爲主。", "況彼時命間，倚伏何足數。", "時來不可遏，命去焉能取。", "唯當養浩然，吾聞達人語。"]'),
('40257275-9bd6-4698-a37c-f3a816ffa86e','湖亭晚望殘水','白居易','唐','唐诗','tang','','[]','湖上秋泬寥，湖邊晚蕭瑟。',108,'全唐诗/poet.tang.22000.json','["湖上秋泬寥，湖邊晚蕭瑟。", "登亭望湖水，水縮湖底出。", "清渟得早霜，明滅浮殘日。", "流注隨地勢，窪坳無定質。", "泓澄白龍臥，宛轉青蛇屈。", "破鏡折劒頭，光芒又非一。", "久爲山水客，見盡幽奇物。", "及來湖亭望，此狀難談悉。", "乃知天地間，勝事殊未畢。"]'),
('78240bba-291b-4149-84d8-c8c616498188','郭虛舟相訪','白居易','唐','唐诗','tang','','[]','朝暖就南軒，暮寒歸後屋。',48,'全唐诗/poet.tang.22000.json','["朝暖就南軒，暮寒歸後屋。", "晚酒一兩杯，夜棊三數局。", "寒灰埋暗火，曉燄凝殘燭。", "不嫌貧冷人，時來同一宿。"]'),
('bbf5e186-e78c-4e66-9470-5e463f63a1ef','長慶二年七月自中書舍人出守杭州路次藍溪作','白居易','唐','唐诗','tang','','[]','太原一男子，自顧庸且鄙。',240,'全唐诗/poet.tang.22000.json','["太原一男子，自顧庸且鄙。", "老逢不次恩，洗拔出泥滓。", "既居可言地，願助朝廷理。", "伏閤三上章，戇愚不稱旨。", "聖人存大體，優貸容不死。", "鳳詔停舍人，魚書除刺史。", "冥懷齊寵辱，委順隨行止。", "我自得此心，於茲十年矣。", "餘杭乃名郡，郡郭臨江汜。", "已想海門山，潮聲來入耳。", "昔予貞元末，羇旅曾遊此。", "甚覺太守尊，亦諳魚酒美。", "因生江海興，每羨滄浪水。", "尚擬拂衣行，況今兼祿仕。", "青山峰巒接，白日煙塵起。", "東道既不通，改轅遂南指。", "自秦窮楚越，浩蕩五千里。", "聞有賢主人，而多好山水。", "是行頗爲愜，所歷良可紀。", "策馬度藍溪，勝遊從此始。"]'),
('7cb24eb8-809a-4c32-b4d8-c2729a135d79','初出城留別','白居易','唐','唐诗','tang','','[]','朝從紫禁歸，暮出青門去。',48,'全唐诗/poet.tang.22000.json','["朝從紫禁歸，暮出青門去。", "勿言城東陌，便是江南路。", "揚鞭簇車馬，揮手辭親故。", "我生本無鄉，心安是歸處。"]'),
('74be07be-af29-42b9-9c5e-0f6a7e2f2dcd','過駱山人野居小池','白居易','唐','唐诗','tang','','[]','茅覆環堵亭，泉添方丈沼。',96,'全唐诗/poet.tang.22000.json','["茅覆環堵亭，泉添方丈沼。", "紅芳照水荷，白頸觀魚鳥。", "拳石苔蒼翠，尺波煙杳渺。", "但問有意無，勿論池大小。", "門前車馬路，奔走無昏曉。", "名利驅人心，賢愚同擾擾。", "善哉駱處士，安置身心了。", "何乃獨多君，丘園居者少。"]'),
('feff2589-7318-44b3-aa22-895bd04e2db5','宿清源寺','白居易','唐','唐诗','tang','','[]','往謫潯陽去，夜憩輞溪曲。',84,'全唐诗/poet.tang.22000.json','["往謫潯陽去，夜憩輞溪曲。", "今爲錢塘行，重經茲寺宿。", "爾來幾何歲，溪草二八綠。", "不見舊房僧，蒼然新樹木。", "虛空走日月，世界遷陵谷。", "我生寄其間，孰能逃倚伏。", "隨緣又南去，好住東廊竹。"]'),
('110831cb-d146-4614-9d67-954dbaa50d52','宿藍溪對月','白居易','唐','唐诗','tang','','[]','昨夜鳳池頭，今夜藍溪口。',48,'全唐诗/poet.tang.22000.json','["昨夜鳳池頭，今夜藍溪口。", "明月本無心，行人自回首。", "新秋松影下，半夜鐘聲後。", "清影不宜昏，聊將茶代酒。"]'),
('d0f39920-676a-42ac-b027-6386f449489b','自秦望赴五松驛馬上偶睡睡覺成吟','白居易','唐','唐诗','tang','','[]','長途發已久，前館行未至。',84,'全唐诗/poet.tang.22000.json','["長途發已久，前館行未至。", "體倦目已昏，瞌然遂成睡。", "右袂尚垂鞭，左手暫委轡。", "忽覺問僕夫，纔行百步地。", "形神分處所，遲速相乖異。", "馬上幾多時，夢中無限事。", "誠哉達人語，百齡同一寐。"]'),
('aa01fd76-539b-44ea-8778-5828aa6d122c','鄧州路中作','白居易','唐','唐诗','tang','','[]','蕭蕭誰家村，秋棃葉半坼。',72,'全唐诗/poet.tang.22000.json','["蕭蕭誰家村，秋棃葉半坼。", "漠漠誰家園，秋韭花初白。", "路逢故里物，使我嗟行役。", "不歸渭北村，又作江南客。", "去鄉徒自苦，濟世終無益。", "自問波上萍，何如澗中石。"]'),
('ced7b79c-a2b3-4e66-b45c-57c064e448fa','朱藤杖紫驄吟','白居易','唐','唐诗','tang','','[]','拄上山之下，騎下山之下。',44,'全唐诗/poet.tang.22000.json','["拄上山之下，騎下山之下。", "江州去日朱藤杖，忠州歸日紫驄馬。", "天生二物濟我窮，我生合是栖栖者。"]'),
('eb50b096-bba0-4390-8e18-462fc3f75a3b','桐樹館重題','白居易','唐','唐诗','tang','','[]','階前下馬時，梁上題詩處。',36,'全唐诗/poet.tang.22000.json','["階前下馬時，梁上題詩處。", "慘澹病使君，蕭疎老松樹。", "自嗟還自哂，又向杭州去。"]'),
('a082af8d-f141-4009-afe5-302510c3f93b','過紫霞蘭若','白居易','唐','唐诗','tang','','[]','我愛此山頭，及此三登歷。',48,'全唐诗/poet.tang.22000.json','["我愛此山頭，及此三登歷。", "紫霞舊精舍，寥落空泉石。", "朝市日喧隘，雲林長悄寂。", "猶存住寺僧，肯有歸山客。"]'),
('131197a4-3c77-46e9-b666-6a469444c1d7','感舊紗帽','白居易','唐','唐诗','tang','','[]','昔君烏紗帽，贈我白頭翁。',48,'全唐诗/poet.tang.22000.json','["昔君烏紗帽，贈我白頭翁。", "帽今在頂上，君已歸泉中。", "物故猶堪用，人亡不可逢。", "岐山今夜月，墳樹正秋風。"]'),
('0c092e94-17fd-450d-b39d-362438c2c577','思竹窗','白居易','唐','唐诗','tang','','[]','不憶西省松，不憶南宮菊。',36,'全唐诗/poet.tang.22000.json','["不憶西省松，不憶南宮菊。", "惟憶新昌堂，蕭蕭北窗竹。", "窗間枕簟在，來後何人宿。"]'),
('46824eef-0191-4de8-9e84-7a1c7fdb4e3a','馬上作','白居易','唐','唐诗','tang','','[]','處世非不遇，榮身頗有餘。',240,'全唐诗/poet.tang.22000.json','["處世非不遇，榮身頗有餘。", "勳爲上柱國，爵乃朝大夫。", "自問有何才，兩入承明廬。", "又問有何政，再駕朱輪車。", "矧予東山人，自惟樸且疎。", "彈琴復有酒，且慕嵇阮徒。", "暗被鄉里薦，誤上賢能書。", "一列朝士籍，遂爲世網拘。", "高有罾繳憂，下有陷穽虞。", "每覺宇宙窄，未嘗心體舒。", "蹉跎二十年，頷下生白鬚。", "何言左遷去，尚獲專城居。", "杭州五千里，往若投淵魚。", "雖未脫簪組，且來泛江湖。", "吳中多詩人，亦不少酒酤。", "高聲詠篇什，大笑飛杯盂。", "五十未全老，尚可且歡娛。", "用茲送日月，君以爲何如。", "秋風起江上，白日落路隅。", "回首語五馬，去矣勿踟躕。"]'),
('f80f2e73-c485-486a-b3a6-0bea73275501','秋蝶','白居易','唐','唐诗','tang','','[]','秋花紫蒙蒙，秋蝶黃茸茸。',72,'全唐诗/poet.tang.22000.json','["秋花紫蒙蒙，秋蝶黃茸茸。", "花低蝶新小，飛戲叢西東。", "日暮涼風來，紛紛花落叢。", "夜深白露冷，蝶已死叢中。", "朝生夕俱死，氣類各相從。", "不見千年鶴，多棲百丈松。"]'),
('19a54dfa-fb1c-4fb6-8fa2-f4d6f10b1852','登商山最高頂','白居易','唐','唐诗','tang','','[]','高高此山頂，四望唯煙雲。',72,'全唐诗/poet.tang.22000.json','["高高此山頂，四望唯煙雲。", "下有一條路，通達楚與秦。", "或名誘其心，或利牽其身。", "乘者及負者，來去何云云。", "我亦斯人徒，未能出囂塵。", "七年三往復，何得笑他人。"]'),
('173699a6-d696-4d20-ad2f-1555ae9e75d8','枯桑','白居易','唐','唐诗','tang','','[]','道傍老枯樹，枯來非一朝。',36,'全唐诗/poet.tang.22000.json','["道傍老枯樹，枯來非一朝。", "皮黃外尚活，心黑中先焦。", "有似多憂者，非因外火燒。"]'),
('baa8e467-50f3-430f-aa57-7957ad9c51d6','山路偶興','白居易','唐','唐诗','tang','','[]','筋力未全衰，僕馬不至弱。',96,'全唐诗/poet.tang.22000.json','["筋力未全衰，僕馬不至弱。", "又多山水趣，心賞非寂莫。", "捫蘿上煙嶺，蹋石穿雲壑。", "谷鳥晚仍啼，洞花秋不落。", "提籠復攜榼，遇勝時停泊。", "泉憩茶數甌，嵐行酒一酌。", "獨吟還獨嘯，此興殊未惡。", "假使在城時，終年有何樂。"]'),
('7619bb74-39a0-4fff-b258-7bae0c7f5676','山雉','白居易','唐','唐诗','tang','','[]','五步一啄草，十步一飲水。',72,'全唐诗/poet.tang.22000.json','["五步一啄草，十步一飲水。", "適性遂其生，時哉山梁雉。", "梁上無罾繳，梁下無鷹鸇。", "雌雄與羣雛，皆得終天年。", "嗟嗟籠下雞，及彼池中鴈。", "既有稻粱恩，必有犧牲患。"]'),
('894ac014-040e-4295-8804-2d9551398996','初下漢江舟中作寄兩省給舍','白居易','唐','唐诗','tang','','[]','秋水淅紅粒，朝煙烹白鱗。',96,'全唐诗/poet.tang.22000.json','["秋水淅紅粒，朝煙烹白鱗。", "一食飽至夜，一臥安達晨。", "晨無朝謁勞，夜無直宿勤。", "不知兩掖客，何似扁舟人。", "尚想到郡日，且稱守土臣。", "猶須副憂寄，恤隱安疲民。", "朞年庶報政，三年當退身。", "終使滄浪水，濯吾纓上塵。"]'),
('8b7f3d41-bd0a-40a7-8d74-b30e149cacc6','自蜀江至洞庭湖口有感而作','白居易','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','江從西南來，浩浩無旦夕。',264,'全唐诗/poet.tang.22000.json','["江從西南來，浩浩無旦夕。", "長波逐若瀉，連山鑿如劈。", "千年不壅潰，萬姓無墊溺。", "不爾民爲魚，大哉禹之績。", "導岷既艱遠，距海無咫尺。", "胡爲不訖功，餘水斯委積。", "洞庭與青草，大小兩相敵。", "混合萬丈深，淼茫千里白。", "每歲秋夏時，浩大吞七澤。", "水族窟穴多，農人土地窄。", "我今尚嗟歎，禹豈不愛惜。", "邈未究其由，想古觀遺跡。", "疑此苗人頑，恃險不終役。", "帝亦無奈何，留患與今昔。", "水流天地內，如身有血脈。", "滯則爲疽疣，治之在鍼石。", "安得禹復生，爲唐水官伯。", "手提倚天劒，重來親指畫。", "疏河似翦紙，決壅同裂帛。", "滲作膏腴田，蹋平魚鼈宅。", "龍宮變閭里，水府生禾麥。", "坐添百萬戶，書我司徒籍。"]'),
('4ecf5ff9-e393-42c7-9003-590250b970de','初領郡政衙退登東樓作','白居易','唐','唐诗','tang','','[]','鰥惸心所念，簡牘手自操。',96,'全唐诗/poet.tang.22000.json','["鰥惸心所念，簡牘手自操。", "何言符竹貴，未免州縣勞。", "賴是餘杭郡，臺榭繞官曹。", "凌晨親政事，向晚恣遊遨。", "山冷微有雪，波平未生濤。", "水心如鏡面，千里無纖毫。", "直下江最闊，近東樓更高。", "煩襟與滯念，一望皆遁逃。"]'),
('f34c11c4-7b8c-4d6c-9073-11c7263ef2c5','清調吟','白居易','唐','唐诗','tang','','[]','索索風戒寒，沈沈日藏耀。',72,'全唐诗/poet.tang.22000.json','["索索風戒寒，沈沈日藏耀。", "勸君飲濁醪，聽我吟清調。", "芳節變窮陰，朝光成夕照。", "與君生此世，不合長年少。", "今晨從此過，明日安能料。", "若不結跏禪，即須開口笑。"]'),
('ba03df23-9823-419f-8897-45d82bc9ea54','狂歌詞','白居易','唐','唐诗','tang','','[]','明月照君席，白露霑我衣。',72,'全唐诗/poet.tang.22000.json','["明月照君席，白露霑我衣。", "勸君酒杯滿，聽我狂歌詞。", "五十已後衰，二十已前癡。", "晝夜又分半，其間幾何時。", "生前不歡樂，死後有餘貲。", "焉用黃墟下，珠衾玉匣爲。"]'),
('e45db398-cab9-4305-a827-f1a69334a10a','郡亭','白居易','唐','唐诗','tang','','[]','平旦起視事，亭午臥掩關。',96,'全唐诗/poet.tang.22000.json','["平旦起視事，亭午臥掩關。", "除親簿領外，多在琴書前。", "況有虛白亭，坐見海門山。", "潮來一凭檻，賓至一開筵。", "終朝對雲水，有時聽管弦。", "持此聊過日，非忙亦非閑。", "山林太寂莫，朝闕空喧煩。", "唯茲郡閤內，囂靜得中間。"]'),
('1ec181c5-cb7c-4950-b680-2c264e9d4aff','詠懷','白居易','唐','唐诗','tang','','[]','昔爲鳳閤郎，今爲二千石。',120,'全唐诗/poet.tang.22000.json','["昔爲鳳閤郎，今爲二千石。", "自覺不如今，人言不如昔。", "昔雖居近密，終日多憂惕。", "有詩不敢吟，有酒不敢喫。", "今雖在疎遠，竟歲無牽役。", "飽食坐終朝，長歌醉通夕。", "人生百年內，疾速如過隙。", "先務身安閑，次要心歡適。", "事有得而失，物有損而益。", "所以見道人，觀心不觀跡。"]'),
('dbfe3f7a-9f95-463a-b90e-934879b5e8b4','立春後五日','白居易','唐','唐诗','tang','','[]','立春後五日，春態紛婀娜。',72,'全唐诗/poet.tang.22000.json','["立春後五日，春態紛婀娜。", "白日斜漸長，碧雲低欲墮。", "殘冰坼玉片，新萼排紅顆。", "遇物盡欣欣，愛春非獨我。", "迎芳後園立，就暖前檐作。", "還有惆悵心，欲別紅爐火。"]'),
('0ff7a5a9-10ad-43dd-8998-fa65ec646ef7','郡中即事','白居易','唐','唐诗','tang','','[]','漫漫潮初平，熙熙春日至。',120,'全唐诗/poet.tang.22000.json','["漫漫潮初平，熙熙春日至。", "空闊遠江山，晴明好天氣。", "外有適意物，中無繫心事。", "數篇對竹吟，一杯望雲醉。", "行攜杖扶力，臥讀書取睡。", "久養病形骸，深諳閑氣味。", "遙思九城陌，擾擾趨名利。", "今朝是雙日，朝謁多軒騎。", "寵者防悔尤，權者懷憂畏。", "爲報高車蓋，恐非真富貴。"]'),
('2ef8d258-11d0-4f0f-ae66-1495b711de9b','郡齋暇日辱常州陳郎中使君早春晚坐水西館書事詩十六韻見寄亦以十六韻酬之','白居易','唐','唐诗','tang','','[]','新年多暇日，晏起褰簾坐。',192,'全唐诗/poet.tang.22000.json','["新年多暇日，晏起褰簾坐。", "睡足心更慵，日高頭未裹。", "徐傾下藥酒，稍爇煎茶火。", "誰伴寂寥身，無弦琴在左。", "遙思毘陵館，春深物嫋娜。", "波拂黃柳梢，風搖白梅朵。", "衙門排曉戟，鈴閣開朝鎖。", "太守水西來，朱衣垂素舸。", "良辰不易得，佳會無由果。", "五馬正相望，雙魚忽前墮。", "魚中獲瑰寶，持玩何磊砢。", "一百六十言，字字靈珠顆。", "上申心款曲，下敘時轗軻。", "才富不如君，道孤還似我。", "敢辭官遠慢，且貴身安妥。", "勿復問榮枯，冥心無不可。"]'),
('9f8886aa-4e9c-4fe9-aaba-348518a30c5f','官舍','白居易','唐','唐诗','tang','','[]','高樹換新葉，陰陰覆地隅。',108,'全唐诗/poet.tang.22000.json','["高樹換新葉，陰陰覆地隅。", "何言太守宅，有似幽人居。", "太守臥其下，閑慵兩有餘。", "起嘗一甌茗，行讀一卷書。", "早梅結青實，殘櫻落紅珠。", "穉女弄庭果，嬉戲牽人裾。", "是日晚彌靜，巢禽下相呼。", "嘖嘖護兒鵲，啞啞母子烏。", "豈唯云鳥爾，吾亦引吾雛。"]'),
('c250cfa9-a262-432a-827d-d69fe38ca758','吾雛','白居易','唐','唐诗','tang','','[]','吾雛字阿羅，阿羅纔七齡。',120,'全唐诗/poet.tang.22000.json','["吾雛字阿羅，阿羅纔七齡。", "嗟吾不才子，憐爾無弟兄。", "撫養雖驕騃，性識頗聰明。", "學母畫眉樣，效吾詠詩聲。", "我齒今欲墮，汝齒昨始生。", "我頭髮盡落，汝頂髻初成。", "老幼不相待，父衰汝孩嬰。", "緬想古人心，慈愛亦不輕。", "蔡邕念文姬，于公歎緹縈。", "敢求得汝力，但未忘父情。"]'),
('6471155f-3234-40ba-922f-51737a960a7b','題小橋前新竹招客','白居易','唐','唐诗','tang','','[]','鴈齒小紅橋，垂檐低白屋。',96,'全唐诗/poet.tang.22000.json','["鴈齒小紅橋，垂檐低白屋。", "橋前何所有，苒苒新生竹。", "皮開坼褐錦，節露抽青玉。", "筠翠如可餐，粉霜不忍觸。", "閑吟聲未已，幽玩心難足。", "管領好風煙，輕欺凡草木。", "誰能有月夜，伴我林中宿。", "爲君傾一杯，狂歌竹枝曲。"]'),
('17a64973-cd58-4910-954d-856d75390941','病中逢秋招客夜酌','白居易','唐','唐诗','tang','','[]','不見詩酒客，臥來半月餘。',72,'全唐诗/poet.tang.22000.json','["不見詩酒客，臥來半月餘。", "合和新藥草，尋檢舊方書。", "晚霽煙景度，早涼窗戶虛。", "雪生衰鬢久，秋入病心初。", "臥簟蘄竹冷，風襟邛葛疎。", "夜來身校健，小飲復何如。"]'),
('dd60fd5e-b9ef-4c24-b786-ac4e6af48410','食飽','白居易','唐','唐诗','tang','','[]','食飽拂枕臥，睡足起閑吟。',48,'全唐诗/poet.tang.22000.json','["食飽拂枕臥，睡足起閑吟。", "淺酌一杯酒，緩彈數弄琴。", "既可暢情性，亦足傲光陰。", "誰知利名盡，無復長安心。"]'),
('63ff9c4a-2756-4c82-9c2a-eeb59870194d','嚴十八郎中在郡日改制東南樓因名清輝未立標牓徵歸郎署予既到郡性愛樓居宴遊其間頗有幽致聊成十韻兼戲寄嚴','白居易','唐','唐诗','tang','','[]','嚴郎置茲樓，立名曰清輝。',120,'全唐诗/poet.tang.22000.json','["嚴郎置茲樓，立名曰清輝。", "未及署花牓，遽徵還粉闈。", "去來三四年，塵土登者稀。", "今春新太守，灑埽施簾幃。", "院柳煙婀娜，檐花雪霏微。", "看山倚前戶，待月闡東扉。", "碧窗戛瑤瑟，朱闌飄舞衣。", "燒香卷幕坐，風燕雙雙飛。", "君作不得住，我來幸因依。", "始知天地間，靈境有所歸。"]'),
('ba12e934-7c19-41f5-b395-5b19c6f92486','南亭對酒送春','白居易','唐','唐诗','tang','','[]','含桃實已落，紅薇花尚熏。',120,'全唐诗/poet.tang.22000.json','["含桃實已落，紅薇花尚熏。", "冉冉三月盡，晚鶯城上聞。", "獨持一杯酒，南亭送殘春。", "半酣忽長歌，歌中何所云。", "云我五十餘，未是苦老人。", "刺史二千石，亦不爲賤貧。", "天下三品官，多老於我身。", "同年登第者，零落無一分。", "親故半爲鬼，僮僕多見孫。", "念此聊自解，逢酒且歡欣。"]'),
('55779b22-5259-45fa-b988-cbe798935041','玩新庭樹因詠所懷','白居易','唐','唐诗','tang','','[]','靄靄四月初，新樹葉成陰。',96,'全唐诗/poet.tang.22000.json','["靄靄四月初，新樹葉成陰。", "動搖風景麗，蓋覆庭院深。", "下有無事人，竟日此幽尋。", "豈惟玩時物，亦可開煩襟。", "時與道人語，或聽詩客吟。", "度春足芳色，入夜多鳴禽。", "偶得幽閑境，遂忘塵俗心。", "始知真隱者，不必在山林。"]'),
('5620ae9b-f33f-40c8-b2b2-60bfbb54078c','仲夏齋戒月','白居易','唐','唐诗','tang','','[]','仲夏齋戒月，三旬斷腥羶。',122,'全唐诗/poet.tang.22000.json','["仲夏齋戒月，三旬斷腥羶。", "自覺心骨爽，行起身翩翩。", "始知絕粒人，四體更輕便。", "初能脫病患，久必成神仙。", "禦寇馭[泠]風，赤松遊紫煙。", "常疑此說謬，今乃知其然。", "我今過半百，氣衰神不全。", "已垂兩鬢絲，難補三丹田。", "但減葷血味，稍結清淨緣。", "脫巾且修養，聊以終天年。"]'),
('854faac6-f108-46b7-8ba0-3eb3bfbc52ae','除官去未間','白居易','唐','唐诗','tang','','[]','除官去未間，半月恣遊討。',96,'全唐诗/poet.tang.22000.json','["除官去未間，半月恣遊討。", "朝尋霞外寺，暮宿波上島。", "新樹少於松，平湖半連草。", "躋攀有次第，賞玩無昏早。", "有時騎馬醉，兀兀冥天造。", "窮通與生死，其奈吾懷抱。", "江山信爲美，齒髮行將老。", "在郡誠未厭，歸鄉去亦好。"]'),
('aba03e64-f677-4118-9db0-a949ff266ee6','三年爲刺史二首 一','白居易','唐','唐诗','tang','','[]','三年爲刺史，無政在人口。',36,'全唐诗/poet.tang.22000.json','["三年爲刺史，無政在人口。", "唯向城郡中，題詩十餘首。", "慙非甘棠詠，豈有思人不。"]'),
('a2bb10e4-a402-4ca3-9dd8-233944bbb728','三年爲刺史二首 二','白居易','唐','唐诗','tang','','[]','三年爲刺史，飲冰復食檗。',36,'全唐诗/poet.tang.22000.json','["三年爲刺史，飲冰復食檗。", "唯向天竺山，取得兩片石。", "此抵有千金，無乃傷清白。"]'),
('2994cca5-f393-4075-a401-74d5c572e5f6','別萱桂','白居易','唐','唐诗','tang','','[]','使君竟不住，萱桂徒栽種。',36,'全唐诗/poet.tang.22000.json','["使君竟不住，萱桂徒栽種。", "桂有留人名，萱無忘憂用。", "不如江畔月，步步來相送。"]'),
('c4bf8f1f-24a9-4400-b2ca-d0464705b5d8','自餘杭歸宿淮口作','白居易','唐','唐诗','tang','','[]','爲郡已多暇，猶少勤吏職。',108,'全唐诗/poet.tang.22000.json','["爲郡已多暇，猶少勤吏職。", "罷郡更安閑，無所勞心力。", "舟行明月下，夜泊清淮北。", "豈止吾一身，舉家同燕息。", "三年請祿俸，頗有餘衣食。", "乃至僮僕間，皆無凍餒色。", "行行弄雲水，步步近鄉國。", "妻子在我前，琴書在我側。", "此外吾不知，於焉心自得。"]'),
('1ad19230-37d1-462c-967d-6c0186b51e02','舟中李山人訪宿','白居易','唐','唐诗','tang','','[]','日暮舟悄悄，煙生水沈沈。',72,'全唐诗/poet.tang.22000.json','["日暮舟悄悄，煙生水沈沈。", "何以延宿客，夜酒與秋琴。", "來客道門子，來自嵩高岑。", "軒軒舉雲貌，豁豁開清襟。", "得意言語斷，入玄滋味深。", "默然相顧哂，心適而忘心。"]'),
('0c866b9c-1ca3-4c30-83e1-87c977c4ee63','洛下卜居','白居易','唐','唐诗','tang','','[]','三年典郡歸，所得非金帛。',144,'全唐诗/poet.tang.22000.json','["三年典郡歸，所得非金帛。", "天竺石兩片，華亭鶴一隻。", "飲啄供稻粱，包裹用茵席。", "誠知是勞費，其奈心愛惜。", "遠從餘杭郭，同到洛陽陌。", "下擔拂雲根，開籠展霜翮。", "貞姿不可雜，高性宜其適。", "遂就無塵坊，仍求有水宅。", "東南得幽境，樹老寒泉碧。", "池畔多竹陰，門前少人跡。", "未請中庶祿，且脫雙驂易。", "豈獨爲身謀，安吾鶴與石。"]'),
('d82c10e5-52bc-45f6-ae3c-589ae681de31','洛中偶作','白居易','唐','唐诗','tang','','[]','五年職翰林，四年涖潯陽。',144,'全唐诗/poet.tang.22000.json','["五年職翰林，四年涖潯陽。", "一年巴郡守，半年南宮郎。", "二年直綸閤，三年刺史堂。", "凡此十五載，有詩千餘章。", "境興周萬象，土風備四方。", "獨無洛中作，能不心悢悢。", "今爲青宮長，始來遊此鄉。", "裴回伊澗上，睥睨嵩少傍。", "遇物輒一詠，一詠傾一觴。", "筆下成釋憾，卷中同補亡。", "往往顧自哂，眼昏鬚鬢蒼。", "不知老將至，猶自放詩狂。"]'),
('1a4d93c4-781f-44a5-a32e-ea35ab45a285','贈蘇少府','白居易','唐','唐诗','tang','','[]','籍甚二十年，今日方款顏。',72,'全唐诗/poet.tang.22000.json','["籍甚二十年，今日方款顏。", "相送嵩洛下，論心杯酒間。", "河亞嬾出入，府寮多閉關。", "蒼髮彼此老，白日尋常閑。", "朝從攜手出，暮思聯騎還。", "何當挈一榼，同宿龍門山。"]'),
('adbbe50e-2c3c-46e2-acbe-5b94139acaa2','移家入新宅','白居易','唐','唐诗','tang','','[]','移家入新宅，罷郡有餘貲。',192,'全唐诗/poet.tang.22000.json','["移家入新宅，罷郡有餘貲。", "既可避燥濕，復免憂寒飢。", "疾平未還假，官閑得分司。", "幸有俸祿在，而無職役羈。", "清旦盥漱畢，開軒卷簾幃。", "家人及雞犬，隨我亦熙熙。", "取興或寄酒，放情不過詩。", "何必苦修道，此即是無爲。", "外累信已遣，中懷時有思。", "有思一何遠，默坐低雙眉。", "十載囚竄客，萬里征戍兒。", "春朝鏁籠鳥，冬夜支牀龜。", "驛馬走四蹄，痛酸無歇期。", "磑牛封兩目，昏閉何人知。", "誰能脫放去，四散任所之。", "各得適其性，如吾今日時。"]'),
('d7a3f901-b9f6-437b-81e8-7b8864644237','琴','白居易','唐','唐诗','tang','','[]','置琴曲几上，慵坐但含情。',24,'全唐诗/poet.tang.22000.json','["置琴曲几上，慵坐但含情。", "何煩故揮弄，風弦自有聲。"]'),
('afbcc14e-9509-40fd-997c-71d62b6b24a6','鶴','白居易','唐','唐诗','tang','','[]','人各有所好，物固無常宜。',24,'全唐诗/poet.tang.22000.json','["人各有所好，物固無常宜。", "誰謂爾能舞，不如閑立時。"]'),
('e13290af-8a9e-436b-972f-8cef2c6b4d32','自詠','白居易','唐','唐诗','tang','','[]','夜鏡隱白髮，朝酒發紅顏。',180,'全唐诗/poet.tang.22000.json','["夜鏡隱白髮，朝酒發紅顏。", "可憐假年少，自笑須臾間。", "朱砂賤如土，不解燒爲丹。", "玄鬢化爲雪，未聞休得官。", "咄哉箇丈夫，心性何墮頑。", "但遇詩與酒，便忘寢與餐。", "高聲發一吟，似得詩中仙。", "引滿飲一醆，盡忘身外緣。", "昔有醉先生，席地而幕天。", "于今居處在，許我當中眠。", "眠罷又一酌，酌罷又一篇。", "回面顧妻子，生計方落然。", "誠知此事非，又過知非年。", "豈不欲自改，改即心不安。", "且向安處去，其餘皆老閑。"]'),
('e9f3f08b-5a61-410d-8e84-5c11bfef5b10','林下閑步寄皇甫庶子','白居易','唐','唐诗','tang','','[]','扶杖起病初，策馬力未任。',72,'全唐诗/poet.tang.22000.json','["扶杖起病初，策馬力未任。", "既嬾出門去，亦無客來尋。", "以此遂成閑，閑步繞園林。", "天曉煙景澹，樹寒鳥雀深。", "一酌池上酒，數聲竹間吟。", "寄言東曹長，當知幽獨心。"]'),
('99ea9770-c3ab-4da9-afa3-4410dfde41cd','晏起','白居易','唐','唐诗','tang','','[]','鳥鳴庭樹上，日照屋檐時。',96,'全唐诗/poet.tang.22000.json','["鳥鳴庭樹上，日照屋檐時。", "老去慵轉極，寒來起尤遲。", "厚薄被適性，高低枕得宜。", "神安體穩暖，此味何人知。", "睡足仰頭坐，兀然無所思。", "如未鑿七竅，若都遺四肢。", "緬想長安客，早朝霜滿衣。", "彼此各自適，不知誰是非。"]'),
('bbc0c564-743d-4ded-87a8-0a3b3e2ea9b9','池畔二首 一','白居易','唐','唐诗','tang','','[]','結構池西廊，疏理池東樹。',24,'全唐诗/poet.tang.22000.json','["結構池西廊，疏理池東樹。", "此意人不知，欲爲待月處。"]'),
('fe56b3d6-8caf-4bae-9c41-ca6b00b6c59c','池畔二首 二','白居易','唐','唐诗','tang','','[]','持刀𠜴密竹，竹少風來多。',24,'全唐诗/poet.tang.22000.json','["持刀𠜴密竹，竹少風來多。", "此意人不會，欲令池有波。"]'),
('345a734b-c2c1-4f2d-ad3a-3c65804fc26a','春葺新居','白居易','唐','唐诗','tang','','[]','江州司馬日，忠州刺史時。',120,'全唐诗/poet.tang.22000.json','["江州司馬日，忠州刺史時。", "栽松滿後院，種柳蔭前墀。", "彼皆非吾土，栽種尚忘疲。", "況茲是我宅，葺藝固其宜。", "平旦領僕使，乘春親指揮。", "移花夾暖室，徙竹覆寒池。", "池水變綠色，池芳動清輝。", "尋芳弄水坐，盡日心熙熙。", "一物苟可適，萬緣都若遺。", "設如宅門外，有事吾不知。"]'),
('482803cb-52e2-49ac-a2a9-bc2be2d5dfc3','贈言','白居易','唐','唐诗','tang','','[]','捧籯獻千金，彼金何足道。',84,'全唐诗/poet.tang.22000.json','["捧籯獻千金，彼金何足道。", "臨觴贈一言，此言真可寶。", "流光我已晚，適意君不早。", "況君春風面，柔促如芳草。", "二十方長成，三十向衰老。", "鏡中桃李色，不得十年好。", "胡爲坐脈脈，不肯傾懷抱。"]'),
('61f15c85-4558-4a0a-a8d0-9629f1c7387d','泛春池','白居易','唐','唐诗','tang','','[]','白蘋湘渚曲，綠篠剡溪口。',204,'全唐诗/poet.tang.22000.json','["白蘋湘渚曲，綠篠剡溪口。", "各在天一涯，信美非吾有。", "何如此庭內，水竹交左右。", "霜竹百千竿，煙波六七畝。", "泓澄動階砌，澹泞映戶牖。", "蛇皮細有紋，鏡面清無垢。", "主人過橋來，雙童扶一叟。", "恐汚清泠波，塵纓先抖擻。", "波上一葉舟，舟中一尊酒。", "酒開舟不繫，去去隨所偶。", "或繞蒲浦前，或泊桃島後。", "未撥落杯花，低衝拂面柳。", "半酣迷所在，倚榜兀回首。", "不知此何處，復是人寰否。", "誰知始疏鑿，幾主相傳受。", "楊家去云遠，田氏將非久。", "天與愛水人，終焉落吾手。"]'),
('b6112834-34c5-463c-bb0c-6d32c7360980','西明寺牡丹花時憶元九','白居易','唐','唐诗','tang','','[]','前年題名處，今日看花來。',60,'全唐诗/poet.tang.22000.json','["前年題名處，今日看花來。", "一作芸香吏，三見牡丹開。", "豈獨花堪惜，方知老闇催。", "何況尋花伴，東都去未迴。", "詎知紅芳側，春盡思悠哉。"]'),
('c1a57862-f4d1-450e-b606-7fb9932565a5','傷楊弘貞','白居易','唐','唐诗','tang','','[]','顏子昔短命，仲尼惜其賢。',36,'全唐诗/poet.tang.22000.json','["顏子昔短命，仲尼惜其賢。", "楊生亦好學，不幸復徒然。", "誰識天地意，獨與龜鶴年。"]'),
('d3eae8d8-7aa5-4353-bee9-990025e545b7','權攝昭應早秋書事寄元拾遺兼呈李司錄','白居易','唐','唐诗','tang','','[]','夏閏秋候早，七月風騷騷。',96,'全唐诗/poet.tang.22000.json','["夏閏秋候早，七月風騷騷。", "渭川煙景晚，驪山宮殿高。", "丹殿子司諫，赤縣我徒勞。", "相去半日程，不得同遊遨。", "到官來十日，覽鏡生二毛。", "可憐趨走吏，塵土滿青袍。", "郵傳擁兩驛，簿書堆六曹。", "爲問綱紀掾，何必使鉛刀。"]'),
('7591d16f-6511-4e1a-b950-71a697ccfd7f','新栽竹','白居易','唐','唐诗','tang','','[]','佐邑意不適，閉門秋草生。',84,'全唐诗/poet.tang.22000.json','["佐邑意不適，閉門秋草生。", "何以娛野性，種竹百餘莖。", "見此溪上色，憶得山中情。", "有時公事暇，盡日繞闌行。", "勿言根未固，勿言陰未成。", "已覺庭宇內，稍稍有餘清。", "最愛近窗臥，秋風枝有聲。"]'),
('2297e849-df3b-40aa-9599-3faa8a1b35c0','秋霖中過尹縱之仙遊山居','白居易','唐','唐诗','tang','','[]','慘慘八月暮，連連三日霖。',84,'全唐诗/poet.tang.22000.json','["慘慘八月暮，連連三日霖。", "邑居尚愁寂，況乃在山林。", "林下有志士，苦學惜光陰。", "歲晚千萬慮，幷入方寸心。", "巖鳥共旅宿，草蟲伴愁吟。", "秋天牀席冷，夜雨燈火深。", "憐君寂莫意，攜酒一相尋。"]'),
('ff5b4af6-0b5a-44de-acd3-a8d564d97a13','寄江南兄弟','白居易','唐','唐诗','tang','','[]','分散骨肉戀，趨馳名利牽。',96,'全唐诗/poet.tang.22000.json','["分散骨肉戀，趨馳名利牽。", "一奔塵埃馬，一泛風波船。", "忽憶分手時，憫默秋風前。", "別來朝復夕，積日成七年。", "花落城中池，春深江上天。", "登樓東南望，鳥滅煙蒼然。", "相去復幾許，道里近三千。", "平地猶難見，況乃隔山川。"]'),
('3c818221-55ea-430b-9c56-94fb4cbf9b7b','曲江早秋','白居易','唐','唐诗','tang','','[]','秋波紅蓼水，夕照青蕪岸。',84,'全唐诗/poet.tang.22000.json','["秋波紅蓼水，夕照青蕪岸。", "獨信馬蹄行，曲江池四畔。", "早涼晴後至，殘暑暝來散。", "方喜炎燠銷，復嗟時節換。", "我年三十六，冉冉昏復旦。", "人壽七十稀，七十新過半。", "且當對酒笑，勿起臨風歎。"]'),
('d68df0bf-18b6-422a-b2aa-1bb730290c90','寄題盩厔廳前雙松','白居易','唐','唐诗','tang','','[]','憶昨爲吏日，折腰多苦辛。',144,'全唐诗/poet.tang.22000.json','["憶昨爲吏日，折腰多苦辛。", "歸來不自適，無計慰心神。", "手栽兩樹松，聊以當嘉賓。", "乘春日一溉，生意漸欣欣。", "清韻度秋在，綠茸隨日新。", "始憐澗底色，不憶城中春。", "有時晝掩關，雙影對一身。", "盡日不寂莫，意中如三人。", "忽奉宣室詔，徵爲文苑臣。", "閑來一惆悵，恰似別交親。", "早知煙翠前，攀玩不逡巡。", "悔從白雲裏，移爾落囂塵。"]'),
('822c5051-4bdf-4408-8b07-9c5fc029bdf2','翰林院中感秋懷王質夫','白居易','唐','唐诗','tang','','[]','何處感時節，新蟬禁中聞。',60,'全唐诗/poet.tang.22000.json','["何處感時節，新蟬禁中聞。", "宮槐有秋意，風夕花紛紛。", "寄跡鴛鷺行，歸心鷗鶴羣。", "唯有王居士，知予憶白雲。", "何日仙遊寺，潭前秋見君。"]'),
('7a1f1233-063c-4adb-ba10-66a7ff648f12','禁中月','白居易','唐','唐诗','tang','','[]','海水明月出，禁中清夜長。',48,'全唐诗/poet.tang.22000.json','["海水明月出，禁中清夜長。", "東南樓殿白，稍稍上宮牆。", "淨落金塘水，明浮玉砌霜。", "不比人間見，塵土汚清光。"]'),
('246b0459-19f8-4397-b839-2c63191412fe','贈賣松者','白居易','唐','唐诗','tang','','[]','一束蒼蒼色，知從澗底來。',36,'全唐诗/poet.tang.22000.json','["一束蒼蒼色，知從澗底來。", "斸掘經幾日，枝葉滿塵埃。", "不買非他意，城中無地栽。"]'),
('c8e9a040-c9a9-475e-a5a8-33405b418baa','初見白髮','白居易','唐','唐诗','tang','','[]','白髮生一莖，朝來明鏡裏。',48,'全唐诗/poet.tang.22000.json','["白髮生一莖，朝來明鏡裏。", "勿言一莖少，滿頭從此始。", "青山方遠別，黃綬初從仕。", "未料容鬢間，蹉跎忽如此。"]'),
('20a89f69-eab6-4d45-a51b-c455dd068e7d','別元九後詠所懷','白居易','唐','唐诗','tang','','["\u601d\u5ff5", "\u53cb\u4eba", "\u79cb\u5929", "\u5b64\u5bc2"]','零落桐葉雨，蕭條槿花風。',72,'全唐诗/poet.tang.22000.json','["零落桐葉雨，蕭條槿花風。", "悠悠早秋意，生此幽閑中。", "況與故人別，中懷正無悰。", "勿云不相送，心到青門東。", "相知豈在多，但問同不同。", "同心一人去，坐覺長安空。"]'),
('c00802d6-14e0-4611-96e5-700d18a335ef','禁中秋宿','白居易','唐','唐诗','tang','','[]','風飜朱裏幕，雨冷通中枕。',24,'全唐诗/poet.tang.22000.json','["風飜朱裏幕，雨冷通中枕。", "耿耿背斜燈，秋牀一人寢。"]'),
('31faed9c-869b-4eb0-9d40-3802f389aa82','早秋曲江感懷','白居易','唐','唐诗','tang','','[]','離離暑雲散，嫋嫋涼風起。',72,'全唐诗/poet.tang.22000.json','["離離暑雲散，嫋嫋涼風起。", "池上秋又來，荷花半成子。", "朱顏易銷歇，白日無窮已。", "人壽不如山，年光忽於水。", "青蕪與紅蓼，歲歲秋相似。", "去歲此悲秋，今秋復來此。"]'),
('da73e6ac-e170-4aa9-8cce-caa9c87fd16e','寄元九','白居易','唐','唐诗','tang','','[]','身爲近密拘，心爲名檢縛。',120,'全唐诗/poet.tang.22000.json','["身爲近密拘，心爲名檢縛。", "月夜與花時，少逢杯酒樂。", "唯有元夫子，閑來同一酌。", "把手或酣歌，展眉時笑謔。", "今春除御史，前月之東洛。", "別來未開顏，塵埃滿尊杓。", "蕙風晚香盡，槐雨餘花落。", "秋意一蕭條，離容兩寂莫。", "況隨白日老，共負青山約。", "誰識相念心，韝鷹與籠鶴。"]'),
('6f19baaa-24e9-412f-8b3a-9ff0264efaa9','暮春寄元九','白居易','唐','唐诗','tang','','[]','棃花結成實，燕卵化爲雛。',72,'全唐诗/poet.tang.22000.json','["棃花結成實，燕卵化爲雛。", "時物又若此，道情復何如。", "但覺日月促，不嗟年歲徂。", "浮生都是夢，老小亦何殊。", "唯與故人別，江陵初謫居。", "時時一相見，此意未全除。"]'),
('bc29f2ec-43f8-4b7c-b5d7-ddecd6fc3327','早梳頭','白居易','唐','唐诗','tang','','[]','夜沐早梳頭，窗明秋鏡曉。',60,'全唐诗/poet.tang.22000.json','["夜沐早梳頭，窗明秋鏡曉。", "颯然握中髮，一沐知一少。", "年事漸蹉跎，世緣方繳繞。", "不學空門法，老病何由了。", "未得無生心，白頭亦爲夭。"]'),
('a9cb1b56-c0e2-460f-aad3-b6cbadaa2e36','出關路','白居易','唐','唐诗','tang','','[]','山川函谷路，塵土遊子顏。',24,'全唐诗/poet.tang.22000.json','["山川函谷路，塵土遊子顏。", "蕭條去國意，秋風生故關。"]'),
('73bc4f05-7c09-4641-af67-df578c1324bb','別舍弟後月夜','白居易','唐','唐诗','tang','','[]','悄悄初別夜，去住兩盤桓。',72,'全唐诗/poet.tang.22000.json','["悄悄初別夜，去住兩盤桓。", "行子孤燈店，居人明月軒。", "平生共貧苦，未必日成歡。", "及此暫爲別，懷抱已憂煩。", "況是庭葉盡，復思山路寒。", "如何爲不念，馬瘦衣裳單。"]'),
('7d550832-7c18-4a43-973c-22d8824d287f','新豐路逢故人','白居易','唐','唐诗','tang','','[]','塵土長路晚，風煙廢宮秋。',48,'全唐诗/poet.tang.22000.json','["塵土長路晚，風煙廢宮秋。", "相逢立馬語，盡日此橋頭。", "知君不得意，鬱鬱來西遊。", "惆悵新豐店，何人識馬周。"]'),
('3f943b3e-8779-4855-92d3-cabb46f4e166','金鑾子晬日','白居易','唐','唐诗','tang','','[]','行年欲四十，有女曰金鑾。',72,'全唐诗/poet.tang.22000.json','["行年欲四十，有女曰金鑾。", "生來始周歲，學坐未能言。", "慙非達者懷，未免俗情憐。", "從此累身外，徒云慰目前。", "若無夭折患，則有婚嫁牽。", "使我歸山計，應遲十五年。"]'),
('721cf4b0-fcee-4a61-b71a-60cea3e3c805','青龍寺早夏','白居易','唐','唐诗','tang','','[]','塵埃經小雨，地高倚長坡。',96,'全唐诗/poet.tang.22000.json','["塵埃經小雨，地高倚長坡。", "日西寺門外，景氣含清和。", "閑有老僧立，靜無凡客過。", "殘鶯意思盡，新葉陰涼多。", "春去來幾日，夏雲忽嵯峨。", "朝朝感時節，年鬢闇蹉跎。", "胡爲戀朝市，不去歸煙蘿。", "青山寸步地，自問心如何。"]'),
('7fca5118-ff38-4321-9ac8-4e448590b93e','秋題牡丹叢','白居易','唐','唐诗','tang','','[]','晚叢白露夕，衰葉涼風朝。',36,'全唐诗/poet.tang.22000.json','["晚叢白露夕，衰葉涼風朝。", "紅豔久已歇，碧芳今亦銷。", "幽人坐相對，心事共蕭條。"]'),
('483540a1-433e-4a6a-8167-fcfda736a28c','勸酒寄元九','白居易','唐','唐诗','tang','','[]','薤葉有朝露，槿枝無宿花。',156,'全唐诗/poet.tang.22000.json','["薤葉有朝露，槿枝無宿花。", "君今亦如此，促促生有涯。", "既不逐禪僧，林下學楞伽。", "又不隨道士，山中鍊丹砂。", "百年夜分半，一歲春無多。", "何不飲美酒？胡然自悲嗟。", "俗號銷愁藥，神速無以加。", "一杯驅世慮，兩杯反天和。", "三杯即酩酊，或笑任狂歌。", "陶陶復兀兀，吾孰知其他。", "況在名利途，平生有風波。", "深心藏陷穽，巧言織網羅。", "舉目非不見，不醉欲如何。"]'),
('c1e06ad3-5320-40b3-9007-11a7520d9e2a','曲江感秋','白居易','唐','唐诗','tang','','[]','沙草新雨地，岸柳涼風枝。',96,'全唐诗/poet.tang.22000.json','["沙草新雨地，岸柳涼風枝。", "三年感秋意，幷在曲江池。", "早蟬已嘹唳，晚荷復離披。", "前秋去秋思，一一生此時。", "昔人三十二，秋興已云悲。", "我今欲四十，秋懷亦可知。", "歲月不虛設，此身隨日衰。", "闇老不自覺，直到鬢成絲。"]'),
('b3b3e541-4cce-47ad-87ab-5dfcbd8fdc4e','酬張太祝晚秋臥病見寄','白居易','唐','唐诗','tang','','[]','高才淹禮寺，短羽翔禁林。',120,'全唐诗/poet.tang.22000.json','["高才淹禮寺，短羽翔禁林。", "西街居處遠，北闕官曹深。", "君病不來訪，我忙難往尋。", "差池終日別，寥落經年心。", "露濕綠蕪地，月寒紅樹陰。", "況茲獨愁夕，聞彼相思吟。", "上歎言笑阻，下嗟時歲侵。", "容衰曉窗鏡，思苦秋弦琴。", "一章錦繡段，八韻瓊瑤音。", "何以報珍重，慙無雙南金。"]'),
('847c2196-b35c-4735-bd72-5c363ee96c61','立秋日曲江憶元九','白居易','唐','唐诗','tang','','[]','下馬柳陰下，獨上堤上行。',48,'全唐诗/poet.tang.22000.json','["下馬柳陰下，獨上堤上行。", "故人千萬里，新蟬三兩聲。", "城中曲江水，江上江陵城。", "兩地新秋思，應同此日情。"]'),
('448335bb-7019-4000-b9e7-12c8b5335d69','早朝賀雪寄陳山人','白居易','唐','唐诗','tang','','[]','長安盈尺雪，早朝賀君喜。',96,'全唐诗/poet.tang.22000.json','["長安盈尺雪，早朝賀君喜。", "將赴銀臺門，始出新昌里。", "上堤馬蹄滑，中路蠟燭死。", "十里向北行，寒風吹破耳。", "待漏午門外，候對三殿裏。", "鬚鬢凍生冰，衣裳冷如水。", "忽思仙遊谷，闇謝陳居士。", "暖覆褐裘眠，日高應未起。"]'),
('f79eec1c-d15c-4ca2-a32b-49f98e1c4be9','初與元九別後忽夢見之及寤而書適至兼寄桐花詩悵然感懷因以此寄','白居易','唐','唐诗','tang','','[]','永壽寺中語，新昌坊北分。',288,'全唐诗/poet.tang.22000.json','["永壽寺中語，新昌坊北分。", "歸來數行淚，悲事不悲君。", "悠悠藍田路，自去無消息。", "計君食宿程，已過商山北。", "昨夜雲四散，千里同月色。", "曉來夢見君，應是君相憶。", "夢中握君手，問君意何如。", "君言苦相憶，無人可寄書。", "覺來未及說，叩門聲冬冬。", "言是商州使，送君書一封。", "枕上忽驚起，顛倒著衣裳。", "開緘見手札，一紙十三行。", "上論遷謫心，下說離別腸。", "心腸都未盡，不暇敘炎涼。", "云作此書夜，夜宿商州東。", "獨對孤燈坐，陽城山館中。", "夜深作書畢，山月向西斜。", "月下何所有，一樹紫桐花。", "桐花半落時，復道正相思。", "殷勤書背後，兼寄桐花詩。", "桐花詩八韻，思緒一何深。", "以我今朝意，憶君此夜心。", "一章三徧讀，一句十回吟。", "珍重八十字，字字化爲金。"]'),
('016852d0-1d90-4505-a40d-0790a919f615','和元九悼往','白居易','唐','唐诗','tang','','[]','美人別君去，自去無處尋。',120,'全唐诗/poet.tang.22000.json','["美人別君去，自去無處尋。", "舊物零落盡，此情安可任。", "唯有襭紗幌，塵埃日夜侵。", "馨香與顏色，不似舊時深。", "透影燈耿耿，籠光月沈沈。", "中有孤眠客，秋涼生夜衾。", "舊宅牡丹院，新墳松柏林。", "夢中咸陽淚，覺後江陵心。", "含此隔年恨，發爲中夜吟。", "無論君自感，聞者欲霑襟。"]'),
('08ddb320-00e7-48e2-b758-c9d4986a0178','重到渭上舊居','白居易','唐','唐诗','tang','','[]','舊居清渭曲，開門當蔡渡。',144,'全唐诗/poet.tang.22000.json','["舊居清渭曲，開門當蔡渡。", "十年方一還，幾欲迷歸路。", "追思昔日行，感傷故游處。", "插柳作高林，種桃成老樹。", "因驚成人者，盡是舊童孺。", "試問舊老人，半爲繞村墓。", "浮生同過客，前後遞來去。", "白日如弄珠，出沒光不住。", "人物日改變，舉目悲所遇。", "回念念我身，安得不衰暮。", "朱顏銷不歇，白髮生無數。", "唯有山門外，三峰色如故。"]'),
('a2811f42-120f-4b45-b4f7-7d97ba992ef0','白髮','白居易','唐','唐诗','tang','','[]','白髮知時節，闇與我有期。',144,'全唐诗/poet.tang.22000.json','["白髮知時節，闇與我有期。", "今朝日陽裹，梳落數莖絲。", "家人不慣見，憫默爲我悲。", "我云何足怪，此意爾不知。", "凡人年三十，外壯中已衰。", "但思寢食味，已減二十時。", "況我今四十，本來形貌羸。", "書魔昏兩眼，酒病沈四肢。", "親愛日零落，在者仍別離。", "身心久如此，白髮生已遲。", "由來生老死，三病長相隨。", "除却念無生，人間無藥治。"]'),
('d7f1fa7e-9a70-40a3-8d1b-62f7389d6b0f','秋日','白居易','唐','唐诗','tang','','[]','池殘寥落水，窗下悠楊日。',36,'全唐诗/poet.tang.22000.json','["池殘寥落水，窗下悠楊日。", "嫋嫋秋風多，槐花半成實。", "下有獨立人，年來四十一。"]'),
('783dbf4f-eaee-419c-a86f-5bba5e8a8370','將之饒州江浦夜泊','白居易','唐','唐诗','tang','','[]','明月滿深浦，愁人臥孤舟。',108,'全唐诗/poet.tang.22000.json','["明月滿深浦，愁人臥孤舟。", "煩冤寢不得，夏夜長於秋。", "苦乏衣食資，遠爲江海游。", "光陰坐遲暮，鄉國行阻修。", "身病向鄱陽，家貧寄徐州。", "前事與後事，豈堪心幷憂。", "憂來起長望，但見江水流。", "雲樹靄蒼蒼，煙波澹悠悠。", "故園迷處所，一念堪白頭。"]'),
('76488b18-9b18-47db-abeb-1c2ba3d98cb3','思歸','白居易','唐','唐诗','tang','','[]','養無晨昏膳，隱無伏臘資。',96,'全唐诗/poet.tang.22000.json','["養無晨昏膳，隱無伏臘資。", "遂求及親祿，僶俛來京師。", "薄俸未及親，別家已經時。", "冬積溫席戀，春違采蘭期。", "夏至一陰生，稍稍夕漏遲。", "塊然抱愁者，長夜獨先知。", "悠悠鄉關路，夢去身不隨。", "坐惜時節變，蟬鳴槐花枝。"]'),
('b687e90b-e200-4a42-9e09-0c05702c2378','冀城北原作','白居易','唐','唐诗','tang','','[]','野色何莽蒼，秋聲亦蕭疎。',108,'全唐诗/poet.tang.22000.json','["野色何莽蒼，秋聲亦蕭疎。", "風吹黃埃起，落日驅征車。", "何代此開國，封疆百里餘。", "古今不相待，朝市無常居。", "昔人城邑中，今變爲丘墟。", "昔人墓田中，今化爲里閭。", "廢興相催迫，日月互居諸。", "世變無遺風，焉能知其初。", "行人千載後，懷古空躊躇。"]'),
('0176e6c7-d4db-4890-9cbb-937f04a351d2','客路感秋寄明準上人','白居易','唐','唐诗','tang','','[]','日暮天地冷，雨霽山河清。',72,'全唐诗/poet.tang.22000.json','["日暮天地冷，雨霽山河清。", "長風從西來，草木凝秋聲。", "已感歲倏忽，復傷物凋零。", "孰能不憯悽，天時牽人情。", "借問空門子，何法易修行。", "使我忘得心，不教煩惱生。"]'),
('0d9ceb06-f371-490a-bfb9-0687677aabf5','遊襄陽懷孟浩然','白居易','唐','唐诗','tang','','[]','楚山碧巖巖，漢水碧湯湯。',72,'全唐诗/poet.tang.22000.json','["楚山碧巖巖，漢水碧湯湯。", "秀氣結成象，孟氏之文章。", "今我諷遺文，思人至其鄉。", "清風無人繼，日暮空襄陽。", "南望鹿門山，藹若有餘芳。", "舊隱不知處，雲深樹蒼蒼。"]'),
('31a7d689-501a-42d0-858b-9a57cefff693','秋暮西歸途中書情','白居易','唐','唐诗','tang','','[]','耿耿旅燈下，愁多常少眠。',96,'全唐诗/poet.tang.22000.json','["耿耿旅燈下，愁多常少眠。", "思鄉貴早發，發在雞鳴前。", "九月草木落，平蕪連遠山。", "秋陰和曙色，萬木蒼蒼然。", "去秋偶東遊，今秋始西旋。", "馬瘦衣裳破，別家來二年。", "憶歸復愁歸，歸無一囊錢。", "心雖非蘭膏，安得不自然。"]'),
('264fac5e-a33e-4c83-8bb8-f80cf8d4fc3d','秋懷','白居易','唐','唐诗','tang','','[]','月出照北堂，光華滿階墀。',72,'全唐诗/poet.tang.22000.json','["月出照北堂，光華滿階墀。", "涼風從西至，草木日夜衰。", "桐柳減綠陰，蕙蘭消碧滋。", "感物私自念，我心亦如之。", "安得長少壯，盛衰迫天時。", "人生如石火，爲樂長苦遲。"]'),
('cfa3c78d-8545-4281-885e-1f3818fc01a8','別楊穎士盧克柔殷堯藩','白居易','唐','唐诗','tang','','[]','倦鳥暮歸林，浮雲晴歸山。',84,'全唐诗/poet.tang.22000.json','["倦鳥暮歸林，浮雲晴歸山。", "獨有行路子，悠悠不知還。", "人生苦營營，終日羣動間。", "所務雖不同，同歸於不閑。", "扁舟來楚鄉，匹馬往秦關。", "離憂繞心曲，宛轉如循環。", "且持一杯酒，聊以開愁顏。"]'),
('936b0dc4-23d8-4b40-bd1e-1e471248c3f5','題贈定光上人','白居易','唐','唐诗','tang','','[]','二十身出家，四十心離塵。',84,'全唐诗/poet.tang.22000.json','["二十身出家，四十心離塵。", "得徑入大道，乘此不退輪。", "一坐十五年，林下秋復春。", "春花與秋氣，不感無情人。", "我來如有悟，潛以心照身。", "誤落聞見中，憂喜傷形神。", "安得遺耳目，冥然反天真。"]'),
('a53e45ec-bf42-4a8b-ac28-c346640da045','祇役駱口驛喜蕭侍御書至兼覩新詩吟諷通宵因寄八韻','白居易','唐','唐诗','tang','','[]','日暮心無憀，吏役正營營。',96,'全唐诗/poet.tang.22000.json','["日暮心無憀，吏役正營營。", "忽驚芳信至，復與新詩幷。", "是時天無雲，山館有月明。", "月下讀數徧，風前吟一聲。", "一吟三四歎，聲盡有餘清。", "雅哉君子文，詠性不詠情。", "使我靈府中，鄙恡不得生。", "始知聽韶濩，可使心和平。"]'),
('12cc58c8-a039-480f-9da6-930f3187643f','酬李少府曹長官舍見贈','白居易','唐','唐诗','tang','','[]','低腰復斂手，心體不遑安。',120,'全唐诗/poet.tang.22000.json','["低腰復斂手，心體不遑安。", "一落風塵下，方知爲吏難。", "公事與日長，宦情隨歲闌。", "惆悵青袍袖，芸香無半殘。", "賴有李夫子，此懷聊自寬。", "兩心如止水，彼此無波瀾。", "往往簿書暇，相勸強爲歡。", "白馬晚蹋雪，淥觴春暖寒。", "戀月夜同宿，愛山晴共看。", "野性自相近，不是爲同官。"]'),
('fb05abc3-afb4-4db4-bc39-d18d65b8575c','留別','白居易','唐','唐诗','tang','','[]','秋涼卷朝簟，春暖撤夜衾。',84,'全唐诗/poet.tang.22000.json','["秋涼卷朝簟，春暖撤夜衾。", "雖是無情物，欲別尚沈吟。", "況與有情別，別隨情淺深。", "二年歡笑意，一旦東西心。", "獨留誠可念，同行力不任。", "前事詎能料，後期諒難尋。", "唯有潺湲淚，不惜共霑襟。"]'),
('141edffd-4350-4fdc-b4f0-2bc2a19d3917','曉別','白居易','唐','唐诗','tang','','[]','曉鼓聲已半，離筵坐難久。',48,'全唐诗/poet.tang.22000.json','["曉鼓聲已半，離筵坐難久。", "請君斷腸歌，送我和淚酒。", "月落欲明前，馬嘶初別後。", "浩浩暗塵中，何由見回首。"]'),
('732bc81e-d8f9-4313-a6a8-72d3c556adac','北園','白居易','唐','唐诗','tang','','[]','北園東風起，雜花次第開。',48,'全唐诗/poet.tang.22000.json','["北園東風起，雜花次第開。", "心知須臾落，一日三四來。", "花下豈無酒，欲酌復遲迴。", "所思眇千里，誰勸我一杯。"]'),
('a8212efc-dbeb-45c7-9480-433e10eefcc3','惜栯李花','白居易','唐','唐诗','tang','','[]','樹小花鮮妍，香繁條輭弱。',72,'全唐诗/poet.tang.22000.json','["樹小花鮮妍，香繁條輭弱。", "高低二三尺，重疊千萬萼。", "朝豔藹霏霏，夕凋紛漠漠。", "辭枝朱粉細，覆地紅綃薄。", "由來好顏色，常苦易銷鑠。", "不見莨蕩花，狂風吹不落。"]'),
('32438154-b246-43e1-9d94-cf3dbece702b','照鏡','白居易','唐','唐诗','tang','','[]','皎皎青銅鏡，斑斑白絲鬢。',24,'全唐诗/poet.tang.22000.json','["皎皎青銅鏡，斑斑白絲鬢。", "豈復更藏年，實年君不信。"]'),
('f269f218-4019-4bd1-89d2-84645352fc6f','新秋','白居易','唐','唐诗','tang','','[]','西風飄一葉，庭前颯已涼。',36,'全唐诗/poet.tang.22000.json','["西風飄一葉，庭前颯已涼。", "風池明月水，衰蓮白露房。", "其奈江南夜，緜緜自此長。"]'),
('f6d8b0d3-b2d5-452e-b99a-073be0c949b1','夜雨','白居易','唐','唐诗','tang','','[]','早蛩啼復歇，殘燈滅又明。',24,'全唐诗/poet.tang.22000.json','["早蛩啼復歇，殘燈滅又明。", "隔窗知夜雨，芭蕉先有聲。"]'),
('f3ae22d8-4ffa-40c0-b27b-d7d4a2a5b9a2','秋江送客','白居易','唐','唐诗','tang','','[]','秋鴻次第過，哀猨朝夕聞。',48,'全唐诗/poet.tang.22000.json','["秋鴻次第過，哀猨朝夕聞。", "是日孤舟客，此地亦離羣。", "濛濛潤衣雨，漠漠冒帆雲。", "不醉潯陽酒，煙波愁殺人。"]'),
('7ed6624c-c86d-4e4c-aeec-70c4fd40beba','感逝寄遠','白居易','唐','唐诗','tang','','[]','昨日聞甲死，今朝聞乙死。',108,'全唐诗/poet.tang.22000.json','["昨日聞甲死，今朝聞乙死。", "知識三分中，二分化爲鬼。", "逝者不復見，悲哉長已矣。", "存者今如何，去我皆萬里。", "平生知心者，屈指能有幾。", "通果澧鳳州，眇然四君子。", "相思俱老大，浮世如流水。", "應歎舊交遊，凋零日如此。", "何當一杯酒，開眼笑相視。"]'),
('28aa0fb5-842b-451f-9f56-f7139050a820','秋月','白居易','唐','唐诗','tang','','[]','夜初色蒼然，夜深光浩然。',60,'全唐诗/poet.tang.22000.json','["夜初色蒼然，夜深光浩然。", "稍轉西廊下，漸滿南窗前。", "況是綠蕪地，復茲清露天。", "落葉聲策策，驚鳥影翩翩。", "棲禽尚不穩，愁人安可眠。"]'),
('0222bb09-1f03-473b-b3d7-bd41709a2643','朱陳村','白居易','唐','唐诗','tang','','[]','徐州古豐縣，有村曰朱陳。',288,'全唐诗/poet.tang.22000.json','["徐州古豐縣，有村曰朱陳。", "去縣百餘里，桑麻青氛氳。", "機梭聲札札，牛驢走紜紜。", "女汲澗中水，男采山上薪。", "縣遠官事少，山深人俗淳。", "有財不行商，有丁不入軍。", "家家守村業，頭白不出門。", "生爲村之民，死爲村之塵。", "田中老與幼，相見何欣欣。", "一村唯兩姓，世世爲婚姻。", "親疎居有族，少長游有羣。", "黃雞與白酒，歡會不隔旬。", "生者不遠別，嫁娶先近鄰。", "死者不遠葬，墳墓多繞村。", "既安生與死，不苦形與神。", "所以多壽考，往往見玄孫。", "我生禮義鄉，少小孤且貧。", "徒學辨是非，祗自取辛勤。", "世法貴名教，士人重冠婚。", "以此自桎梏，信爲大謬人。", "十歲解讀書，十五能屬文。", "二十舉秀才，三十爲諫臣。", "下有妻子累，上有君親恩。", "承家與事國，望此不肖身。"]'),
('72f3a210-bbcb-475a-893e-e503b0a2b2b3','讀鄧魴詩','白居易','唐','唐诗','tang','','[]','塵架多文集，偶取一卷披。',132,'全唐诗/poet.tang.22000.json','["塵架多文集，偶取一卷披。", "未及看姓名，疑是陶潛詩。", "看名知是君，惻惻令我悲。", "詩人多蹇厄，近日誠有之。", "京兆杜子美，猶得一拾遺。", "襄陽孟浩然，亦聞鬢成絲。", "嗟君兩不如，三十在布衣。", "擢第祿不及，新婚妻未歸。", "少年無疾患，溘死於路岐。", "天不與爵壽，唯與好文詞。", "此理勿復道，巧曆不能推。"]'),
('46651f37-51e1-42ac-a715-7cc7b371ad9d','寄元九','白居易','唐','唐诗','tang','','[]','晨雞纔發聲，夕雀俄斂翼。',120,'全唐诗/poet.tang.22000.json','["晨雞纔發聲，夕雀俄斂翼。", "晝夜往復來，疾如出入息。", "非徒改年貌，漸覺無心力。", "自念因念君，俱爲老所逼。", "君年雖校少，顦顇謫南國。", "三年不放歸，炎瘴消顏色。", "山無殺草霜，水有含沙蜮。", "健否遠不知，書多隔年得。", "願君少愁苦，我亦加餐食。", "各保金石軀，以慰長相憶。"]'),
('62c92c57-888e-4d8a-89a5-ea71ae667588','秋夕','白居易','唐','唐诗','tang','','["\u6292\u60c5", "\u79cb\u5929", "\u591c\u665a", "\u5bc2\u5bde"]','葉聲落如雨，月色白似霜。',24,'全唐诗/poet.tang.22000.json','["葉聲落如雨，月色白似霜。", "夜深方獨臥，誰爲拂塵牀。"]'),
('a9d53bcc-3270-4d07-8231-c562f2ac6ab1','夜雨','白居易','唐','唐诗','tang','','["\u601d\u5ff5", "\u7231\u60c5"]','我有所念人，隔在遠遠鄉。',84,'全唐诗/poet.tang.22000.json','["我有所念人，隔在遠遠鄉。", "我有所感事，結在深深腸。", "鄉遠去不得，無日不瞻望。", "腸深解不得，無夕不思量。", "況此殘燈夜，獨宿在空堂。", "秋天殊未曉，風雨正蒼蒼。", "不學頭陀法，前心安可忘。"]'),
('248d9898-55a6-4808-9e38-5efc8f42e577','秋霽','白居易','唐','唐诗','tang','','[]','金火不相待，炎涼雨中變。',96,'全唐诗/poet.tang.22000.json','["金火不相待，炎涼雨中變。", "林晴有殘蟬，巢冷無留燕。", "沈吟卷長簟，愴惻收團扇。", "向夕稍無泥，閑步青苔院。", "月出砧杵動，家家擣秋練。", "獨對多病妻，不能理鍼線。", "冬衣殊未製，夏服行將綻。", "何以迎早秋，一杯聊自勸。"]'),
('4772819b-32a2-4514-8f90-1361d2357843','歎老三首 一','白居易','唐','唐诗','tang','','[]','晨興照青鏡，形影兩寂莫。',96,'全唐诗/poet.tang.22000.json','["晨興照青鏡，形影兩寂莫。", "少年辭我去，白髮隨梳落。", "萬化成於漸，漸衰看不覺。", "但恐鏡中顏，今朝老於昨。", "人年少滿百，不得長歡樂。", "誰會天地心，千齡與龜鶴。", "吾聞善醫者，今古稱扁鵲。", "萬病皆可治，唯無治老藥。"]'),
('5996c15d-b2f7-4a0c-bb8b-65d4a2825b60','歎老三首 二','白居易','唐','唐诗','tang','','[]','我有一握髮，梳理何稠直。',72,'全唐诗/poet.tang.22000.json','["我有一握髮，梳理何稠直。", "昔似玄雲光，今如素絲色。", "匣中有舊鏡，欲照先歎息。", "自從頭白來，不欲明磨拭。", "鵶頭與鶴頸，至老常如墨。", "獨有人鬢毛，不得終身黑。"]'),
('79801027-bbbc-4b2c-a4c7-b21b6a043b03','歎老三首 三','白居易','唐','唐诗','tang','','[]','前年種桃核，今歲成花樹。',72,'全唐诗/poet.tang.22000.json','["前年種桃核，今歲成花樹。", "去歲新嬰兒，今年已學步。", "但驚物長成，不覺身衰暮。", "去矣欲何如，少年留不住。", "因書今日意，徧寄諸親故。", "壯歲不歡娛，長年當悔悟。"]'),
('3a41a91c-5796-4fdc-b894-09d5bc60104a','送兄弟迴雪夜','白居易','唐','唐诗','tang','','[]','日晦雲氣黃，東北風切切。',132,'全唐诗/poet.tang.22000.json','["日晦雲氣黃，東北風切切。", "時從村南還，新與兄弟別。", "離襟淚猶濕，迴馬嘶未歇。", "欲歸一室坐，天陰多無月。", "夜長火消盡，歲暮雨凝結。", "寂莫滿爐灰，飄零上階雪。", "對雪畫寒灰，殘燈明復滅。", "灰死如我心，雪白如我髮。", "所隅皆如此，頃刻堪愁絕。", "迴念入坐忘，轉憂作禪悅。", "平生洗心法，正爲今宵設。"]'),
('c3ae4cc8-c812-4a1b-8db1-d288eae16cd8','溪中早春','白居易','唐','唐诗','tang','','[]','南山雪未盡，陰嶺留殘白。',96,'全唐诗/poet.tang.22000.json','["南山雪未盡，陰嶺留殘白。", "西澗冰已消，春溜含新碧。", "東風來幾日，蟄動萌草坼。", "潛知陽和功，一日不虛擲。", "愛此天氣暖，來拂溪邊石。", "一坐欲忘歸，暮禽聲嘖嘖。", "蓬蒿隔桑棗，隱映煙火夕。", "歸來問夜餐，家人烹薺麥。"]'),
('aa1d614a-80fe-45d0-9a71-d45504eb7e2a','同友人尋澗花','白居易','唐','唐诗','tang','','[]','聞有澗底花，貰得村中酒。',72,'全唐诗/poet.tang.22000.json','["聞有澗底花，貰得村中酒。", "與君來校遲，已逢搖落後。", "臨觴有遺恨，悵望空溪口。", "記取花發時，期君重攜手。", "我生日日老，春色年年有。", "且作來歲期，不知身健否。"]'),
('4f5e9ddd-d31b-4114-876f-4c88e68529df','登村東古冢','白居易','唐','唐诗','tang','','[]','高低古時冢，上有牛羊道。',72,'全唐诗/poet.tang.22000.json','["高低古時冢，上有牛羊道。", "獨立最高頭，悠哉此懷抱。", "回頭向村望，但見荒田草。", "村人不愛花，多種栗與棗。", "自來此村住，不覺風光好。", "花少鶯亦稀，年年春暗老。"]'),
('25aa730e-feeb-4c76-a53d-a01af05b3e81','夢裴相公','白居易','唐','唐诗','tang','','[]','五年生死隔，一夕魂夢通。',96,'全唐诗/poet.tang.22000.json','["五年生死隔，一夕魂夢通。", "夢中如往日，同直金鑾宮。", "髣髴金紫色，分明冰玉容。", "勤勤相眷意，亦與平生同。", "既寤知是夢，憫然情未終。", "追想當時事，何殊昨夜中。", "自我學心法，萬緣成一空。", "今朝爲君子，流涕一霑胷。"]'),
('c8b85263-8da7-44f4-8c86-6b9c14fa722e','晝寢','白居易','唐','唐诗','tang','','[]','坐整白單衣，起穿黃草屨。',72,'全唐诗/poet.tang.22000.json','["坐整白單衣，起穿黃草屨。", "朝餐盥漱畢，徐下階前步。", "暑風微變候，晝刻漸加數。", "院靜地陰陰，鳥鳴新葉樹。", "獨行還獨臥，夏景殊未暮。", "不作午時眠，日長安可度。"]'),
('a5fa2ff4-32fd-4d08-8b7b-8b0a9648391b','別行簡','白居易','唐','唐诗','tang','','[]','漠漠病眼花，星星愁鬢雪。',72,'全唐诗/poet.tang.22000.json','["漠漠病眼花，星星愁鬢雪。", "筋骸已衰憊，形影仍分訣。", "梓州二千里，劒門五六月。", "豈是遠行時，火雲燒棧熱。", "何言巾上淚，乃是腸中血。", "念此早歸來，莫作經年別。"]'),
('7ad675c6-429f-4c7f-8206-9dad9eb9bf97','觀兒戲','白居易','唐','唐诗','tang','','[]','髫齔七八歲，綺紈三四兒。',72,'全唐诗/poet.tang.22000.json','["髫齔七八歲，綺紈三四兒。", "弄塵復鬭草，盡日樂嬉嬉。", "堂上長年客，鬢間新有絲。", "一看竹馬戲，每憶童騃時。", "童騃饒戲樂，老大多憂悲。", "靜念彼與此，不知誰是癡。"]'),
('55a68da0-d388-41e1-b2bc-bc28d7cb5c90','歎常生','白居易','唐','唐诗','tang','','[]','西村常氏子，臥疾不須臾。',84,'全唐诗/poet.tang.22000.json','["西村常氏子，臥疾不須臾。", "前旬猶訪我，今日忽云殂。", "時我病多暇，與之同野居。", "園林青藹藹，相去數里餘。", "村鄰無好客，所遇唯農夫。", "之子何如者，往還猶勝無。", "於今亦已矣，可爲一長吁。"]'),
('8696f17e-1c98-44c7-aea6-ef1e5d77bc81','寄元九','白居易','唐','唐诗','tang','','[]','一病經四年，親朋書信斷。',144,'全唐诗/poet.tang.22000.json','["一病經四年，親朋書信斷。", "窮通合易交，自笑知何晚。", "元君在荆楚，去日唯云遠。", "彼獨是何人，心如石不轉。", "憂我貧病身，書來唯勸勉。", "上言少愁苦，下道加餐飯。", "憐君爲謫吏，窮薄家貧褊。", "三寄衣食資，數盈二十萬。", "豈是貪衣食，感君心繾綣。", "念我口中食，分君身上暖。", "不因身病久，不因命多蹇。", "平生親友心，豈得知深淺。"]'),
('59961879-b1b9-4b0a-a135-0eee90d9c6df','以鏡贈別','白居易','唐','唐诗','tang','','[]','人言似明月，我道勝明月。',84,'全唐诗/poet.tang.22000.json','["人言似明月，我道勝明月。", "明月非不明，一年十二缺。", "豈如玉匣裏，如水常澄澈。", "月破天闇時，圓明獨不歇。", "我慙貌醜老，繞鬢斑斑雪。", "不如贈少年，迴照青絲髮。", "因君千里去，持此將爲別。"]'),
('7c0844ef-7bb9-4f46-905c-cd9ec2397780','城上對月期友人不至','白居易','唐','唐诗','tang','','[]','古人惜晝短，勸令秉燭遊。',72,'全唐诗/poet.tang.22000.json','["古人惜晝短，勸令秉燭遊。", "況此迢迢夜，明月滿西樓。", "復有盈尊酒，置在城上頭。", "期君君不至，人月兩悠悠。", "照水煙波白，照人肌髮秋。", "清光正如此，不醉即須愁。"]'),
('b80e5559-aae4-4e73-a4d6-17bac3a5861e','念金鑾子二首 一','白居易','唐','唐诗','tang','','[]','衰病四十身，嬌癡三歲女。',96,'全唐诗/poet.tang.22000.json','["衰病四十身，嬌癡三歲女。", "非男猶勝無，慰情時一撫。", "一朝舍我去，魂影無處所。", "況念夭札時，嘔啞初學語。", "始知骨肉愛，乃是憂悲聚。", "唯思未有前，以理遣傷苦。", "忘懷日已久，三度移寒暑。", "今日一傷心，因逢舊乳母。"]'),
('4a567bce-4469-4608-9276-3b91502f0677','念金鑾子二首 二','白居易','唐','唐诗','tang','','[]','與爾爲父子，八十有六旬。',72,'全唐诗/poet.tang.22000.json','["與爾爲父子，八十有六旬。", "忽然又不見，邇來三四春。", "形質本非實，氣聚偶成身。", "恩愛元是妄，緣合暫爲親。", "念茲庶有悟，聊用遣悲辛。", "暫將理自奪，不是忘情人。"]'),
('b9adf761-989e-4bc6-9b8c-c03e721acc7e','對酒','白居易','唐','唐诗','tang','','[]','人生一百歲，通計三萬日。',132,'全唐诗/poet.tang.22000.json','["人生一百歲，通計三萬日。", "何況百歲人，人間百無一。", "賢愚共零落，貴賤同埋沒。", "東岱前後魂，北邙新舊骨。", "復聞藥誤者，爲愛延年術。", "又有憂死者，爲貪政事筆。", "藥誤不得老，憂死非因疾。", "誰言人最靈，知得不知失。", "何如會親友，飲此杯中物。", "能沃煩慮消，能陶真性出。", "所以劉阮輩，終年醉兀兀。"]'),
('97001933-f16b-4287-8c28-85289dcddc9f','渭村雨歸','白居易','唐','唐诗','tang','','[]','渭水寒漸落，離離蒲稗苗。',60,'全唐诗/poet.tang.22000.json','["渭水寒漸落，離離蒲稗苗。", "閑傍沙邊立，看人刈葦苕。", "近水風景冷，晴明猶寂寥。", "復茲夕陰起，野色重蕭條。", "蕭條獨歸路，暮雨濕村橋。"]'),
('340df5b6-8d20-43a3-98a7-bb34a042c1e4','諭懷','白居易','唐','唐诗','tang','','[]','黑頭日已白，白面日已黑。',60,'全唐诗/poet.tang.22000.json','["黑頭日已白，白面日已黑。", "人生未死間，變化何終極。", "常言在己者，莫若形與色。", "一朝改變來，止遏不能得。", "況彼身外事，悠悠通與塞。"]'),
('e47a5ac3-492a-474c-a0e5-77e8c277ab94','喜友至留宿','白居易','唐','唐诗','tang','','[]','村中少賓客，柴門多不開。',60,'全唐诗/poet.tang.22000.json','["村中少賓客，柴門多不開。", "忽聞車馬至，云是故人來。", "況值風雨夕，愁心正悠哉。", "願君且同宿，盡此手中杯。", "人生開口笑，百年都幾回。"]'),
('3e72b2f1-222f-4aef-9bc4-edc14a398d2b','西原晚望','白居易','唐','唐诗','tang','','[]','花菊引閑行，行上西原路。',120,'全唐诗/poet.tang.22000.json','["花菊引閑行，行上西原路。", "原上晚無人，因高聊四顧。", "南阡有煙火，北陌連墟墓。", "村鄰何蕭疎，近者猶百步。", "吾廬在其下，寂莫風日暮。", "門外轉枯蓬，籬根伏寒兔。", "故園汴水上，離亂不堪去。", "近歲始移家，飄然此村住。", "新屋五六間，古槐八九樹。", "便是衰病身，此生終老處。"]'),
('8be600f6-3705-4ab5-8275-d4d00877c84e','感鏡','白居易','唐','唐诗','tang','','[]','美人與我別，留鏡在匣中。',60,'全唐诗/poet.tang.22000.json','["美人與我別，留鏡在匣中。", "自從花顏去，秋水無芙蓉。", "經年不開匣，紅埃覆青銅。", "今朝一拂拭，自照顦顇容。", "照罷重惆悵，背有雙盤龍。"]'),
('66bc5dac-9627-4a9a-bf0b-39d8ab28dcb2','村居臥病三首 一','白居易','唐','唐诗','tang','','[]','戚戚抱羸病，悠悠度朝暮。',72,'全唐诗/poet.tang.22000.json','["戚戚抱羸病，悠悠度朝暮。", "夏木纔結陰，秋蘭已含露。", "前日巢中卵，化作雛飛去。", "昨日穴中蟲，蛻爲蟬上樹。", "四時未嘗歇，一物不暫住。", "唯有病客心，沈然獨如故。"]'),
('2ef928b6-a72b-4b6b-92cb-709e011cac16','村居臥病三首 二','白居易','唐','唐诗','tang','','[]','新秋久病客，起步村南道。',72,'全唐诗/poet.tang.22000.json','["新秋久病客，起步村南道。", "盡日不逢人，蟲聲徧荒草。", "西風吹白露，野綠秋仍早。", "草木猶爲傷，先傷我懷抱。", "朱顏與玄鬢，強健幾時好。", "況爲憂病侵，不得依年老。"]'),
('c7ce007e-4803-48e5-b087-7a038484c02d','村居臥病三首 三','白居易','唐','唐诗','tang','','[]','種黍三十畝，雨來苗漸大。',72,'全唐诗/poet.tang.22000.json','["種黍三十畝，雨來苗漸大。", "種薤二十畦，秋來欲堪刈。", "望黍作冬酒，留薤爲春菜。", "荒村百物無，待此養衰瘵。", "葺廬備陰雨，補褐防寒歲。", "病身知幾時，且作明年計。"]'),
('7b1aa844-eb31-4989-ba2e-6d14e9d57c23','沐浴','白居易','唐','唐诗','tang','','[]','經年不沐浴，塵垢滿肌膚。',72,'全唐诗/poet.tang.22000.json','["經年不沐浴，塵垢滿肌膚。", "今朝一澡濯，衰瘦頗有餘。", "老色頭鬢白，病形支體虛。", "衣寬有賸帶，髮少不勝梳。", "自問今年歲，春秋四十初。", "四十已如此，七十復何如。"]'),
('c8b7495f-8244-4182-b1cd-264e5bcf4e15','栽松二首 一','白居易','唐','唐诗','tang','','[]','小松未盈尺，心愛手自移。',60,'全唐诗/poet.tang.22000.json','["小松未盈尺，心愛手自移。", "蒼然澗底色，雲濕煙霏霏。", "栽植我年晚，長成君性遲。", "如何過四十，種此數寸枝。", "得見成陰否，人生七十稀。"]'),
('fe4b141c-4a95-452b-af67-743ab26378dc','栽松二首 二','白居易','唐','唐诗','tang','','[]','愛君抱晚節，憐君含直文。',36,'全唐诗/poet.tang.22000.json','["愛君抱晚節，憐君含直文。", "欲得朝朝見，階前故種君。", "知君死則已，不死會凌雲。"]'),
('ccfd07df-3beb-43b8-bec7-945cca87118c','病中友人相訪','白居易','唐','唐诗','tang','','[]','臥久不記日，南窗昏復昏。',72,'全唐诗/poet.tang.22000.json','["臥久不記日，南窗昏復昏。", "蕭條草檐下，寒雀朝夕聞。", "強扶牀前杖，起向庭中行。", "偶逢故人至，便當一逢迎。", "移榻就斜日，披裘倚前楹。", "閑談勝服藥，稍覺有心情。"]'),
('0140c146-0252-485e-a8d3-fc3e41b1d774','自覺二首 一','白居易','唐','唐诗','tang','','[]','四十未爲老，憂傷早衰惡。',96,'全唐诗/poet.tang.22000.json','["四十未爲老，憂傷早衰惡。", "前歲二毛生，今年一齒落。", "形骸日損耗，心事同蕭索。", "夜寢與朝餐，其間味亦薄。", "同歲崔舍人，容光方灼灼。", "始知年與貌，衰盛隨憂樂。", "畏老老轉迫，憂病病彌縛。", "不畏復不憂，是除老病藥。"]'),
('233f44a6-9083-4777-980f-480bc30cafb1','自覺二首 二','白居易','唐','唐诗','tang','','[]','朝哭心所愛，暮哭心所親。',168,'全唐诗/poet.tang.22000.json','["朝哭心所愛，暮哭心所親。", "親愛零落盡，安用身獨存。", "幾許平生歡，無限骨肉恩。", "結爲腸間痛，聚作鼻頭辛。", "悲來四支緩，泣盡雙眸昏。", "所以年四十，心如七十人。", "我聞浮屠教，中有解脫門。", "置心爲止水，視身如浮雲。", "斗擻垢穢衣，度脫生死輪。", "胡爲戀此苦，不去猶逡巡。", "迴念發弘願，願此見在身。", "但受過去報，不結將來因。", "誓以智慧水，永洗煩惱塵。", "不將恩愛子，更種悲憂根。"]'),
('2a648b50-fe29-43e2-9fba-773a0f8ee498','夜雨有念','白居易','唐','唐诗','tang','','[]','以道治心氣，終歲得晏然。',168,'全唐诗/poet.tang.22000.json','["以道治心氣，終歲得晏然。", "何乃戚戚意，忽來風雨天。", "既非慕榮顯，又不恤飢寒。", "胡爲悄不樂，抱膝殘燈前。", "形影闇相問，心默對以言。", "骨肉能幾人，各在天一端。", "吾兄寄宿州，吾弟客東川。", "南北五千里，吾身在中間。", "欲去病未能，欲住心不安。", "有如波上舟，此縛而彼牽。", "自我向道來，於今六七年。", "鍊成不二性，消盡千萬緣。", "唯有恩愛火，往往猶熬煎。", "豈是藥無効，病多難盡蠲。"]'),
('3c9550da-c246-44cf-ab2d-2433ccc1a379','寄楊六','白居易','唐','唐诗','tang','','[]','青宮官冷靜，赤縣事繁劇。',144,'全唐诗/poet.tang.22000.json','["青宮官冷靜，赤縣事繁劇。", "一閑復一忙，動作經時隔。", "清觴久廢酌，白日頓虛擲。", "念此忽踟躕，悄然心不適。", "豈無舊交結，久別或遷易。", "亦有新往還，相見多形迹。", "唯君於我分，堅久如金石。", "何況老大來，人情重姻戚。", "會稀歲月急，此事真可惜。", "幾回開口笑，便到髭鬚白。", "公門苦鞅掌，盡日無閑隙。", "猶冀乘暝來，靜言同一夕。"]'),
('b868d49c-b4e7-4ef0-989c-97dfc95a9262','送春','白居易','唐','唐诗','tang','','[]','三月三十日，春歸日復暮。',120,'全唐诗/poet.tang.22000.json','["三月三十日，春歸日復暮。", "惆悵問春風，明朝應不住。", "送春曲江上，眷眷東西顧。", "但見撲水花，紛紛不知數。", "人生似行客，兩足無停步。", "日日進前程，前程幾多路。", "兵刀與水火，盡可違之去。", "唯有老到來，人間無避處。", "感時良爲已，獨倚池南樹。", "今日送春心，心如別親故。"]'),
('b7d2b816-02aa-441b-aa10-0f9ae1cb001a','哭李三','白居易','唐','唐诗','tang','','[]','去年渭水曲，秋時訪我來。',60,'全唐诗/poet.tang.22000.json','["去年渭水曲，秋時訪我來。", "今年常樂里，春日哭君迴。", "哭君仰問天，天意安在哉。", "若必奪其壽，何如不與才。", "落然身後事，妻病女嬰孩。"]'),
('18f47afa-c6d7-474b-a31e-530e4be0b123','別李十一後重寄','白居易','唐','唐诗','tang','','[]','秋日正蕭條，驅車出蓬蓽。',96,'全唐诗/poet.tang.22000.json','["秋日正蕭條，驅車出蓬蓽。", "回望青門道，目極心鬱鬱。", "豈獨戀鄉土，非關慕簪紱。", "所愴別李君，平生同道術。", "俱承金馬詔，聯秉諫臣筆。", "共上青雲梯，中途一相失。", "江湖我方往，朝廷君不出。", "蕙帶與華簪，相逢是何日。"]'),
('c1dc6a8f-3f1d-474c-a890-db56f552175f','初出藍田路作','白居易','唐','唐诗','tang','','[]','停驂問前路，路在秋雲裏。',84,'全唐诗/poet.tang.22000.json','["停驂問前路，路在秋雲裏。", "蒼蒼縣南道，去途從此始。", "絕頂忽上盤，衆山皆下視。", "下視千萬峰，峰頭如浪起。", "朝經韓公坡，夕次藍橋水。", "潯陽近四千，始行七十里。", "人煩馬蹄跙，勞苦已如此。"]'),
('048aa681-6d9e-46e7-8c33-e3079b829bfc','仙娥峰下作','白居易','唐','唐诗','tang','','[]','我爲東南行，始登商山道。',96,'全唐诗/poet.tang.22000.json','["我爲東南行，始登商山道。", "商山無數峰，最愛仙娥好。", "參差樹若插，匼匝雲如抱。", "渴望寒玉泉，香聞紫芝草。", "青崖屏削碧，白石牀鋪縞。", "向無如此物，安足留四皓。", "感彼私自問，歸山何不早？", "可能塵土中，還隨衆人老。"]'),
('09cc086c-f5d8-4a81-bcf8-b5e0409102bd','微雨夜行','白居易','唐','唐诗','tang','','["\u5199\u96e8", "\u96e8", "\u79cb\u5929"]','漠漠秋雲起，稍稍夜寒生。',24,'全唐诗/poet.tang.22000.json','["漠漠秋雲起，稍稍夜寒生。", "但覺衣裳濕，無點亦無聲。"]'),
('2b71596a-461e-42f8-8b3b-3e008a47ba11','再到襄陽訪問舊居','白居易','唐','唐诗','tang','','[]','昔到襄陽日，髯髯初有髭。',72,'全唐诗/poet.tang.22000.json','["昔到襄陽日，髯髯初有髭。", "今過襄陽日，髭鬢半成絲。", "舊遊都是夢，乍到忽如歸。", "東郭蓬蒿宅，荒涼今屬誰。", "故知多零落，閭井亦遷移。", "獨有秋江水，煙波似舊時。"]'),
('0a07b860-b2a9-400a-bd64-6ae984238e8e','寄微之三首 一','白居易','唐','唐诗','tang','','[]','江州望通州，天涯與地末。',108,'全唐诗/poet.tang.22000.json','["江州望通州，天涯與地末。", "有山萬丈高，有江千里闊。", "間之以雲霧，飛鳥不可越。", "誰知千古險，爲我二人設。", "通州君初到，鬱鬱愁如結。", "江州我方去，迢迢行未歇。", "道路日乖隔，音信日斷絕。", "因風欲寄語，地遠聲不徹。", "生當復相逢，死當從此別。"]'),
('f4a0f93e-d434-4637-a68d-36c810f7c7b5','寄微之三首 二','白居易','唐','唐诗','tang','','[]','君遊襄陽日，我在長安住。',72,'全唐诗/poet.tang.22000.json','["君遊襄陽日，我在長安住。", "今君在通州，我過襄陽去。", "襄陽九里郭，樓堞連雲樹。", "顧此稍依依，是君舊遊處。", "蒼茫蒹葭水，中有潯陽路。", "此去更相思，江西少親故。"]'),
('7501b5d9-3970-4e2d-9bed-ffc62ecf8fa2','寄微之三首 三','白居易','唐','唐诗','tang','','[]','去國日已遠，喜逢物似人。',72,'全唐诗/poet.tang.22000.json','["去國日已遠，喜逢物似人。", "如何含此意，江上坐思君。", "有如河嶽氣，相合方氛氳。", "狂風吹中絕，兩處成孤雲。", "風迴終有時，雲合豈無因。", "努力各自愛，窮通我爾身。"]'),
('4cda6a5a-7b3a-48d9-9b33-5c94a08addbd','舟中雨夜','白居易','唐','唐诗','tang','','[]','江雲闇悠悠，江風冷修修。',36,'全唐诗/poet.tang.22000.json','["江雲闇悠悠，江風冷修修。", "夜雨滴船背，風浪打船頭。", "船中有病客，左降向江州。"]'),
('ddc5d190-b8ce-4fea-8688-c8207f1dd0a3','夜聞歌者','白居易','唐','唐诗','tang','','[]','夜泊鸚鵡洲，江月秋澄澈。',96,'全唐诗/poet.tang.22000.json','["夜泊鸚鵡洲，江月秋澄澈。", "鄰船有歌者，發詞堪愁絕。", "歌罷繼以泣，泣聲通復咽。", "尋聲見其人，有婦顏如雪。", "獨倚帆檣立，娉婷十七八。", "夜淚如真珠，雙雙墮明月。", "借問誰家婦，歌泣何淒切。", "一問一霑襟，低眉終不說。"]'),
('0246b2be-ab19-4063-9447-b6658308e987','江樓聞砧','白居易','唐','唐诗','tang','','[]','江人授衣晚，十月始聞砧。',24,'全唐诗/poet.tang.22000.json','["江人授衣晚，十月始聞砧。", "一夕高樓月，萬里故園心。"]'),
('837bb26f-fb51-410f-8450-1d8585163e7b','宿東林寺','白居易','唐','唐诗','tang','','["\u5e90\u5c71"]','經窗燈燄短，僧爐火氣深。',24,'全唐诗/poet.tang.22000.json','["經窗燈燄短，僧爐火氣深。", "索落廬山夜，風雪宿東林。"]'),
('c6ff9ad0-43ff-4ebc-97f8-329f854a396a','憶洛下故園','白居易','唐','唐诗','tang','','[]','潯陽遷謫地，洛陽離亂年。',36,'全唐诗/poet.tang.22000.json','["潯陽遷謫地，洛陽離亂年。", "煙塵三川上，炎瘴九江邊。", "鄉心坐如此，秋風仍颯然。"]'),
('289051f2-c5ae-4d15-a8ad-af047135eafe','贈別崔五','白居易','唐','唐诗','tang','','[]','朝送南去客，暮迎北來賓。',120,'全唐诗/poet.tang.22000.json','["朝送南去客，暮迎北來賓。", "孰云當大路，少遇心所親。", "勞者念息肩，熱者思濯身。", "何如愁獨日，忽見平生人。", "平生已不淺，是日重殷勤。", "問從何處來，及此江亭春。", "江天春多陰，夜月隔重雲。", "移尊樹間飲，燈照花紛紛。", "一會不易得，餘事何足云。", "明旦又分手，今夕且歡忻。"]'),
('c284fc26-a0d0-4613-8098-ab3902dd42f5','春晚寄微之','白居易','唐','唐诗','tang','','[]','三月江水闊，悠悠桃花波。',60,'全唐诗/poet.tang.22000.json','["三月江水闊，悠悠桃花波。", "年芳與心事，此地共蹉跎。", "南國方譴謫，中原正兵戈。", "眼前故人少，頭上白髮多。", "通州更迢遰，春盡復如何。"]'),
('4141d0b8-ba8d-47ce-9557-f67a2c96f247','漸老','白居易','唐','唐诗','tang','','[]','今朝復明日，不覺年齒暮。',60,'全唐诗/poet.tang.22000.json','["今朝復明日，不覺年齒暮。", "白髮逐梳落，朱顏辭鏡去。", "當春頗愁寂，對酒寡歡趣。", "遇境多愴辛，逢人益敦故。", "形質屬天地，推遷從不住。"]'),
('816b18c2-ded2-498f-b2ec-e38c089fe2a1','送幼史','白居易','唐','唐诗','tang','','[]','淮右寇未散，江西歲再徂。',36,'全唐诗/poet.tang.22000.json','["淮右寇未散，江西歲再徂。", "故里干戈地，行人風雪途。", "此時與爾別，江畔立踟躕。"]'),
('c1b24e4f-f54b-492d-b36e-32c4657e90eb','夜雪','白居易','唐','唐诗','tang','','["\u5199\u96ea", "\u51ac\u5929", "\u96ea"]','已訝衾枕冷，復見窗戶明。',24,'全唐诗/poet.tang.22000.json','["已訝衾枕冷，復見窗戶明。", "夜深知雪重，時聞折竹聲。"]'),
('56cd2868-9a01-4826-951e-c8a8dc6c167f','寄行簡','白居易','唐','唐诗','tang','','[]','鬱鬱眉多斂，默默口寡言。',96,'全唐诗/poet.tang.22000.json','["鬱鬱眉多斂，默默口寡言。", "豈是願如此，舉目誰與歡。", "去春爾西征，從事巴蜀間。", "今春我南謫，抱疾江海壖。", "相去六千里，地絕天邈然。", "十書九不達，何以開憂顏。", "渴人多夢飲，飢人多夢餐。", "春來夢何處，合眼到東川。"]'),
('4abf0c4a-d492-4dc2-a274-77ce17def74e','首夏','白居易','唐','唐诗','tang','','[]','孟夏百物滋，動植一時好。',144,'全唐诗/poet.tang.22000.json','["孟夏百物滋，動植一時好。", "麋鹿樂深林，蟲蛇喜豐草。", "翔禽愛密葉，游鱗悅新藻。", "天和遺漏處，而我獨枯槁。", "一身在天末，骨肉皆遠道。", "舊國無來人，寇戎塵浩浩。", "沈憂竟何益，祗自勞懷抱。", "不如放身心，冥然任天造。", "潯陽多美酒，可使杯不燥。", "湓魚賤如泥，烹炙無昏早。", "朝飯山下寺，暮醉湖中島。", "何必歸故鄉，茲焉可終老。"]'),
('26c15679-c698-4827-8a23-1592a0840196','孟夏思渭村舊居寄舍弟','白居易','唐','唐诗','tang','','[]','嘖嘖雀引雛，稍稍筍成竹。',240,'全唐诗/poet.tang.22000.json','["嘖嘖雀引雛，稍稍筍成竹。", "時物感人情，憶我故鄉曲。", "故園渭水上，十載事樵牧。", "手種榆柳成，陰陰覆牆屋。", "兔隱豆苗肥，鳥鳴桑椹熟。", "前年當此時，與爾同遊矚。", "詩書課弟姪，農圃資童僕。", "日暮麥登場，天晴蠶坼簇。", "弄泉南澗坐，待月東亭宿。", "興發飲數杯，悶來棊一局。", "一朝忽分散，萬里仍羈束。", "井鮒思反泉，籠鶯悔出谷。", "九江地卑濕，四月天炎燠。", "苦雨初入梅，瘴雲稍含毒。", "泥秧水畦稻，灰種畬田粟。", "已訝殊歲時，仍嗟異風俗。", "閑登郡樓望，日落江山綠。", "歸雁拂鄉心，平湖斷人目。", "殊方我漂泊，舊里君幽獨。", "何時同一瓢，飲水心亦足。"]'),
('14ccf041-ae0f-489d-90fa-5ea184a7d8a2','早蟬','白居易','唐','唐诗','tang','','[]','六月初七日，江頭蟬始鳴。',72,'全唐诗/poet.tang.22000.json','["六月初七日，江頭蟬始鳴。", "石楠深葉裏，薄暮兩三聲。", "一催衰鬢色，再動故園情。", "西風殊未起，秋思先秋生。", "憶昔在東掖，宮槐花下聽。", "今朝無限思，雲樹繞湓城。"]'),
('287580ab-9187-4aec-ba10-33a7cd5f2826','感情','白居易','唐','唐诗','tang','','[]','中庭曬服玩，忽見故鄉履。',120,'全唐诗/poet.tang.22000.json','["中庭曬服玩，忽見故鄉履。", "昔贈我者誰，東鄰嬋娟子。", "因思贈時語，特用結終始。", "永願如履綦，雙行復雙止。", "自吾謫江郡，漂蕩三千里。", "爲感長情人，提攜同到此。", "今朝一惆悵，反覆看未已。", "人隻履猶雙，何曾得相似。", "可嗟復可惜，錦表繡爲裏。", "況經梅雨來，色黯花草死。"]'),
('842ff974-8346-4805-ad5b-ebec93d13f5f','南湖晚秋','白居易','唐','唐诗','tang','','[]','八月白露降，湖中水方老。',72,'全唐诗/poet.tang.22000.json','["八月白露降，湖中水方老。", "旦夕秋風多，衰荷半傾倒。", "手攀青楓樹，足蹋黃蘆草。", "慘澹老容顏，冷落秋懷抱。", "有兄在淮楚，有弟在蜀道。", "萬里何時來，煙波白浩浩。"]'),
('787e94dc-b15a-42be-b2e8-a2e0b970481c','郡廳有樹晚榮早凋人不識名因題其上','白居易','唐','唐诗','tang','','[]','潯陽郡廳後，有樹不知名。',120,'全唐诗/poet.tang.22000.json','["潯陽郡廳後，有樹不知名。", "秋先梧桐落，春後桃李榮。", "五月始萌動，八月已凋零。", "左右皆松桂，四時鬱青青。", "豈量雨露恩，霑濡不均平。", "榮枯各有分，天地本無情。", "顧我亦相類，早衰向晚成。", "形骸少多病，三十不豐盈。", "毛鬢早改變，四十白髭生。", "誰教兩蕭索，相對此江城。"]'),
('8b250a95-0bf8-4672-a0d8-378158b9cd91','感秋懷微之','白居易','唐','唐诗','tang','','[]','葉下湖又波，秋風此時至。',72,'全唐诗/poet.tang.22000.json','["葉下湖又波，秋風此時至。", "誰知濩落心，先納蕭條氣。", "推移感流歲，漂泊思同志。", "昔爲煙霄侶，今作泥塗吏。", "白鷗毛羽弱，青鳳文章異。", "各閉一籠中，歲晚同顦顇。"]'),
('adc7d652-54ba-4845-9d3c-ffe81ad2174f','因沐感髮寄朗上人二首 一','白居易','唐','唐诗','tang','','[]','年長身轉慵，百事無所欲。',72,'全唐诗/poet.tang.22000.json','["年長身轉慵，百事無所欲。", "乃至頭上髮，經年方一沐。", "沐稀髮苦落，一沐仍半禿。", "短鬢經霜蓬，老面辭春木。", "強年過猶近，衰相來何速。", "應是煩惱多，心焦血不足。"]'),
('cf647d2d-712a-48a0-903b-edb59b12bbb3','因沐感髮寄朗上人二首 二','白居易','唐','唐诗','tang','','[]','漸少不滿把，漸短不盈尺。',72,'全唐诗/poet.tang.22000.json','["漸少不滿把，漸短不盈尺。", "況茲短少中，日夜落復白。", "既無神仙術，何除老死籍。", "祗有解脫門，能度衰苦厄。", "掩鏡望東寺，降心謝禪客。", "衰白何足言，剃落猶不惜。"]'),
('278b7df6-83fe-49f6-8447-1790ec5da2c0','早蟬','白居易','唐','唐诗','tang','','[]','月出先照山，風生先動水。',60,'全唐诗/poet.tang.22000.json','["月出先照山，風生先動水。", "亦如早蟬聲，先入閑人耳。", "一聞愁意結，再聽鄉心起。", "渭上新蟬聲，先聽渾相似。", "衡門有誰聽，日暮槐花裏。"]'),
('377c55a5-da60-42c1-9b58-ab5617744186','苦熱喜涼','白居易','唐','唐诗','tang','','[]','經時苦炎暑，心體但煩倦。',96,'全唐诗/poet.tang.22000.json','["經時苦炎暑，心體但煩倦。", "白日一何長，清秋不可見。", "歲功成者去，天數極則變。", "潛知寒燠間，遷次如乘傳。", "火雲忽朝斂，金風俄夕扇。", "枕簟遂清涼，筋骸稍輕健。", "因思望月侶，好卜迎秋宴。", "竟夜無客來，引杯還自勸。"]'),
('3e96bfb7-5878-406d-ba70-f87ad0730c09','早秋晚望兼呈韋侍郎','白居易','唐','唐诗','tang','','[]','九派繞孤城，城高生遠思。',96,'全唐诗/poet.tang.22000.json','["九派繞孤城，城高生遠思。", "人煙半在船，野水多於地。", "穿霞日脚直，驅雁風頭利。", "去國來幾時，江上秋三至。", "夫君亦淪落，此地同飄寄。", "憫默向隅心，摧頹觸籠翅。", "且謀眼前計，莫問胸中事。", "潯陽酒甚濃，相勸時時醉。"]'),
('98672314-fd63-4678-bfab-8acbbb0e3a66','司馬宅','白居易','唐','唐诗','tang','','[]','雨徑綠蕪合，霜園紅葉多。',36,'全唐诗/poet.tang.22000.json','["雨徑綠蕪合，霜園紅葉多。", "蕭條司馬宅，門巷無人過。", "唯對大江水，秋風朝夕波。"]'),
('3b0e069d-fa3c-4934-9543-661d17d857a2','司馬廳獨宿','白居易','唐','唐诗','tang','','[]','荒涼滿庭草，偃亞侵檐竹。',48,'全唐诗/poet.tang.22000.json','["荒涼滿庭草，偃亞侵檐竹。", "府吏下廳簾，家僮開被襆。", "數聲城上漏，一點窗間燭。", "官曹冷似冰，誰肯來同宿。"]'),
('967dc2ba-b92a-47ea-9cd1-3b414e6b0c66','夢與李七庾三十三同訪元九','白居易','唐','唐诗','tang','','[]','夜夢歸長安，見我故親友。',144,'全唐诗/poet.tang.22000.json','["夜夢歸長安，見我故親友。", "損之在我左，順之在我右。", "云是二月天，春風出攜手。", "同過靖安里，下馬尋元九。", "元九正獨坐，見我笑開口。", "還指西院花，仍開北亭酒。", "如言各有故，似惜歡難久。", "神合俄頃間，神離欠伸後。", "覺來疑在側，求索無所有。", "殘燈影閃牆，斜月光穿牖。", "天明西北望，萬里君知否。", "老去無見期，踟躕搔白首。"]'),
('ce42dcdc-431b-4d07-86ea-9320bb18d917','秋槿','白居易','唐','唐诗','tang','','[]','風露颯已冷，天色亦黃昏。',96,'全唐诗/poet.tang.22000.json','["風露颯已冷，天色亦黃昏。", "中庭有槿花，榮落同一晨。", "秋開已寂莫，夕隕何紛紛。", "正憐少顏色，復歎不逡巡。", "感此因念彼，懷哉聊一陳。", "男兒老富貴，女子晚婚姻。", "頭白始得志，色衰方事人。", "後時不獲已，安得如青春。"]'),
('a88fdc72-c694-4ce8-8f1b-6f99aebff66e','荅元郎中楊員外喜烏見寄','白居易','唐','唐诗','tang','','[]','南宮鴛鴦地，何忽烏來止。',52,'全唐诗/poet.tang.22000.json','["南宮鴛鴦地，何忽烏來止。", "故人錦帳郎，聞烏笑相視。", "疑烏報消息，望我歸鄉里。", "我歸應待烏頭白，慙媿元郎誤歡喜。"]'),
('5f1a8923-5764-4b1e-a250-828e14bdc2ea','初入峽有感','白居易','唐','唐诗','tang','','[]','上有萬仞山，下有千丈水。',144,'全唐诗/poet.tang.22000.json','["上有萬仞山，下有千丈水。", "蒼蒼兩崖間，闊狹容一葦。", "瞿唐呀直瀉，灩澦屹中峙。", "未夜黑巖昏，無風白浪起。", "大石如刀劒，小石如牙齒。", "一步不可行，況千三百里。", "苒蒻竹篾𥮘，欹危檝師趾。", "一跌無完舟，吾生繫於此。", "常聞仗忠信，蠻貊可行矣。", "自古漂沈人，豈盡非君子。", "況吾時與命，蹇舛不足恃。", "常恐不才身，復作無名死。"]'),
('4ac91fcb-b4d4-4eb8-9000-35d652c92c74','過昭君村','白居易','唐','唐诗','tang','','[]','靈珠產無種，彩雲出無根。',156,'全唐诗/poet.tang.22000.json','["靈珠產無種，彩雲出無根。", "亦如彼姝子，生此遐陋村。", "至麗物難掩，遽選入君門。", "獨美衆所嫉，終棄出塞垣。", "唯此希代色，豈無一顧恩。", "事排勢須去，不得由至尊。", "白黑既可變，丹青何足論。", "竟埋代北骨，不返巴東魂。", "慘澹晚雲水，依稀舊鄉園。", "妍姿化已久，但有村名存。", "村中有遺老，指點爲我言。", "不敢往者戒，恐貽來者冤。", "至今村女面，燒灼成瘢痕。"]'),
('c4acc37b-e7f1-49ce-bed0-2ce8b02b45d9','自江州至忠州','白居易','唐','唐诗','tang','','[]','前在潯陽日，已歎賓朋寡。',72,'全唐诗/poet.tang.22000.json','["前在潯陽日，已歎賓朋寡。", "忽忽抱憂懷，出門無處寫。", "今來轉深僻，窮峽巔山下。", "五月斷行舟，灩堆正如馬。", "巴人類猨狖，矍鑠滿山野。", "敢望見交親，喜逢似人者。"]'),
('bfd6d686-38b5-4367-b370-4995aeae8574','初到忠州登東樓寄萬州楊八使君','白居易','唐','唐诗','tang','','[]','山束邑居窄，峽牽氣候偏。',144,'全唐诗/poet.tang.22000.json','["山束邑居窄，峽牽氣候偏。", "林巒少平地，霧雨多陰天。", "隱隱煮鹽火，漠漠燒畬煙。", "賴此東樓夕，風月時翛然。", "憑軒望所思，目斷心涓涓。", "背春有去雁，上水無來船。", "我懷巴東守，本是關西賢。", "平生已不淺，流落重相憐。", "水梗漂萬里，籠禽囚五年。", "新恩同雨露，遠郡鄰山川。", "書信雖往復，封疆徒接連。", "其如美人面，欲見杳無緣。"]'),
('38653c12-f754-4dc5-8845-4062ed54fdde','郡中','白居易','唐','唐诗','tang','','[]','鄉路音信斷，山城日月遲。',24,'全唐诗/poet.tang.22000.json','["鄉路音信斷，山城日月遲。", "欲知州近遠，階前摘荔枝。"]'),
('1d9fc7c8-493a-4dfd-a408-83cb06f4004a','西樓夜','白居易','唐','唐诗','tang','','[]','悄悄復悄悄，城隅隱林杪。',48,'全唐诗/poet.tang.22000.json','["悄悄復悄悄，城隅隱林杪。", "山郭燈火稀，峽天星漢少。", "年光東流水，生計南枝鳥。", "月沒江沈沈，西樓殊未曉。"]'),
('ea5503db-8f38-4f06-b439-0446024f3a05','東樓曉','白居易','唐','唐诗','tang','','[]','脈脈復脈脈，東樓無宿客。',48,'全唐诗/poet.tang.22000.json','["脈脈復脈脈，東樓無宿客。", "城闇雲霧多，峽深田地窄。", "宵燈尚留燄，晨禽初展翮。", "欲知山高低，不見東方白。"]'),
('b93ee049-d09e-4cd6-a07f-5bcddbe31df6','寄王質夫','白居易','唐','唐诗','tang','','[]','憶始識君時，愛君世緣薄。',192,'全唐诗/poet.tang.22000.json','["憶始識君時，愛君世緣薄。", "我亦吏王畿，不爲名利著。", "春尋仙遊洞，秋上雲居閣。", "樓觀水潺潺，龍潭花漠漠。", "吟詩石上坐，引酒泉邊酌。", "因話出處心，心期老巖壑。", "忽從風雨別，遂被簪纓縛。", "君作出山雲，我爲入籠鶴。", "籠深鶴殘顇，山遠雲飄泊。", "去處雖不同，同負平生約。", "今來各何在，老去隨所託。", "我守巴南城，君佐征西幕。", "年顏漸衰颯，生計仍蕭索。", "方含去國愁，且羨從軍樂。", "舊遊疑是夢，往事思如昨。", "相憶春又深，故山花正落。"]'),
('e675e6ae-cd0d-4c09-9d37-9f09ded3847f','南賓郡齋即事寄楊萬州','白居易','唐','唐诗','tang','','[]','山上巴子城，山下巴江水。',96,'全唐诗/poet.tang.22000.json','["山上巴子城，山下巴江水。", "中有窮獨人，強名爲刺史。", "時時竊自哂，刺史豈如是。", "倉粟餧家人，黃縑裹妻子。", "莓苔翳冠帶，霧雨霾樓雉。", "衙鼓暮復朝，郡齋臥還起。", "回頭望南浦，亦在煙波裏。", "而我復何嗟，夫君猶滯此。"]'),
('ffbb0e4f-6a8d-4cf5-8128-a943e00f1541','招蕭處士','白居易','唐','唐诗','tang','','[]','峽內豈無人，所逢非所思。',96,'全唐诗/poet.tang.22000.json','["峽內豈無人，所逢非所思。", "門前亦有客，相對不相知。", "仰望但雲樹，俯顧惟妻兒。", "寢食起居外，端然無所爲。", "東郊蕭處士，聊可與開眉。", "能飲滿杯酒，善吟長句詩。", "庭前吏散後，江畔路乾時。", "請君攜竹杖，一赴郡齋期。"]'),
('89024d78-3e78-4e9a-8736-704bfa63cb8d','庭槐','白居易','唐','唐诗','tang','','[]','南方饒竹樹，唯有青槐稀。',96,'全唐诗/poet.tang.22000.json','["南方饒竹樹，唯有青槐稀。", "十種七八死，縱活亦支離。", "何此郡庭下，一株獨華滋。", "蒙蒙碧煙葉，嫋嫋黃花枝。", "我家渭水上，此樹蔭前墀。", "忽向天涯見，憶在故園時。", "人生有情感，遇物牽所思。", "樹木猶復爾，況見舊親知。"]'),
('0f059da3-35a7-4735-ae84-9e238d86dfa5','送客回晚興','白居易','唐','唐诗','tang','','[]','城上雲霧開，沙頭風浪定。',48,'全唐诗/poet.tang.22000.json','["城上雲霧開，沙頭風浪定。", "參差亂山出，澹泞平江淨。", "行客舟已遠，居人酒初醒。", "嫋嫋秋竹梢，巴蟬聲似磬。"]'),
('aa1af4de-0505-4ca9-aa54-669cc7d1edbf','東樓竹','白居易','唐','唐诗','tang','','[]','瀟灑城東樓，繞樓多修竹。',72,'全唐诗/poet.tang.22000.json','["瀟灑城東樓，繞樓多修竹。", "森然一萬竿，白粉封青玉。", "卷簾睡初覺，欹枕看未足。", "影轉色入樓，牀席生浮綠。", "空城絕賓客，向夕彌幽獨。", "樓上夜不歸，此君留我宿。"]'),
('7799166e-7971-4e27-b9a9-653501393dc1','九日登巴臺','白居易','唐','唐诗','tang','','[]','黍香酒初熟，菊暖花未開。',72,'全唐诗/poet.tang.22000.json','["黍香酒初熟，菊暖花未開。", "閑聽竹枝曲，淺酌茱萸杯。", "去年重陽日，漂泊湓城隈。", "今歲重陽日，蕭條巴子臺。", "旅鬢尋已白，鄉書久不來。", "臨觴一搔首，座客亦裴回。"]'),
('1636cc5f-761d-4d17-b8ca-36434a9778ba','東城尋春','白居易','唐','唐诗','tang','','[]','老色日上面，歡情日去心。',72,'全唐诗/poet.tang.22000.json','["老色日上面，歡情日去心。", "今既不如昔，後當不如今。", "今猶未甚衰，每事力可任。", "花時仍愛出，酒後尚能吟。", "但恐如此興，亦隨日銷沈。", "東城春欲老，勉強一來尋。"]'),
('b1911556-b763-49e6-b2e2-54550d9c3e7d','江上送客','白居易','唐','唐诗','tang','','[]','江花已萎絕，江草已消歇。',48,'全唐诗/poet.tang.22000.json','["江花已萎絕，江草已消歇。", "遠客何處歸，孤舟今日發。", "杜鵑聲似哭，湘竹斑如血。", "共是多感人，仍爲此中別。"]'),
('30afe17d-a1cf-4c3a-97e2-e89c7084057a','桐花','白居易','唐','唐诗','tang','','[]','春令有常候，清明桐始發。',96,'全唐诗/poet.tang.22000.json','["春令有常候，清明桐始發。", "何此巴峽中，桐花開十月。", "豈伊物理變，信是土宜別。", "地氣反寒暄，天時倒生殺。", "草木堅強物，所稟固難奪。", "風候一參差，榮枯遂乖剌。", "況吾北人性，不耐南方熱。", "強羸壽夭間，安得依時節。"]'),
('c393ae93-e888-4686-b605-0c4ec7080caf','早祭風伯因懷李十一舍人','白居易','唐','唐诗','tang','','[]','遠郡雖褊陋，時祀奉朝經。',96,'全唐诗/poet.tang.22000.json','["遠郡雖褊陋，時祀奉朝經。", "夙興祭風伯，天氣曉冥冥。", "導騎與從吏，引我出東坰。", "水霧重如雨，山火高於星。", "忽憶早朝日，與君趨紫庭。", "步登龍尾道，却望終南青。", "一別身向老，所思心未寧。", "至今想在耳，玉音尚玲玲。"]'),
('9dd8bc7c-b4a2-4814-904d-8fed313d8fde','花下對酒二首 一','白居易','唐','唐诗','tang','','[]','藹藹江氣春，南賓閏正月。',96,'全唐诗/poet.tang.22000.json','["藹藹江氣春，南賓閏正月。", "梅櫻與桃杏，次第城上發。", "紅房爛簇火，素豔紛團雪。", "香惜委風飄，愁牽壓枝折。", "樓中老太守，頭上新白髮。", "冷澹病心情，暄和好時節。", "故園音信斷，遠郡親賓絕。", "欲問花前尊，依然爲誰設。"]'),
('e2bba66b-b9b2-43e8-9913-00304d41e448','花下對酒二首 二','白居易','唐','唐诗','tang','','[]','引手攀紅櫻，紅櫻落似霰。',96,'全唐诗/poet.tang.22000.json','["引手攀紅櫻，紅櫻落似霰。", "仰首看白日，白日走如箭。", "年芳與時景，頃刻猶衰變。", "況是血肉身，安能長強健。", "人心苦迷執，慕貴憂貧賤。", "愁色常在眉，歡容不上面。", "況吾頭半白，把鏡非不見。", "何必花下杯，更待他人勸。"]'),
('03aad1fa-f31a-47d8-8c54-3fdd6d17c099','不二門','白居易','唐','唐诗','tang','','[]','兩眼日將闇，四肢漸衰瘦。',144,'全唐诗/poet.tang.22000.json','["兩眼日將闇，四肢漸衰瘦。", "束帶賸昔圍，穿衣妨寬袖。", "流年似江水，奔注無昏晝。", "志氣與形骸，安得長依舊。", "亦曾登玉陛，舉措多紕繆。", "至今金闕籍，名姓獨遺漏。", "亦曾燒大藥，消息乖火候。", "至今殘丹砂，燒乾不成就。", "行藏事兩失，憂惱心交鬬。", "化作顦顇翁，拋身在荒陋。", "坐看老病逼，須得醫王救。", "唯有不二門，其間無夭壽。"]'),
('52e9618c-832e-439e-9578-00b67188cb18','我身','白居易','唐','唐诗','tang','','[]','我身何所似，似彼孤生蓬。',108,'全唐诗/poet.tang.22000.json','["我身何所似，似彼孤生蓬。", "秋霜翦根斷，浩浩隨長風。", "昔游秦雍間，今落巴蠻中。", "昔爲意氣郎，今作寂寥翁。", "外貌雖寂莫，中懷頗沖融。", "賦命有厚薄，委心任窮通。", "通當爲大鵬，舉翅摩蒼穹。", "窮則爲鷦鷯，一枝足自容。", "苟知此道者，身窮心不窮。"]'),
('9a216688-efb9-44e0-87e0-e2e2ca47464f','哭王質夫','白居易','唐','唐诗','tang','','[]','仙遊寺前別，別來十年餘。',156,'全唐诗/poet.tang.22000.json','["仙遊寺前別，別來十年餘。", "生別猶怏怏，死別復何如。", "客從梓潼來，道君死不虛。", "驚疑心未信，欲哭復踟躕。", "踟躕寢門側，聲發涕亦俱。", "衣上今日淚，篋中前月書。", "憐君古人風，重有君子儒。", "篇詠陶謝輩，風流嵇阮徒。", "出身既蹇屯，生世仍須臾。", "誠知天至高，安得不一呼。", "江南有毒蟒，江北有妖狐。", "皆享千年壽，多於王質夫。", "不知彼何德，不識此何辜。"]'),
('b29c04b7-c7d4-49cd-8f60-83863d255b3f','東坡種花二首 一','白居易','唐','唐诗','tang','','[]','持錢買花樹，城東坡上栽。',144,'全唐诗/poet.tang.22000.json','["持錢買花樹，城東坡上栽。", "但購有花者，不限桃杏梅。", "百果參雜種，千枝次第開。", "天時有早晚，地力無高低。", "紅者霞豔豔，白者雪皚皚。", "遊蠭逐不去，好鳥亦來栖。", "前有長流水，下有小平臺。", "時拂臺上石，一舉風前杯。", "花枝蔭我頭，花蘂落我懷。", "獨酌復獨詠，不覺月平西。", "巴俗不愛花，竟春無人來。", "唯此醉太守，盡日不能迴。"]'),
('dafd5719-d415-4bdf-89cb-0094d28ebe21','東坡種花二首 二','白居易','唐','唐诗','tang','','[]','東坡春向暮，樹木今何如。',132,'全唐诗/poet.tang.22000.json','["東坡春向暮，樹木今何如。", "漠漠花落盡，翳翳葉生初。", "每日領童僕，荷鉏仍決渠。", "剗土壅其本，引泉溉其枯。", "小樹低數尺，大樹長丈餘。", "封植來幾時，高下隨扶疎。", "養樹既如此，養民亦何殊。", "將欲茂枝葉，必先救根株。", "云何救根株，勸農均賦租。", "云何茂枝葉，省事寬刑書。", "移此爲郡政，庶幾甿俗蘇。"]'),
('3acbdf76-d67e-41a1-a9a9-553209ac83ec','登城東古臺','白居易','唐','唐诗','tang','','[]','迢迢東郊上，有土青崔嵬。',96,'全唐诗/poet.tang.22000.json','["迢迢東郊上，有土青崔嵬。", "不知何代物，疑是巴王臺。", "巴歌久無聲，巴宮沒黃埃。", "靡靡春草合，牛羊緣四隈。", "我來一登眺，目極心悠哉。", "始見江山勢，峰疊水環迴。", "憑高視聽曠，向遠胷襟開。", "唯有故園念，時時東北來。"]'),
('ee37b756-891c-4d1e-a842-527cb91a2c81','哭諸故人因寄元八','白居易','唐','唐诗','tang','','[]','昨日哭寢門，今日哭寢門。',120,'全唐诗/poet.tang.22000.json','["昨日哭寢門，今日哭寢門。", "借問所哭誰，無非故交親。", "偉卿既長往，質夫亦幽淪。", "屈指數年世，收涕自思身。", "彼皆少於我，先爲泉下人。", "我今頭半白，焉得身久存。", "好狂元郎中，相識二十春。", "昔見君生子，今聞君抱孫。", "存者盡老大，逝者已成塵。", "早晚升平宅，開眉一見君。"]'),
('63e25ab6-0447-4a83-8858-dc040bc51006','郡中春讌因贈諸客','白居易','唐','唐诗','tang','','[]','僕本儒家子，待詔金馬門。',192,'全唐诗/poet.tang.22000.json','["僕本儒家子，待詔金馬門。", "塵忝親近地，孤負聖明恩。", "一旦奉優詔，萬里牧遠人。", "可憐島夷帥，自稱爲使君。", "身騎牂牁馬，口食塗江鱗。", "闇澹緋衫故，斕斑白髮新。", "是時歲二月，玉曆布春分。", "頒條示皇澤，命宴及良辰。", "冉冉趨府吏，蚩蚩聚州民。", "有如蟄蟲鳥，亦應天地春。", "薰草席鋪坐，藤枝酒注樽。", "中庭無平地，高下隨所陳。", "蠻鼓聲坎坎，巴女舞蹲蹲。", "使君居上頭，掩口語衆賓。", "勿笑風俗陋，勿欺官府貧。", "蠭巢與蟻穴，隨分有君臣。"]'),
('67c4784b-57cb-4c97-bf7c-2322a40fa066','開元寺東池早春','白居易','唐','唐诗','tang','','[]','池水暖溫暾，水清波瀲灩。',72,'全唐诗/poet.tang.22000.json','["池水暖溫暾，水清波瀲灩。", "簇簇青泥中，新蒲葉如劒。", "梅房小白裹，柳彩輕黃染。", "順氣草熏熏，適情鷗汎汎。", "舊遊成夢寐，往事隨陽焱。", "芳物感幽懷，一動平生念。"]'),
('955c6d5b-fe80-4b54-b527-069a24df1abb','東溪種柳','白居易','唐','唐诗','tang','','[]','野性愛栽植，植柳水中坻。',132,'全唐诗/poet.tang.22000.json','["野性愛栽植，植柳水中坻。", "乘春持斧斫，裁截而樹之。", "長短既不一，高下隨所宜。", "倚岸埋大幹，臨流插小枝。", "松柏不可待，楩柟固難移。", "不如種此樹，此樹易榮滋。", "無根亦可活，成陰況非遲。", "三年未離郡，可以見依依。", "種罷水邊憩，仰頭閑自思。", "富貴本非望，功名須待時。", "不種東溪柳，端坐欲何爲。"]'),
('9184ab85-6805-4537-ac17-e21cea26fbfd','臥小齋','白居易','唐','唐诗','tang','','[]','朝起視事畢，晏坐飽食終。',48,'全唐诗/poet.tang.22000.json','["朝起視事畢，晏坐飽食終。", "散步長廊下，臥退小齋中。", "拙政自多暇，幽情誰與同。", "孰云二千石，心如田野翁。"]'),
('e63eecb5-9d61-481a-90e6-40f382ecfc0f','步東坡','白居易','唐','唐诗','tang','','[]','朝上東坡步，夕上東坡步。',96,'全唐诗/poet.tang.22000.json','["朝上東坡步，夕上東坡步。", "東坡何所愛，愛此新成樹。", "種植當歲初，滋榮及春暮。", "信意取次栽，無行亦無數。", "綠陰斜景轉，芳氣微風度。", "新葉鳥下來，萎花蝶飛去。", "閑攜斑竹杖，徐曳黃麻屨。", "欲識往來頻，青蕪成白路。"]'),
('16c5152f-1b45-480e-9c0c-0812dc42c4ce','徵秋稅畢題郡南亭','白居易','唐','唐诗','tang','','[]','高城直下視，蠢蠢見巴蠻。',84,'全唐诗/poet.tang.22000.json','["高城直下視，蠢蠢見巴蠻。", "安可施政教，尚不通語言。", "且喜賦斂畢，幸聞閭井安。", "豈伊循良化，賴此豐登年。", "案牘既簡少，池館亦清閑。", "秋雨檐果落，夕鐘林鳥還。", "南亭日瀟灑，偃臥恣疎頑。"]'),
('84f056c8-56dd-4b6c-9cc7-4ec78f9c7551','蚊蟆','白居易','唐','唐诗','tang','','[]','巴徼炎毒早，二月蚊蟆生。',72,'全唐诗/poet.tang.22000.json','["巴徼炎毒早，二月蚊蟆生。", "咂膚拂不去，繞耳薨薨聲。", "斯物頗微細，中人初甚輕。", "如有膚受譖，久則瘡痏成。", "痏成無奈何，所要防其萌。", "麼蟲何足道，潛喻儆人情。"]'),
('c2cf4ca2-c6f4-4c14-9684-68bfd570da45','登龍昌上寺望江南山懷錢舍人','白居易','唐','唐诗','tang','','[]','騎馬出西郭，悠悠欲何之。',72,'全唐诗/poet.tang.22000.json','["騎馬出西郭，悠悠欲何之。", "獨上高寺去，一與白雲期。", "虛檻晚瀟灑，前山碧參差。", "忽似青龍閤，同望玉峰時。", "因詠松雪句，永懷鸞鶴姿。", "六年不相見，況乃隔榮衰。"]'),
('e2ebce80-29bb-493b-b99f-ffe64a25d6a4','郊下','白居易','唐','唐诗','tang','','[]','西日照高樹，樹頭子規鳴。',48,'全唐诗/poet.tang.22000.json','["西日照高樹，樹頭子規鳴。", "東風吹野水，水畔江蘺生。", "盡日看山立，有時尋澗行。", "兀兀長如此，何許似專城。"]'),
('bc717baa-dade-4fc8-8fc5-eaae1fb90a07','遣懷','白居易','唐','唐诗','tang','','[]','樂往必悲生，泰來由否極。',96,'全唐诗/poet.tang.22000.json','["樂往必悲生，泰來由否極。", "誰言此數然，吾道何終塞。", "嘗求詹尹卜，拂龜竟默默。", "亦曾仰問天，天但蒼蒼色。", "自茲唯委命，名利心雙息。", "近日轉安閑，鄉園亦休憶。", "回看世間苦，苦在求不得。", "我今無所求，庶離憂悲域。"]'),
('f5c0311c-cbfc-46e7-bb25-df5607eb8f52','歲晚','白居易','唐','唐诗','tang','','[]','霜降水返壑，風落木歸山。',84,'全唐诗/poet.tang.22000.json','["霜降水返壑，風落木歸山。", "冉冉歲將宴，物皆復本源。", "何此南遷客，五年獨未還。", "命屯分已定，日久心彌安。", "亦嘗心與口，靜念私自言。", "去國固非樂，歸鄉未必歡。", "何須自生苦，舍易求其難。"]'),
('4e766207-5407-4502-b41f-064e72ec8a9a','負冬日','白居易','唐','唐诗','tang','','[]','杲杲冬日出，照我屋南隅。',60,'全唐诗/poet.tang.22000.json','["杲杲冬日出，照我屋南隅。", "負暄閉目坐，和氣生肌膚。", "初似飲醇醪，又如蟄者蘇。", "外融百骸暢，中適一念無。", "曠然忘所在，心與虛空俱。"]'),
('4e6a3dfe-dc72-4904-9888-a3797fdc2872','委順','白居易','唐','唐诗','tang','','[]','山城雖荒蕪，竹樹有嘉色。',72,'全唐诗/poet.tang.22000.json','["山城雖荒蕪，竹樹有嘉色。", "郡俸誠不多，亦足充衣食。", "外累由心起，心寧累自息。", "尚欲忘家鄉，誰能算官職。", "宜懷齊遠近，委順隨南北。", "歸去誠可憐，天涯住亦得。"]'),
('66bded42-156a-4f06-9d76-c3aed2807748','宿溪翁','白居易','唐','唐诗','tang','','[]','衆心愛金玉，衆口貪酒肉。',96,'全唐诗/poet.tang.22000.json','["衆心愛金玉，衆口貪酒肉。", "何如此溪翁，飲瓢亦自足。", "溪南刈薪草，溪北修牆屋。", "歲種一頃田，春驅兩黃犢。", "於中甚安適，此外無營欲。", "溪畔偶相逢，菴中遂同宿。", "醉翁向朝市，問我何官祿。", "虛言笑殺翁，郎官應列宿。"]'),
('8bcabd4c-e483-4d43-858d-9b2affc9d1d4','重過壽泉憶與楊九別時因題店壁','白居易','唐','唐诗','tang','','[]','商州南十里，有水名壽泉。',84,'全唐诗/poet.tang.22000.json','["商州南十里，有水名壽泉。", "湧出石崖下，流經山店前。", "憶昔相送日，我去君言還。", "寒波與老淚，此地共潺湲。", "一去歷萬里，再來經六年。", "形容已變改，處所猶依然。", "他日君過此，慇懃吟此篇。"]'),
('f937828a-ee5b-4a42-9717-dee2529ab0b0','西掖早秋直夜書意','白居易','唐','唐诗','tang','','[]','涼風起禁掖，新月生宮沼。',108,'全唐诗/poet.tang.22000.json','["涼風起禁掖，新月生宮沼。", "夜半秋闇來，萬年枝嫋嫋。", "炎涼遞時節，鐘鼓交昏曉。", "遇聖惜年衰，報恩愁力小。", "素餐無補益，朱綬虛纏繞。", "冠蓋栖野雲，稻粱養山鳥。", "量能私自省，所得已非少。", "五品不爲賤，五十不爲夭。", "若無知足心，貪求何日了。"]'),
('7fa9056a-e756-4b11-a51d-fddcbb46df15','庭松','白居易','唐','唐诗','tang','','[]','堂下何所有，十松當我階。',192,'全唐诗/poet.tang.22000.json','["堂下何所有，十松當我階。", "亂立無行次，高下亦不齊。", "高者三丈長，下者十尺低。", "有如野生物，不知何人栽。", "接以青瓦屋，承之白沙臺。", "朝昏有風月，燥濕無塵泥。", "疎韻秋槭槭，涼陰夏淒淒。", "春深微雨夕，滿葉珠蓑蓑。", "歲暮大雪天，壓枝玉皚皚。", "四時各有趣，萬木非其儕。", "去年買此宅，多爲人所咍。", "一家二十口，移轉就松來。", "移來有何得，但得煩襟開。", "即此是益友，豈必交賢才。", "顧我猶俗士，冠帶走塵埃。", "未稱爲松主，時時一媿懷。"]'),
('969edf06-789e-4f14-a899-d55c61fcc946','竹窗','白居易','唐','唐诗','tang','','[]','常愛輞川寺，竹窗東北廊。',168,'全唐诗/poet.tang.22000.json','["常愛輞川寺，竹窗東北廊。", "一別十餘載，見竹未曾忘。", "今春二月初，卜居在新昌。", "未暇作廐庫，且先營一堂。", "開窗不糊紙，種竹不依行。", "意取北檐下，窗與竹相當。", "繞屋聲淅淅，逼人色蒼蒼。", "煙通杳藹氣，月透玲瓏光。", "是時三伏天，天氣熱如湯。", "獨此竹窗下，朝迴解衣裳。", "輕紗一幅巾，小簟六尺牀。", "無客盡日靜，有風終夜涼。", "乃知前古人，言事頗諳詳。", "清風北窗臥，可以傲羲皇。"]'),
('31debc88-7cae-4121-80a0-46a24e47b296','同韓侍郎遊鄭家池吟詩小飲','白居易','唐','唐诗','tang','','[]','野艇容三人，晚池流浼浼。',96,'全唐诗/poet.tang.22000.json','["野艇容三人，晚池流浼浼。", "悠然依櫂坐，水思如江海。", "宿雨洗沙塵，晴風蕩煙靄。", "殘陽上竹樹，枝葉生光彩。", "我本偶然來，景物如相待。", "白鷗驚不起，綠芡行堪采。", "齒髮雖已衰，性靈未云改。", "逢詩遇杯酒，尚有心情在。"]'),
('63d05382-1fc9-4d2c-9d36-c30856dd8b2b','晚歸有感','白居易','唐','唐诗','tang','','[]','朝弔李家孤，暮問崔家疾。',72,'全唐诗/poet.tang.22000.json','["朝弔李家孤，暮問崔家疾。", "回馬獨歸來，低眉心鬱鬱。", "平生所善者，多不過六七。", "如何十年間，零落三無一。", "劉曾夢中見，元向花前失。", "漸老與誰遊，春城好風日。"]'),
('cb9cd0a9-99a6-4044-8bbd-ff24ef3317e6','曲江感秋二首 一','白居易','唐','唐诗','tang','','["\u5e90\u5c71"]','元和二年秋，我年三十七。',120,'全唐诗/poet.tang.22000.json','["元和二年秋，我年三十七。", "長慶二年秋，我年五十一。", "中間十四年，六年居譴黜。", "窮通與榮悴，委運隨外物。", "遂師廬山遠，重弔湘江屈。", "夜聽竹枝愁，秋看灩堆沒。", "近辭巴郡印，又秉綸闈筆。", "晚遇何足言，白髮映朱紱。", "銷沈昔意氣，改換舊容質。", "獨有曲江秋，風煙如往日。"]'),
('7769baae-b823-4ec1-ba57-614726034320','曲江感秋二首 二','白居易','唐','唐诗','tang','','[]','疎蕪南岸草，蕭颯西風樹。',120,'全唐诗/poet.tang.22000.json','["疎蕪南岸草，蕭颯西風樹。", "秋到未幾時，蟬聲又無數。", "莎平綠茸合，蓮落青房露。", "今日臨望時，往年感秋處。", "池中水依舊，城上山如故。", "獨我鬢間毛，昔黑今垂素。", "榮名與壯齒，相避如朝暮。", "時命始欲來，年顏已先去。", "當春不歡樂，臨老徒驚誤。", "故作詠懷詩，題於曲江路。"]'),
('a1d2cdbd-5919-40f4-b357-105ea49ccbf4','玩松竹二首 一','白居易','唐','唐诗','tang','','[]','龍蛇隱大澤，麋鹿遊豐草。',60,'全唐诗/poet.tang.22000.json','["龍蛇隱大澤，麋鹿遊豐草。", "栖鳳安於梧，潛魚樂於藻。", "吾亦愛吾廬，廬中樂吾道。", "前松後修竹，偃臥可終老。", "各附其所安，不知他物好。"]'),
('12f11d46-6c33-4697-8d64-edb6822ed456','玩松竹二首 二','白居易','唐','唐诗','tang','','[]','坐愛前檐前，臥愛北窗北。',60,'全唐诗/poet.tang.22000.json','["坐愛前檐前，臥愛北窗北。", "窗竹多好風，檐松有嘉色。", "幽懷一以合，俗念隨緣息。", "在爾雖無情，於予即有得。", "乃知性相近，不必動與植。"]'),
('95cc8031-c40f-42f2-be9b-680a26c048fc','衰病無趣因吟所懷','白居易','唐','唐诗','tang','','[]','朝餐多不飽，夜臥常少睡。',108,'全唐诗/poet.tang.22000.json','["朝餐多不飽，夜臥常少睡。", "自覺寢食間，多無少年味。", "平生好詩酒，今亦將舍棄。", "酒唯下藥飲，無復曾歡醉。", "詩多聽人吟，自不題一字。", "病姿與衰相，日夜相繼至。", "況當尚少朝，彌慙居近侍。", "終當求一郡，聚少漁樵費。", "合口便歸山，不問人間事。"]'),
('78cc6d2f-786b-4545-93b5-5704dde8a0ef','逍遙詠','白居易','唐','唐诗','tang','','[]','亦莫戀此身，亦莫厭此身。',48,'全唐诗/poet.tang.22000.json','["亦莫戀此身，亦莫厭此身。", "此身何足戀，萬劫煩惱根。", "此身何足厭，一聚虛空塵。", "無戀亦無厭，始是逍遙人。"]'),
('0e99d354-961e-438b-b52f-5b07d963c253','短歌行','白居易','唐','唐诗','tang','','[]','曈曈太陽如火色，上行千里下一刻。',128,'全唐诗/poet.tang.22000.json','["曈曈太陽如火色，上行千里下一刻。", "出爲白晝入爲夜，圓轉如珠住不得。", "住不得，可奈何，爲君舉酒歌短歌。", "歌聲苦，詞亦苦，四座少年君聽取。", "今夕未竟明夕催，秋風纔往春風回。", "人無根蔕時不駐，朱顏白日相隳頹。", "勸君且強笑一面，勸君且強飲一杯。", "人生不得長歡樂，年少須臾老到來。"]'),
('a4232ae1-1468-44a2-88c1-ba10c77627ce','生離別','白居易','唐','唐诗','tang','','["\u9ec4\u6cb3"]','食檗不易食梅難，檗能苦兮梅能酸。',128,'全唐诗/poet.tang.22000.json','["食檗不易食梅難，檗能苦兮梅能酸。", "未如生別之爲難，苦在心兮酸在肝。", "晨雞再鳴殘月沒，征馬連嘶行人出。", "回看骨肉哭一聲，梅酸檗苦甘如蜜。", "黃河水白黃雲秋，行人河邊相對愁。", "天寒野曠何處宿？棠棃葉戰風颼颼。", "生離別，生離別，憂從中來無斷絕。", "憂極心勞血氣衰，未年三十生白髮。"]'),
('e5767690-7d09-4cbc-8b7d-6b28e4dcc1bc','浩歌行','白居易','唐','唐诗','tang','','[]','天長地久無終畢，昨夜今朝又明日。',176,'全唐诗/poet.tang.22000.json','["天長地久無終畢，昨夜今朝又明日。", "鬢髮蒼浪牙齒疎，不覺身年四十七。", "前去五十有幾年，把鏡照面心茫然。", "既無長繩繫白日，又無大藥駐朱顏。", "朱顏日漸不如故，青史功名在何處？", "欲留年少待富貴，富貴不來年少去。", "去復去兮如長河，東流赴海無迴波。", "賢愚貴賤同歸盡，北邙冢墓高嵯峨。", "古來如此非獨我，未死有酒且高歌。", "顏回短命伯夷餓，我今所得亦已多。", "功名富貴須待命，命若不來知奈何。"]'),
('3e971330-6463-4711-83aa-1d0da96589e1','王夫子','白居易','唐','唐诗','tang','','[]','王夫子，送君爲一尉，東南三千五百里。',168,'全唐诗/poet.tang.22000.json','["王夫子，送君爲一尉，東南三千五百里。", "道途雖遠位雖卑，月俸猶堪活妻子。", "男兒口讀古人書，束帶斂手來從事。", "近將徇祿給一家，遠則行道佐時理。", "行道佐時須待命，委身下位無爲恥。", "命苟未來且求食，官無卑高及遠邇。", "男兒上既未能濟天下，下又不至飢寒死。", "吾觀九品至一品，其間氣味都相似。", "紫綬朱紱青布衫，顏色不同而已矣。", "王夫子，別有一事欲勸君，遇酒逢春且歡喜。"]'),
('0129589a-6416-4fb0-960a-48e58ae4f8b4','江南遇天寶樂叟','白居易','唐','唐诗','tang','','[]','白頭病叟泣且言，祿山未亂入棃園。',256,'全唐诗/poet.tang.22000.json','["白頭病叟泣且言，祿山未亂入棃園。", "能彈琵琶和法曲，多在華清隨至尊。", "是時天下太平久，年年十月坐朝元。", "千官起居環珮合，萬國會同車馬奔。", "金鈿照耀石甕寺，蘭麝熏煮溫湯源。", "貴妃宛轉侍君側，體弱不勝珠翠繁。", "冬雪飄颻錦袍暖，春風蕩漾霓裳飜。", "歡娛未足燕寇至，弓勁馬肥胡語喧。", "豳土人遷避夷狄，鼎湖龍去哭軒轅。", "從此漂淪落南土，萬人死盡一身存。", "秋風江上浪無限，暮雨舟中酒一尊。", "涸魚久失風波勢，枯草曾霑雨露恩。", "我自秦來君莫問，驪山渭水如荒村。", "新豐樹老籠明月，長生殿闇鎖春雲。", "紅葉紛紛蓋欹瓦，綠苔重重封壞垣。", "唯有中官作宮使，每年寒食一開門。"]'),
('4ec1aa75-831a-46ff-873f-98c40ce01e46','送張山人歸嵩陽','白居易','唐','唐诗','tang','','[]','黃昏慘慘天微雪，修行坊西鼓聲絕。',152,'全唐诗/poet.tang.22000.json','["黃昏慘慘天微雪，修行坊西鼓聲絕。", "張生馬瘦衣且單，夜扣柴門與我別。", "媿君冒寒來別我，爲君酤酒張燈火。", "酒酣火煖與君言，何事入關又出關。", "荅云前年偶下山，四十餘月客長安。", "長安古來名利地，空手無金行路難。", "朝遊九城陌，肥馬輕車欺殺客。", "暮宿五侯門，殘茶冷酒愁殺人。", "春明門，門前便是嵩山路。", "幸有雲泉容此身，明日辭君且歸去。"]'),
('1d498e59-1ff8-4f16-8e5f-a33b9bcb6046','醉後走筆酬劉五主簿長句之贈兼簡張大賈二十四先輩昆季','白居易','唐','唐诗','tang','','[]','劉兄文高行孤立，十五年前名翕習。',384,'全唐诗/poet.tang.22000.json','["劉兄文高行孤立，十五年前名翕習。", "是時相遇在符離，我年二十君三十。", "得意忘年心迹親，寓居同縣日知聞。", "衡門寂莫朝尋我，古寺蕭條暮訪君。", "朝來暮去多攜手，窮巷貧居何所有。", "秋燈夜寫聯句詩，春雪朝傾煖寒酒。", "陴湖綠愛白鷗飛，濉水清憐紅鯉肥。", "偶語閑攀芳樹立，相扶醉蹋落花歸。", "張賈弟兄同里巷，乘閑數數來相訪。", "雨天連宿草堂中，月夜徐行石橋上。", "我年漸長忽自驚，鏡中冉冉髭鬚生。", "心畏後時同勵志，身牽前事各求名。", "問我栖栖何所適，鄉人薦爲鹿鳴客。", "二千里別謝交遊，三十韻詩慰行役。", "出門可憐唯一身，敝裘瘦馬入咸秦。", "鼕鼕街鼓紅塵闇，晚到長安無主人。", "二賈二張與余弟，軀車邐迤來相繼。", "操詞握賦爲干戈，鋒銳森然勝氣多。", "齊入文場同苦戰，五人十載九登科。", "二張得雋名居甲，美退爭雄重告捷。", "棠棣輝榮竝桂枝，芝蘭芳馥和荆葉。", "唯有沅犀屈未伸，握中自謂駭雞珍。", "三年不鳴鳴必大，豈獨駭雞當駭人。", "元和運啓千年聖，同遇明時余最幸。"]'),
('c6d4ea3d-eae6-4187-86b0-573f353a859e','和錢員外荅盧員外早春獨遊曲江見寄長句','白居易','唐','唐诗','tang','','[]','春來有色闇融融，先到詩情酒思中。',96,'全唐诗/poet.tang.22000.json','["春來有色闇融融，先到詩情酒思中。", "柳岸霏微裛塵雨，杏園澹蕩開花風。", "聞君獨遊心鬱鬱，薄晚新晴騎馬出。", "醉思詩侶有同年，春歎翰林無暇日。", "雲夫首倡寒玉音，蔚章繼和春搜吟。", "此時我亦閉門坐，一日風光三處心。"]'),
('23f6be13-844f-4db1-bf1d-2011ff467bf1','東墟晚歇','白居易','唐','唐诗','tang','','[]','涼風冷露蕭索天，黃蒿紫菊荒涼田。',96,'全唐诗/poet.tang.22000.json','["涼風冷露蕭索天，黃蒿紫菊荒涼田。", "繞冢秋花少顏色，細蟲小蝶飛飜飜。", "中有騰騰獨行者，手拄漁竿不騎馬。", "晚從南澗釣魚回，歇此墟中白楊下。", "褐衣半故白髮新，人逢知我是何人。", "誰言渭浦棲遲客，曾作甘泉侍從臣。"]'),
('125c752d-23ff-4ce8-a975-e476c244e3ea','客中月','白居易','唐','唐诗','tang','','[]','客從江南來，來時月上弦。',72,'全唐诗/poet.tang.22000.json','["客從江南來，來時月上弦。", "悠悠行旅中，三見清光圓。", "曉隨殘月行，夕與新月宿。", "誰謂月無情，千里遠相逐。", "朝發渭水橋，暮入長安陌。", "不知今夜月，又作誰家客。"]'),
('a16e1400-1726-48b2-8e22-ba8bb0e9e275','輓歌詞','白居易','唐','唐诗','tang','','[]','丹旐何飛揚，素驂亦悲鳴。',100,'全唐诗/poet.tang.22000.json','["丹旐何飛揚，素驂亦悲鳴。", "晨光照閭巷，輀車儼欲行。", "蕭條九月天，哀輓出重城。", "借問送者誰，妻子與弟兄。", "蒼蒼上古原，峨峨開新塋。", "含酸一慟哭，異口同哀聲。", "舊隴轉蕪絕，新墳日羅列。", "春風草綠北邙山，此地年年生死別。"]'),
('3f7f7c78-d246-4b88-a1a0-a688e373ecda','長相思','白居易','唐','唐诗','tang','','[]','九月西風興，月冷露華凝。',132,'全唐诗/poet.tang.22000.json','["九月西風興，月冷露華凝。", "思君秋夜長，一夜魂九升。", "二月東風來，草拆花心開。", "思君春日遲，一日腸九迴。", "妾住洛橋北，君住洛橋南。", "十五即相識，今年二十三。", "有如女蘿草，生在松之側。", "蔓短枝苦高，縈迴上不得。", "人言人有願，願至天必成。", "願作遠方獸，步步比肩行。", "願作深山木，枝枝連理生。"]'),
('94f2ece1-4d41-41c5-81a5-3f6c91f86cc2','山鷓鴣','白居易','唐','唐诗','tang','','[]','山鷓鴣，朝朝暮暮啼復啼，啼時露白風淒淒。',128,'全唐诗/poet.tang.22000.json','["山鷓鴣，朝朝暮暮啼復啼，啼時露白風淒淒。", "黃茅岡頭秋日晚，苦竹嶺下寒月低。", "畬田有粟何不啄，石楠有枝何不棲？", "迢迢不緩復不急，樓上舟中聲闇入。", "夢鄉遷客展轉臥，抱兒寡婦彷徨立。", "山鷓鴣，爾本此鄉鳥。", "生不辭巢不別羣，何苦聲聲啼到曉。", "啼到曉，唯能愁北人，南人慣聞如不聞。"]'),
('45ca0762-7bc6-4a29-94a9-edd1ca287568','放旅雁','白居易','唐','唐诗','tang','','[]','九江十年冬大雪，江水生冰樹枝折。',160,'全唐诗/poet.tang.22000.json','["九江十年冬大雪，江水生冰樹枝折。", "百鳥無食東西飛，中有旅鴈聲最飢。", "雪中啄草冰上宿，翅冷騰空飛動遲。", "江童持網捕將去，手攜入市生賣之。", "我本北人今譴謫，人鳥雖殊同是客。", "見此客鳥傷客人，贖汝放汝飛入雲。", "鴈鴈汝飛向何處？第一莫飛西北去。", "淮西有賊討未平，百萬甲兵久屯聚。", "官軍賊軍相守老，食盡兵窮將及汝。", "健兒飢餓射汝喫，拔汝翅翎爲箭羽。"]'),
('634f34d5-c116-4417-b2f3-4ec76f027659','送春歸','白居易','唐','唐诗','tang','','[]','送春歸，三月盡日日暮時。',124,'全唐诗/poet.tang.22000.json','["送春歸，三月盡日日暮時。", "去年杏園花飛御溝綠，何處送春曲江曲。", "今年杜鵑花落子規啼，送春何處西江西。", "帝城送春猶怏怏，天涯送春能不加惆悵。", "莫惆悵，送春人。", "冗員無替五年罷，應須準擬再送潯陽春。", "五年炎涼凡十變，又知此身健不健。", "好去今年江上春，明年未死還相見。"]'),
('0d8a000b-b06d-4320-bd30-e9aa8e9a14b0','山石榴寄元九','白居易','唐','唐诗','tang','','[]','山石榴，一名山躑躅，一名杜鵑花。',264,'全唐诗/poet.tang.22000.json','["山石榴，一名山躑躅，一名杜鵑花。", "杜鵑啼時花撲撲，九江三月杜鵑來，一聲催得一枝開。", "江城上佐閑無事，山下斸得廳前栽。", "爛熳一闌十八樹，根株有數花無數。", "千房萬葉一時新，嫩紫殷紅鮮麴塵。", "淚痕裛損燕支臉，剪刀裁破紅綃巾。", "謫仙初墮愁在世，姹女新嫁嬌泥春。", "日射血珠將滴地，風飜火燄欲燒人。", "閑折兩枝持在手，細看不似人間有。", "花中此物似西施，芙蓉芍藥皆嫫母。", "奇芳絕豔別者誰，通州遷客元拾遺。", "拾遺初貶江陵去，去時正值青春暮。", "商山秦嶺愁殺君，山石榴花紅夾路。", "題詩報我何所云，苦云色似石榴帬。", "當時叢畔唯思我，今日闌前只憶君。", "憶君不見坐銷落，日西風起紅紛紛。"]'),
('4f29124d-9d42-45c3-affe-8d2699e155fe','畫竹歌','白居易','唐','唐诗','tang','','["\u548f\u7269\u8bd7", "\u7af9\u5b50", "\u548f\u7269", "\u8d5e\u7f8e"]','植物之中竹難寫，故今雖畫無似者。',212,'全唐诗/poet.tang.22000.json','["植物之中竹難寫，故今雖畫無似者。", "蕭郎下筆獨逼真，丹青以來唯一人。", "人畫竹身肥擁腫，蕭畫莖瘦節節竦。", "人畫竹梢死羸垂，蕭畫枝活葉葉動。", "不根而生從意生，不筍而成由筆成。", "野塘水邊碕岸側，森森兩叢十五莖。", "嬋娟不失筠粉態，蕭颯盡得風煙情。", "舉頭忽看不似畫，低耳靜聽疑有聲。", "西叢七莖勁而健，省向天竺寺前石上見。", "東叢八莖疎且寒，憶曾湘妃廟裏雨中看。", "幽姿遠思少人別，與君相顧空長歎。", "蕭郎蕭郎老可惜，手顫眼昏頭雪色。", "自言便是絕筆時，從今此竹尤難得。"]'),
('d496aa33-4887-4b07-8076-cb6c242d4ba7','真娘墓','白居易','唐','唐诗','tang','','[]','真娘墓，虎丘道。',72,'全唐诗/poet.tang.22000.json','["真娘墓，虎丘道。", "不識真娘鏡中面，唯見真娘墓頭草。", "霜摧桃李風折蓮，真娘死時猶少年。", "脂膚荑手不牢固，世間尤物難留連。", "難留連，易銷歇，塞北花，江南雪。"]'),
('0a0f9231-d88c-4f81-b941-83b67a736194','長恨歌','白居易','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u5ce8\u7709\u5c71", "\u53d9\u4e8b", "\u5199\u4eba", "\u7231\u60c5", "\u4e03\u8a00\u53e4\u8bd7"]','漢皇重色思傾國，御宇多年求不得。',384,'全唐诗/poet.tang.22000.json','["漢皇重色思傾國，御宇多年求不得。", "楊家有女初長成，養在深閨人未識。", "天生麗質難自棄，一朝選在君王側。", "回眸一笑百媚生，六宮粉黛無顏色。", "春寒賜浴華清池，溫泉水滑洗凝脂。", "侍兒扶起嬌無力，始是新承恩澤時。", "雲鬢花顏金步搖，芙蓉帳暖度春宵。", "春宵苦短日高起，從此君王不早朝。", "承歡侍宴無閑暇，春從春遊夜專夜。", "後宮佳麗三千人，三千寵愛在一身。", "金屋妝成嬌侍夜，玉樓宴罷醉和春。", "姊妹弟兄皆列土，可憐光彩生門戶。", "遂令天下父母心，不重生男重生女。", "驪宮高處入青雲，仙樂風飄處處聞。", "緩歌慢舞凝絲竹，盡日君王看不足。", "漁陽鞞鼓動地來，驚破霓裳羽衣曲。", "九重城闕煙塵生，千乘萬騎西南行。", "翠華搖搖行復止，西出都門百餘里。", "六軍不發無奈何，宛轉蛾眉馬前死。", "花鈿委地無人收，翠翹金雀玉搔頭。", "君王掩面救不得，回看血淚相和流。", "黃埃散漫風蕭索，雲棧縈紆登劒閣。", "峨嵋山下少人行，旌旗無光日色薄。", "蜀江水碧蜀山青，聖主朝朝暮暮情。"]'),
('f24ba5d0-86c3-4632-94c7-8334c17cb325','婦人苦','白居易','唐','唐诗','tang','','[]','蟬鬢加意梳，蛾眉用心埽。',192,'全唐诗/poet.tang.22000.json','["蟬鬢加意梳，蛾眉用心埽。", "幾度曉妝成，君看不言好。", "妾身重同穴，君意輕偕老。", "惆悵去年來，心知未能道。", "今朝一開口，語少意何深。", "願引他時事，移君此日心。", "人言夫婦親，義合如一身。", "及至死生際，何曾苦樂均。", "婦人一喪夫，終身守孤孑。", "有如林中竹，忽被風吹折。", "一折不重生，枯死猶抱節。", "男兒若喪婦，能不暫傷情。", "應似門前柳，逢春易發榮。", "風吹一枝折，還有一枝生。", "爲君委曲言，願君再三聽。", "須知婦人苦，從此莫相輕。"]'),
('afa751bd-268f-4f53-b8cd-be33b62f9fee','長安道','白居易','唐','唐诗','tang','','[]','花枝缺處青樓開，豔歌一曲酒一杯。',51,'全唐诗/poet.tang.22000.json','["花枝缺處青樓開，豔歌一曲酒一杯。", "美人勸我急行樂，自古朱顏不再來。", "君不見外州客，長安道，一迴來，一迴老。"]'),
('2302b508-8d5f-4e43-aaf7-2463d0717e0a','潛別離','白居易','唐','唐诗','tang','','["\u7231\u60c5"]','不得哭，潛別離，不得語，闇相思。',64,'全唐诗/poet.tang.22000.json','["不得哭，潛別離，不得語，闇相思。", "兩心之外無人知，深籠夜鏁獨棲鳥。", "利劒春斷連理枝，河水雖濁有清日。", "烏頭雖黑有白時，唯有潛離與暗別。"]'),
('7a4aebc8-e23e-42b7-8ccb-8a40366adcee','隔浦蓮','白居易','唐','唐诗','tang','','[]','隔浦愛紅蓮，昨日看猶在。',40,'全唐诗/poet.tang.22000.json','["隔浦愛紅蓮，昨日看猶在。", "夜來風吹落，只得一回采。", "花開雖有明年期，復愁明年還暫時。"]'),
('31f3bef9-f227-4ea2-9f4e-8ffb59c8a171','寒食野望吟','白居易','唐','唐诗','tang','','["\u6e05\u660e", "\u601d\u4e61", "\u5bd2\u98df\u8282"]','丘墟郭門外，寒食誰家哭。',60,'全唐诗/poet.tang.22000.json','["丘墟郭門外，寒食誰家哭。", "風吹曠野紙錢飛，古墓纍纍春草綠。", "棠棃花映白楊樹，盡是死生離別處。", "冥寞重泉哭不聞，蕭蕭暮雨人歸去。"]'),
('0fb0189c-8ff3-4106-af94-f6d26d528a1d','琵琶引','白居易','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u4e03\u8a00\u53e4\u8bd7", "\u9ad8\u4e2d\u53e4\u8bd7", "\u5199\u4eba", "\u4e50\u5e9c", "\u4e09\u5e74\u7ea7\u4e0b\u518c"]','潯陽江頭夜送客，楓葉荻花秋索索。',384,'全唐诗/poet.tang.22000.json','["潯陽江頭夜送客，楓葉荻花秋索索。", "主人下馬客在船，舉酒欲飲無管弦。", "醉不成歡慘將別，別時茫茫江浸月。", "忽聞水上琵琶聲，主人忘歸客不發。", "尋聲暗問彈者誰，琵琶聲停欲語遲。", "移船相近邀相見，添酒迴燈重開宴。", "千呼萬喚始出來，猶抱琵琶半遮面。", "轉軸撥弦三兩聲，未成曲調先有情。", "弦弦掩抑聲聲思，似訴平生不得意。", "低眉信手續續彈，說盡心中無限事。", "輕攏慢撚抹復挑，初爲霓裳後六幺。", "大弦嘈嘈如急雨，小弦切切如私語。", "嘈嘈切切錯雜彈，大珠小珠落玉盤。", "間關鶯語花底滑，幽咽泉流水下灘。", "水泉冷澀弦疑絕，疑絕不通聲暫歇。", "別有幽愁暗恨生，此時無聲勝有聲。", "銀缾乍破水漿迸，鐵騎突出刀槍鳴。", "曲終收撥當心畫，四弦一聲如裂帛。", "東舟西舫悄無言，唯見江心秋月白。", "沈吟放撥插弦中，整頓衣裳起斂容。", "自言本是京城女，家在蝦蟇陵下住。", "十三學得琵琶成，名蜀教坊第一部。", "曲罷曾教善才伏，妝成每被秋娘妬。", "五陵年少爭纏頭，一曲紅綃不知數。"]'),
('021b47d2-ef8a-42ca-a7c6-8a8bbb39a98a','簡簡吟','白居易','唐','唐诗','tang','','[]','蘇家小女名簡簡，芙蓉花顋柳葉眼。',144,'全唐诗/poet.tang.22000.json','["蘇家小女名簡簡，芙蓉花顋柳葉眼。", "十一把鏡學點妝，十二抽鍼能繡裳。", "十三行坐事調品，不肯迷頭白地藏。", "玲瓏雲髻生花樣，飄颻風袖薔薇香。", "殊姿異態不可狀，忽忽轉動如有光。", "二月繁霜殺桃李，明年欲嫁今年死。", "丈人阿母勿悲啼，此女不是凡夫妻。", "恐是天仙謫人世，只合人間十三歲。", "大都好物不堅牢，彩雲易散琉璃脆。"]'),
('5ee8cc24-814b-4a1a-8167-be749659a959','花非花','白居易','唐','唐诗','tang','','["\u5b8b\u8bcd\u4e09\u767e\u9996", "\u611f\u609f", "\u4eba\u751f", "\u5377\u4e00\u00b7\u5510\u4e94\u4ee3\u8bcd"]','花非花，霧非霧，夜半來，天明去。',32,'全唐诗/poet.tang.22000.json','["花非花，霧非霧，夜半來，天明去。", "來如春夢幾多時，去似朝雲無覓處。"]'),
('5618f10a-fb25-47ed-81fc-fe37d0cfcf5d','醉後狂言酬贈蕭殷二協律','白居易','唐','唐诗','tang','','[]','餘杭邑客多羇貧，其間甚者蕭與殷。',192,'全唐诗/poet.tang.22000.json','["餘杭邑客多羇貧，其間甚者蕭與殷。", "天寒身上猶衣葛，日高甑中未拂塵。", "江城山寺十一月，北風吹沙雪紛紛。", "賓客不見綈袍惠，黎庶未霑襦袴恩。", "此時太守自慙媿，重衣複衾有餘溫。", "因命染人與鍼女，先製兩裘贈二君。", "吳緜細輭桂布密，柔如狐腋白似雲。", "勞將詩書投贈我，如此小惠何足論。", "我有大裘君未見，寬廣和暖如陽春。", "此裘非繒亦非纊，裁以法度絮以仁。", "刀尺鈍拙製未畢，出亦不獨裹一身。", "若令在郡得五考，與君展覆杭州人。"]'),
('5d20ee30-f31f-42ca-9616-e35b29c5f783','醉歌','白居易','唐','唐诗','tang','','[]','罷胡琴，掩秦瑟，玲瓏再拜歌初畢。',80,'全唐诗/poet.tang.22000.json','["罷胡琴，掩秦瑟，玲瓏再拜歌初畢。", "誰道使君不解歌，聽唱黃雞與白日。", "黃雞催曉丑時鳴，白日催年酉前沒。", "腰間紅綬繫未穩，鏡裏朱顏看已失。", "玲瓏玲瓏奈老何，使君歌了汝更歌。"]'),
('c4dcf8ed-501b-488a-9f96-3411d3531008','代書詩一百韻寄微之','白居易','唐','唐诗','tang','','[]','憶在貞元歲，初登典校司。',288,'全唐诗/poet.tang.22000.json','["憶在貞元歲，初登典校司。", "身名同日授，心事一言知。", "肺腑都無隔，形骸兩不羈。", "疎狂屬年少，閑散爲官卑。", "分定金蘭契，言通藥石規。", "交賢方汲汲，友直每偲偲。", "有月多同賞，無杯不共持。", "秋風拂琴匣，夜雪卷書帷。", "高上慈恩塔，幽尋皇子陂。", "唐昌玉蘂會，崇敬牡丹期。", "笑勸迂辛酒，閑吟短李詩。", "儒風愛敦質，佛理賞玄師。", "度日曾無悶，通宵靡不爲。", "雙聲聯律句，八面對宮棊。", "往往遊三省，騰騰出九逵。", "寒銷直城路，春到曲江池。", "樹暖枝條弱，山晴彩翠奇。", "峰攢石綠點，柳宛麴塵絲。", "岸草煙鋪地，園花雪壓枝。", "早光紅照耀，新溜碧逶迤。", "幄幕侵堤布，盤筵占地施。", "徵伶皆絕藝，選伎悉名姬。", "粉黛凝春態，金鈿耀水嬉。", "風流誇墮髻，時世鬬啼眉。"]'),
('be1503e6-a995-45e0-bcfc-347a0fbd5f2f','和鄭元及第後秋歸洛下閑居','白居易','唐','唐诗','tang','','[]','勤苦成名後，優游得意間。',72,'全唐诗/poet.tang.22000.json','["勤苦成名後，優游得意間。", "玉憐同匠琢，桂恨隔年攀。", "山靜豹難隱，谷幽鶯暫還。", "微吟詩引步，淺酌酒開顏。", "門迥暮臨水，窗深朝對山。", "雲衢日相待，莫誤許身閑。"]'),
('8dd27dbc-9eea-4a37-ab9e-aa2cb87bfb08','與諸同年賀座主侍郎新拜太常同宴蕭尚書亭子','白居易','唐','唐诗','tang','','[]','寵新卿典禮，會盛客徵文。',48,'全唐诗/poet.tang.22000.json','["寵新卿典禮，會盛客徵文。", "不失遷鶯侶，因成賀燕羣。", "池臺晴間雪，冠蓋暮和雲。", "共仰曾攀處，年深桂尚熏。"]'),
('ee0bc226-3aff-4294-98b5-40eb1358ebfd','東都冬日會諸同年宴鄭家林亭','白居易','唐','唐诗','tang','','[]','盛時陪上第，暇日會羣賢。',72,'全唐诗/poet.tang.22000.json','["盛時陪上第，暇日會羣賢。", "桂折因同樹，鶯遷各異年。", "賓階紛組佩，妓席儼花鈿。", "促膝齊榮賤，差肩次後先。", "助歌林下水，銷酒雪中天。", "他日升沈者，無忘共此筵。"]'),
('4c63e71a-bfc5-4c8a-9545-8317db89a9cf','敘德書情四十韻上宣歙翟中丞','白居易','唐','唐诗','tang','','[]','元聖生乘運，忠賢出應期。',288,'全唐诗/poet.tang.22000.json','["元聖生乘運，忠賢出應期。", "還將稽古力，助立太平基。", "土控吳兼越，州連歙與池。", "山河地襟帶，軍鎮國藩維。", "廉察安江甸，澄清肅海夷。", "股肱分外守，耳目付中司。", "楚老歌來暮，秦人詠去思。", "望如時雨至，福是歲星移。", "政靜民無訟，刑行吏不欺。", "撝謙驚主寵，陰德畏人知。", "白玉慙溫色，朱繩讓直辭。", "行爲時領袖，言作世蓍龜。", "盛幕招賢士，連營訓銳師。", "光華下鵷鷺，氣色動熊羆。", "出入麾幢引，登臨劒戟隨。", "好風迎解榻，美景待搴帷。", "晴野霞飛綺，春郊柳宛絲。", "城烏驚畫角，江雁避紅旗。", "藉草朱輪駐，攀花紫綬垂。", "山宜謝公屐，洲稱柳家詩。", "酒氣和芳杜，弦聲亂子規。", "分毬齊馬首，列舞匝蛾眉。", "醉惜年光晚，歡憐日影遲。", "迴塘排玉櫂，歸路擁金羈。"]'),
('9d673641-9811-425e-bd06-30d7dafcce13','和渭北劉大夫借便秋遮虜寄朝中親友','白居易','唐','唐诗','tang','','[]','巨鎮爲邦屏，全材作國楨。',120,'全唐诗/poet.tang.22000.json','["巨鎮爲邦屏，全材作國楨。", "韜鈐漢上將，文墨魯諸生。", "豹虎關西卒，金湯渭北城。", "寵深初受棨，威重正揚兵。", "陣占山河布，軍諳水草行。", "夏苗侵虎落，宵遁失蕃營。", "雲隊攢戈戟，風行卷斾旌。", "堠空烽火滅，氣勝鼓鼙鳴。", "胡馬辭南牧，周師罷北征。", "迴頭問天下，何處有欃槍。"]'),
('c3b1a889-a678-4e76-bdb8-d2eaa8e1377d','題故曹王宅','白居易','唐','唐诗','tang','','[]','甲第何年置，朱門此地開。',72,'全唐诗/poet.tang.22000.json','["甲第何年置，朱門此地開。", "山當賓閣出，溪繞妓堂迴。", "覆井桐新長，陰窗竹舊栽。", "池荒紅菡萏，砌老綠莓苔。", "捐館梁王去，思人楚客來。", "西園飛蓋處，依舊月裴回。"]'),
('a93e907d-4493-4817-8471-644e8d12886d','自江陵之徐州路上寄兄弟','白居易','唐','唐诗','tang','','[]','岐路南將北，離憂弟與兄。',72,'全唐诗/poet.tang.22000.json','["岐路南將北，離憂弟與兄。", "關河千里別，風雪一身行。", "夕宿勞鄉夢，晨裝慘旅情。", "家貧憂後事，日短念前程。", "煙鴈飜寒渚，霜烏聚古城。", "誰憐陟岡者，西楚望南荆。"]'),
('79de9132-ef7d-41be-933b-5975a4990939','酬哥舒大見贈','白居易','唐','唐诗','tang','','[]','去歲歡遊何處去？曲江西岸杏園東。',64,'全唐诗/poet.tang.22000.json','["去歲歡遊何處去？曲江西岸杏園東。", "花下忘歸因美景，尊前勸酒是春風。", "各從微宦風塵裏，共度流年離別中。", "今日相逢愁又喜，八人分散兩人同。"]'),
('cdc21b7e-f366-40b6-ba46-e735209ddcbc','和談校書秋夜感懷呈朝中親友','白居易','唐','唐诗','tang','','[]','遙夜涼風楚客悲，清砧繁漏月高時。',64,'全唐诗/poet.tang.22000.json','["遙夜涼風楚客悲，清砧繁漏月高時。", "秋霜似鬢年空長，春草如袍位尚卑。", "詞賦擅名來已久，煙霄得路去何遲。", "漢庭卿相皆知己，不薦揚雄欲薦誰。"]'),
('954cfeec-37cd-44aa-a7d6-d58f5838a9b5','感秋寄遠','白居易','唐','唐诗','tang','','[]','惆悵時節晚，兩情千里同。',48,'全唐诗/poet.tang.22000.json','["惆悵時節晚，兩情千里同。", "離憂不散處，庭樹正秋風。", "燕影動歸翼，蕙香銷故叢。", "佳期與芳歲，牢落兩成空。"]'),
('4774c672-1e99-4a1d-b388-7c3b341c8499','春題華陽觀','白居易','唐','唐诗','tang','','[]','帝子吹簫逐鳳皇，空留仙洞號華陽。',32,'全唐诗/poet.tang.22000.json','["帝子吹簫逐鳳皇，空留仙洞號華陽。", "落花何處堪惆悵，頭白宮人埽影堂。"]'),
('3ec2706c-b474-43e4-a06f-bdb2b24aa7b9','秋雨中贈元九','白居易','唐','唐诗','tang','','["\u5199\u96e8", "\u79cb\u5929", "\u96e8", "\u6000\u4eba"]','不堪紅葉青苔地，又是涼風暮雨天。',32,'全唐诗/poet.tang.22000.json','["不堪紅葉青苔地，又是涼風暮雨天。", "莫怪獨吟秋思苦，比君校近二毛年。"]'),
('d61d22ec-4e21-487d-a7dc-5f8f98db83ab','城東閑遊','白居易','唐','唐诗','tang','','[]','寵辱憂歡不到情，任他朝市自營營。',32,'全唐诗/poet.tang.22000.json','["寵辱憂歡不到情，任他朝市自營營。", "獨尋秋景城東去，白鹿原頭信馬行。"]'),
('4b14acee-b0cb-4d95-9f75-305e88d21837','荅韋八','白居易','唐','唐诗','tang','','[]','麗句勞相贈，佳期恨有違。',48,'全唐诗/poet.tang.22000.json','["麗句勞相贈，佳期恨有違。", "早知留酒待，悔不趁花歸。", "春盡綠醅老，雨多紅萼稀。", "今朝如一醉，猶得及芳菲。"]'),
('c704db41-2508-4a1f-bc63-964c708285d6','華陽觀桃花時招李六拾遺飲','白居易','唐','唐诗','tang','','[]','華陽觀裏仙桃發，把酒看花心自知。',32,'全唐诗/poet.tang.22000.json','["華陽觀裏仙桃發，把酒看花心自知。", "爭忍開時不同醉，明朝後日即空枝。"]'),
('6162b204-6640-4d84-a068-6d870b10f290','和友人洛中春感','白居易','唐','唐诗','tang','','[]','莫悲金谷園中月，莫歎天津橋上春。',32,'全唐诗/poet.tang.22000.json','["莫悲金谷園中月，莫歎天津橋上春。", "若學多情尋往事，人間何處不傷神。"]'),
('9c90085e-b3c0-4c71-95fb-395232cd3933','送張南簡入蜀','白居易','唐','唐诗','tang','','[]','昨日詔書下，求賢訪陸沈。',36,'全唐诗/poet.tang.22000.json','["昨日詔書下，求賢訪陸沈。", "無論能與否，皆起徇名心。", "君獨南遊去，雲山蜀路深。"]'),
('cb7a7e89-d789-432a-a00b-e7710329c6f1','寄陸補闕','白居易','唐','唐诗','tang','','[]','忽憶前年科第後，此時雞鶴暫同羣。',32,'全唐诗/poet.tang.22000.json','["忽憶前年科第後，此時雞鶴暫同羣。", "秋風惆悵須吹散，雞在中庭鶴在雲。"]'),
('f8f7f42a-fd85-40b0-b374-83ee63f28247','華陽觀中八月十五日夜招友玩月','白居易','唐','唐诗','tang','','[]','人道秋中明月好，欲邀同賞意如何。',32,'全唐诗/poet.tang.22000.json','["人道秋中明月好，欲邀同賞意如何。", "華陽洞裏秋壇上，今夜清光此處多。"]'),
('15938255-e44a-447c-93aa-7a657324458a','曲江憶元九','白居易','唐','唐诗','tang','','[]','春來無伴閑遊少，行樂三分減二分。',32,'全唐诗/poet.tang.22000.json','["春來無伴閑遊少，行樂三分減二分。", "何況今朝杏園裏，閑人逢盡不逢君。"]'),
('58438519-9454-428f-a313-8648598f5f89','過劉三十二故宅','白居易','唐','唐诗','tang','','[]','不見劉君來近遠，門前兩度滿枝花。',32,'全唐诗/poet.tang.22000.json','["不見劉君來近遠，門前兩度滿枝花。", "朝來惆悵宣平過，柳巷當頭第一家。"]'),
('bf2bb174-c237-4b8d-a9a9-17a698553cc6','下邽莊南桃花','白居易','唐','唐诗','tang','','[]','村南無限桃花發，唯我多情獨自來。',32,'全唐诗/poet.tang.22000.json','["村南無限桃花發，唯我多情獨自來。", "日暮風吹紅滿地，無人解惜爲誰開。"]'),
('b1b4e21a-27bf-47bb-a016-239ece08114b','三月三十日題慈恩寺','白居易','唐','唐诗','tang','','[]','慈恩春色今朝盡，盡日裴回倚寺門。',32,'全唐诗/poet.tang.22000.json','["慈恩春色今朝盡，盡日裴回倚寺門。", "惆悵春歸留不得，紫藤花下漸黃昏。"]'),
('b07d6b8d-a5f4-466d-8e67-c7dc5f4db5c6','看惲家牡丹花戲贈李二十','白居易','唐','唐诗','tang','','[]','香勝燒蘭紅勝霞，城中最數令公家。',32,'全唐诗/poet.tang.22000.json','["香勝燒蘭紅勝霞，城中最數令公家。", "人人散後君須看，歸到江南無此花。"]'),
('1f7eeffd-5f59-4e9d-a2b2-0ff35561e93c','春中與盧四周諒華陽觀同居','白居易','唐','唐诗','tang','','[]','性情嬾慢好相親，門巷蕭條稱作鄰。',64,'全唐诗/poet.tang.22000.json','["性情嬾慢好相親，門巷蕭條稱作鄰。", "背燭共憐深夜月，蹋花同惜少年春。", "杏壇住僻雖宜病，芸閣官微不救貧。", "文行如君尚顦顇，不知霄漢待何人。"]'),
('1bec4f5b-2b75-4b00-8c23-6ac25ea0d08e','自城東至以詩代書戲招李六拾遺崔二十六先輩','白居易','唐','唐诗','tang','','[]','青門走馬趁心期，惆悵歸來已校遲。',64,'全唐诗/poet.tang.22000.json','["青門走馬趁心期，惆悵歸來已校遲。", "應過唐昌玉蘂後，猶當崇敬牡丹時。", "暫遊還憶崔先輩，欲醉先邀李拾遺。", "尚殘半月芸香俸，不作歸糧作酒貲。"]'),
('768175e5-04d5-47e2-bbc3-b2d90d14ffb5','盩厔縣北樓望山','白居易','唐','唐诗','tang','','[]','一爲趨走吏，塵土不開顏。',24,'全唐诗/poet.tang.22000.json','["一爲趨走吏，塵土不開顏。", "孤負平生眼，今朝始見山。"]'),
('947db2a2-41fb-4caa-b0e1-bbed25927a99','縣西郊秋寄贈馬造','白居易','唐','唐诗','tang','','[]','紫閣峰西清渭東，野煙深處夕陽中。',48,'全唐诗/poet.tang.22000.json','["紫閣峰西清渭東，野煙深處夕陽中。", "風荷老葉蕭條綠，水蓼殘花寂寞紅。", "我厭宦遊君失意，可憐秋思兩心同。"]'),
('9d882f4e-ce70-4336-a430-b644335028f3','別韋蘇州','白居易','唐','唐诗','tang','','[]','百年愁裏過，萬感醉中來。',24,'全唐诗/poet.tang.22000.json','["百年愁裏過，萬感醉中來。", "惆悵城西別，愁眉兩不開。"]'),
('6d2a307b-1202-4a89-ba1e-34d3b51af3d5','戲題新栽薔薇','白居易','唐','唐诗','tang','','[]','移根易地莫顦顇，野外庭前一種春。',32,'全唐诗/poet.tang.22000.json','["移根易地莫顦顇，野外庭前一種春。", "少府無妻春寂寞，花開將爾當夫人。"]'),
('963a663b-28d3-4728-8a3a-152d54f1dfda','酬王十八李大見招遊山','白居易','唐','唐诗','tang','','[]','自憐幽會心期阻，復媿嘉招書信頻。',32,'全唐诗/poet.tang.22000.json','["自憐幽會心期阻，復媿嘉招書信頻。", "王事牽身去不得，滿山松雪屬他人。"]'),
('5446ce84-6f79-4de1-a771-fa39a81bdc9b','縣南花下醉中留劉五','白居易','唐','唐诗','tang','','[]','百歲幾迴同酩酊，一年今日最芳菲。',32,'全唐诗/poet.tang.22000.json','["百歲幾迴同酩酊，一年今日最芳菲。", "願將花贈天台女，留取劉郎到夜歸。"]'),
('bd0cc70d-73ab-4bd3-b5de-3d3800a8ca2b','宿楊家','白居易','唐','唐诗','tang','','[]','楊氏弟兄俱醉臥，披衣獨起下高齋。',32,'全唐诗/poet.tang.22000.json','["楊氏弟兄俱醉臥，披衣獨起下高齋。", "夜深不語中庭立，月照藤花影上階。"]'),
('2ee15225-57fd-4564-8e2c-4620bfd4afb4','醉中留別楊六兄弟','白居易','唐','唐诗','tang','','[]','春初攜手春深散，無日花間不醉狂。',32,'全唐诗/poet.tang.22000.json','["春初攜手春深散，無日花間不醉狂。", "別後何人堪共醉，猶殘十日好風光。"]'),
('d11f51f5-36f1-45b2-a040-f031c692c249','醉中歸盩厔','白居易','唐','唐诗','tang','','[]','金光門外昆明路，半醉騰騰信馬迴。',32,'全唐诗/poet.tang.22000.json','["金光門外昆明路，半醉騰騰信馬迴。", "數日非關王事繫，牡丹花盡始歸來。"]'),
('53028b2e-544e-459b-bcce-e338144fa773','遊雲居寺贈穆三十六地主','白居易','唐','唐诗','tang','','[]','亂峰深處雲居路，共蹋花行獨惜春。',32,'全唐诗/poet.tang.22000.json','["亂峰深處雲居路，共蹋花行獨惜春。", "勝地本來無定主，大都山屬愛山人。"]'),
('3859bf9d-de38-42a2-81cd-d949039796f0','和王十八薔薇澗花時有懷蕭侍御兼見贈','白居易','唐','唐诗','tang','','[]','霄漢風塵俱是繫，薔薇花委故山深。',32,'全唐诗/poet.tang.22000.json','["霄漢風塵俱是繫，薔薇花委故山深。", "憐君獨向澗中立，一把紅芳三處心。"]'),
('840ce0ed-eb6c-46e5-82e9-f4a8cc0f18da','再因公事到駱口驛','白居易','唐','唐诗','tang','','[]','今年到時夏雲白，去年來時秋樹紅。',32,'全唐诗/poet.tang.22000.json','["今年到時夏雲白，去年來時秋樹紅。", "兩度見山心有媿，皆因王事到山中。"]'),
('e67b678e-4534-46bf-b632-5f235ff5bfbb','期李二十文略王十八質夫不至獨宿仙遊寺','白居易','唐','唐诗','tang','','[]','文略也從牽吏役，質夫何故戀囂塵。',32,'全唐诗/poet.tang.22000.json','["文略也從牽吏役，質夫何故戀囂塵。", "始知解愛山中宿，千萬人中無一人。"]'),
('d505db47-7a71-49b2-8fc2-8377b6867374','酬趙秀才贈新登科諸先輩','白居易','唐','唐诗','tang','','[]','莫羨蓬萊鸞鶴侶，道成羽翼自生身。',32,'全唐诗/poet.tang.22000.json','["莫羨蓬萊鸞鶴侶，道成羽翼自生身。", "君看名在丹臺者，盡是人間修道人。"]'),
('fbf22c24-6020-4423-b6ce-2980ad7128d6','過天門街','白居易','唐','唐诗','tang','','[]','雪盡終南又欲春，遙憐翠色對紅塵。',32,'全唐诗/poet.tang.22000.json','["雪盡終南又欲春，遙憐翠色對紅塵。", "千車萬馬九衢上，回首看山無一人。"]'),
('39e149d5-4920-4e9e-addf-f6856006b0b9','惜玉蘂花有懷集賢王校書起','白居易','唐','唐诗','tang','','[]','芳意將闌風又吹，白雲離葉雪辭枝。',32,'全唐诗/poet.tang.22000.json','["芳意將闌風又吹，白雲離葉雪辭枝。", "集賢讎校無閑日，落盡瑤花君不知。"]'),
('90c2cd6d-0584-481e-942f-4ec54f825a04','春送盧秀才下第遊太原謁嚴尚書','白居易','唐','唐诗','tang','','[]','未將時會合，且與俗浮沈。',48,'全唐诗/poet.tang.22000.json','["未將時會合，且與俗浮沈。", "鴻養青冥翮，蛟潛雲雨心。", "煙郊春別遠，風磧暮程深。", "墨客投何處，幷州舊翰林。"]'),
('d7147b2d-a269-4713-9a36-f33828741d44','長安送柳大東歸','白居易','唐','唐诗','tang','','[]','白社羈遊伴，青門遠別離。',24,'全唐诗/poet.tang.22000.json','["白社羈遊伴，青門遠別離。", "浮名相引住，歸路不同歸。"]'),
('55f9fef6-7e33-469e-b541-b7607eed2915','送文暢上人東遊','白居易','唐','唐诗','tang','','[]','得道即無著，隨緣西復東。',48,'全唐诗/poet.tang.22000.json','["得道即無著，隨緣西復東。", "貌依年臘老，心到夜禪空。", "山宿馴溪虎，江行濾水蟲。", "悠悠塵客思，春滿碧雲中。"]'),
('784ea83c-e62e-46ff-8926-61e23c29faa0','社日關路作','白居易','唐','唐诗','tang','','[]','晚景函關路，涼風社日天。',48,'全唐诗/poet.tang.22000.json','["晚景函關路，涼風社日天。", "青巖新有燕，紅樹欲無蟬。", "愁立驛樓上，厭行官堠前。", "蕭條秋興苦，漸近二毛年。"]'),
('210b9f5e-908c-467f-b8e1-4f894a38debd','重到毓村宅有感','白居易','唐','唐诗','tang','','[]','欲入中門淚滿巾，庭花無主兩迴春。',32,'全唐诗/poet.tang.22000.json','["欲入中門淚滿巾，庭花無主兩迴春。", "軒窗簾幕皆依舊，只是堂前欠一人。"]'),
('bbc32292-ff89-4f1b-8696-f3bc9684faf7','亂後過流溝寺','白居易','唐','唐诗','tang','','[]','九月徐州新戰後，悲風殺氣滿山河。',32,'全唐诗/poet.tang.22000.json','["九月徐州新戰後，悲風殺氣滿山河。", "唯有流溝山下寺，門前依舊白雲多。"]'),
('c4500204-2d83-45a0-b6a8-50aa50ec086c','歎髮落','白居易','唐','唐诗','tang','','[]','多病多愁心自知，行年未老髮先衰。',32,'全唐诗/poet.tang.22000.json','["多病多愁心自知，行年未老髮先衰。", "隨梳落去何須惜，不落終須變作絲。"]'),
('f9c7cfee-dd62-460c-b2b7-2490696deea2','留別吳七正字','白居易','唐','唐诗','tang','','[]','成名共記甲科上，署吏同登芸閣間。',32,'全唐诗/poet.tang.22000.json','["成名共記甲科上，署吏同登芸閣間。", "唯是塵心殊道性，秋蓬常轉水長閑。"]'),
('f3f62a61-92aa-4722-ae49-30f01c03df7f','除夜宿洺州','白居易','唐','唐诗','tang','','[]','家寄關西住，身爲河北遊。',24,'全唐诗/poet.tang.22000.json','["家寄關西住，身爲河北遊。", "蕭條歲除夜，旅泊在洺州。"]'),
('71263a4a-e096-441c-a82f-02a0c483577b','邯鄲冬至夜思家','白居易','唐','唐诗','tang','','["\u51ac\u5929", "\u601d\u4e61", "\u5e26\u6709\u5730\u540d", "\u5730\u540d"]','邯鄲驛裏逢冬至，抱膝燈前影伴身。',32,'全唐诗/poet.tang.22000.json','["邯鄲驛裏逢冬至，抱膝燈前影伴身。", "想得家中夜深坐，還應說著遠行人。"]'),
('578f99ee-4165-4bc0-8c54-d675f4fabf1c','冬至夜懷湘靈','白居易','唐','唐诗','tang','','[]','豔質無由見，寒衾不可親。',24,'全唐诗/poet.tang.22000.json','["豔質無由見，寒衾不可親。", "何堪最長夜，俱作獨眠人。"]'),
('a9515a84-89a0-4245-93ea-d1e1da419f5c','感故張僕射諸妓','白居易','唐','唐诗','tang','','[]','黃金不惜買蛾眉，揀得如花三四枝。',32,'全唐诗/poet.tang.22000.json','["黃金不惜買蛾眉，揀得如花三四枝。", "歌舞教成心力盡，一朝身去不相隨。"]'),
('1f50090f-1c01-4b33-bbf6-965ac5819f57','遊仙遊山','白居易','唐','唐诗','tang','','[]','闇將心地出人間，五六年來人怪閑。',32,'全唐诗/poet.tang.22000.json','["闇將心地出人間，五六年來人怪閑。", "自嫌戀著未全盡，猶愛雲泉多在山。"]'),
('26c0f439-29bc-4cfb-8aef-8a3e51ee1851','見尹公亮新詩偶贈絕句','白居易','唐','唐诗','tang','','[]','袖裏新詩十首餘，吟看句句是瓊琚。',32,'全唐诗/poet.tang.22000.json','["袖裏新詩十首餘，吟看句句是瓊琚。", "如何持此將干謁，不及公卿一字書。"]'),
('50f53af5-9721-49cf-9cd0-4ca7a4cfbbb8','長安閑居','白居易','唐','唐诗','tang','','[]','風竹松煙晝掩關，意中長似在深山。',32,'全唐诗/poet.tang.22000.json','["風竹松煙晝掩關，意中長似在深山。", "無人不怪長安住，何獨朝朝暮暮間。"]'),
('47d39d91-8d2e-4bb8-b68f-98477f427f25','早春獨遊曲江','白居易','唐','唐诗','tang','','[]','散職無羈束，羸驂少送迎。',120,'全唐诗/poet.tang.22000.json','["散職無羈束，羸驂少送迎。", "朝從直城出，春傍曲江行。", "風起池東暖，雲開山北晴。", "冰銷泉脈動，雪盡草芽生。", "露杏紅初坼，煙楊綠未成。", "影遲新度鴈，聲澀欲啼鶯。", "閑地心俱靜，韶光眼共明。", "酒狂憐性逸，藥效喜身輕。", "慵慢疎人事，幽棲逐野情。", "迴看芸閣笑，不似有浮名。"]'),
('7732a927-0843-4d0f-9547-ce2b47334879','祕書省中憶舊山','白居易','唐','唐诗','tang','','[]','厭從薄宦校青簡，悔別故山思白雲。',32,'全唐诗/poet.tang.22000.json','["厭從薄宦校青簡，悔別故山思白雲。", "猶喜蘭臺非傲吏，歸時應免動移文。"]'),
('e6a9b0dc-74fc-4f16-b4f1-7a599982aac2','涼夜有懷','白居易','唐','唐诗','tang','','[]','清風吹枕席，白露濕衣裳。',24,'全唐诗/poet.tang.22000.json','["清風吹枕席，白露濕衣裳。", "好是相親夜，漏遲天氣涼。"]'),
('71a9187b-d586-453c-8ee8-c244203a0de3','送武士曹歸蜀','白居易','唐','唐诗','tang','','[]','花落鳥嚶嚶，南歸稱野情。',48,'全唐诗/poet.tang.22000.json','["花落鳥嚶嚶，南歸稱野情。", "月宜秦嶺宿，春好蜀江行。", "鄉路通雲棧，郊扉近錦城。", "烏臺陟岡送，人羨別時榮。"]'),
('55e096b9-a41b-47e4-8eb6-fd50581a2a68','江南送北客因憑寄徐州兄弟書','白居易','唐','唐诗','tang','','[]','故園望斷欲何如，楚水吳山萬里餘。',32,'全唐诗/poet.tang.22000.json','["故園望斷欲何如，楚水吳山萬里餘。", "今日因君訪兄弟，數行鄉淚一封書。"]'),
('0174cbbc-31fa-4daf-b1cf-7f91c6a646a9','賦得古原草送別','白居易','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u5199\u8349", "\u4e8c\u5e74\u7ea7\u4e0b\u518c", "\u548f\u7269", "\u9001\u522b", "\u4e94\u8a00\u5f8b\u8bd7"]','離離原上草，一歲一枯榮。',48,'全唐诗/poet.tang.22000.json','["離離原上草，一歲一枯榮。", "野火燒不盡，春風吹又生。", "遠芳侵古道，晴翠接荒城。", "又送王孫去，萋萋滿別情。"]'),
('0888ad57-fb1c-41ad-8191-df2d37e0aad1','夜哭李夷道','白居易','唐','唐诗','tang','','[]','逝者絕影響，空庭朝復昏。',40,'全唐诗/poet.tang.22000.json','["逝者絕影響，空庭朝復昏。", "家人哀臨畢，夜鏁壽堂門。", "無妻無子何人葬，空見銘旌向月飜。"]'),
('089fa1dd-9956-44e6-8230-2ad16b259f86','病中作','白居易','唐','唐诗','tang','','[]','久爲勞生事，不學攝生道。',24,'全唐诗/poet.tang.22000.json','["久爲勞生事，不學攝生道。", "年少已多病，此身豈堪老。"]'),
('b25a588e-10c2-40e6-92a4-12e0e1904a2f','秋江晚泊','白居易','唐','唐诗','tang','','[]','扁舟泊雲島，倚櫂念鄉國。',36,'全唐诗/poet.tang.22000.json','["扁舟泊雲島，倚櫂念鄉國。", "四望不見人，煙江澹秋色。", "客心貧易動，日入愁未息。"]'),
('156a6098-8d73-48c3-91e8-ceae6aaee7df','旅次景空寺宿幽上人院','白居易','唐','唐诗','tang','','[]','不與人境接，寺門開向山。',48,'全唐诗/poet.tang.22000.json','["不與人境接，寺門開向山。", "暮鐘寒鳥聚，秋雨病僧閑。", "月隱雲樹外，螢飛廊宇間。", "幸投花界宿，暫得靜心顏。"]'),
('825a3fa6-f22a-406d-88c4-6417a218f417','長安正月十五日','白居易','唐','唐诗','tang','','[]','諠諠車騎帝王州，羇病無心逐勝遊。',32,'全唐诗/poet.tang.22000.json','["諠諠車騎帝王州，羇病無心逐勝遊。", "明月春風三五夜，萬人行樂一人愁。"]'),
('2437cd98-fd11-4eab-be03-636f1ac08e54','過高將軍墓','白居易','唐','唐诗','tang','','[]','原上新墳委一身，城中舊宅有何人。',48,'全唐诗/poet.tang.22000.json','["原上新墳委一身，城中舊宅有何人。", "妓堂賓閣無歸日，野草山花又欲春。", "門客空將感恩淚，白楊風裏一霑巾。"]'),
('b1ea01a1-a614-455d-afc8-3ccf1150f620','寒食臥病','白居易','唐','唐诗','tang','','[]','病逢佳節長歎息，春雨濛濛榆柳色。',48,'全唐诗/poet.tang.22000.json','["病逢佳節長歎息，春雨濛濛榆柳色。", "羸坐全非舊日容，扶行半是他人力。", "諠諠里巷蹋青歸，笑閉柴門度寒食。"]'),
('67c19865-9ca0-4e55-b73a-1d613ef41890','宿桐廬館同崔存度醉後作','白居易','唐','唐诗','tang','','[]','江海漂漂共旅遊，一尊相勸散窮愁。',32,'全唐诗/poet.tang.22000.json','["江海漂漂共旅遊，一尊相勸散窮愁。", "夜深醒後愁還在，雨滴梧桐山館秋。"]'),
('93f9ba05-054c-4c81-b9b0-6f20403c10ae','江樓望歸','白居易','唐','唐诗','tang','','[]','滿眼雲水色，月明樓上人。',48,'全唐诗/poet.tang.22000.json','["滿眼雲水色，月明樓上人。", "旅愁春入越，鄉夢夜歸秦。", "道路通荒服，田園隔虜塵。", "悠悠滄海畔，十載避黃巾。"]'),
('0daf2c4f-321f-44c3-a6c3-eb6576a3aadf','除夜寄弟妹','白居易','唐','唐诗','tang','','["\u601d\u5ff5", "\u8282\u65e5", "\u4eb2\u4eba"]','感時思弟妹，不寐百憂生。',48,'全唐诗/poet.tang.22000.json','["感時思弟妹，不寐百憂生。", "萬里經年別，孤燈此夜情。", "病容非舊日，歸思逼新正。", "早晚重歡會，羇離各長成。"]'),
('b3970bdf-c421-41b9-b6da-d5f57437c3cd','寒食月夜','白居易','唐','唐诗','tang','','[]','風香露重棃花濕，草舍無燈愁未入。',32,'全唐诗/poet.tang.22000.json','["風香露重棃花濕，草舍無燈愁未入。", "南鄰北里歌吹時，獨倚柴門月中立。"]'),
('537740ce-d87e-4cf2-a93d-6b9999b42327','感芍藥花寄正一上人','白居易','唐','唐诗','tang','','[]','今日階前紅芍藥，幾花欲老幾花新。',48,'全唐诗/poet.tang.22000.json','["今日階前紅芍藥，幾花欲老幾花新。", "開時不解比色相，落後始知如幻身。", "空門此去幾多地，欲把殘花問上人。"]'),
('3ae0baa0-f15e-4820-b606-0b873a659e72','晚秋閑居','白居易','唐','唐诗','tang','','[]','地僻門深少送迎，披衣閑坐養幽情。',32,'全唐诗/poet.tang.22000.json','["地僻門深少送迎，披衣閑坐養幽情。", "秋庭不埽攜藤杖，閑蹋梧桐黃葉行。"]'),
('e8143158-8575-48b1-ac8f-146fdb10c033','秋暮郊居書懷','白居易','唐','唐诗','tang','','[]','郊居人事少，晝臥對林巒。',48,'全唐诗/poet.tang.22000.json','["郊居人事少，晝臥對林巒。", "窮巷厭多雨，貧家愁早寒。", "葛衣秋未換，書卷病仍看。", "若問生涯計，前溪一釣竿。"]'),
('85a8c5b3-509e-4215-b4cc-e388a21558d3','爲薛台悼亡','白居易','唐','唐诗','tang','','["\u60bc\u4ea1"]','半死梧桐老病身，重泉一念一傷神。',32,'全唐诗/poet.tang.22000.json','["半死梧桐老病身，重泉一念一傷神。", "手攜穉子夜歸院，月冷空房不見人。"]'),
('f91dac01-51cd-430a-8e08-69634bbcd958','途中寒食','白居易','唐','唐诗','tang','','[]','路傍寒食行人盡，獨占春愁在路旁。',32,'全唐诗/poet.tang.22000.json','["路傍寒食行人盡，獨占春愁在路旁。", "馬上垂鞭愁不語，風吹百草野田香。"]'),
('016f4ae1-2782-47a6-9290-5956da3a2126','題流溝寺古松','白居易','唐','唐诗','tang','','[]','煙葉蔥蘢蒼麈尾，霜皮剝落紫龍鱗。',32,'全唐诗/poet.tang.22000.json','["煙葉蔥蘢蒼麈尾，霜皮剝落紫龍鱗。", "欲知松老看塵壁，死却題詩幾許人。"]'),
('a7f6b674-6f0b-47a1-9ad7-5c2084a8f544','感月悲逝者','白居易','唐','唐诗','tang','','[]','存亡感月一潸然，月色今宵似往年。',32,'全唐诗/poet.tang.22000.json','["存亡感月一潸然，月色今宵似往年。", "何處曾經同望月？櫻桃樹下後堂前。"]'),
('cc28d8c0-ca9d-4418-a3d7-73f23c300a35','代鄰叟言懷','白居易','唐','唐诗','tang','','[]','人生何事心無定，宿昔如今意不同。',32,'全唐诗/poet.tang.22000.json','["人生何事心無定，宿昔如今意不同。", "宿昔愁身不得老，如今恨作白頭翁。"]'),
('a2aed629-465d-412c-a68d-780068488725','自河南經亂關內阻饑兄弟離散各在一處因望月有感聊書所懷寄上浮梁大兄於潛七兄烏江十五兄兼示符離及下邽弟妹','白居易','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996"]','時難年饑世業空，弟兄羇旅各西東。',64,'全唐诗/poet.tang.22000.json','["時難年饑世業空，弟兄羇旅各西東。", "田園寥落干戈後，骨肉流離道路中。", "弔影分爲千里鴈，辭根散作九秋蓬。", "共看明月應垂淚，一夜鄉心五處同。"]'),
('d80fa8fd-ecec-4c5a-9b04-108dc495562b','長安早春旅懷','白居易','唐','唐诗','tang','','[]','軒車歌吹諠都邑，中有一人向隅立。',64,'全唐诗/poet.tang.22000.json','["軒車歌吹諠都邑，中有一人向隅立。", "夜深明月卷簾愁，日暮青山望鄉泣。", "風吹新綠草芽坼，雨灑輕黃柳條濕。", "此生知負少年春，不展愁眉欲三十。"]'),
('3020bd5c-547a-4624-be07-7e59be430879','寒閨夜','白居易','唐','唐诗','tang','','[]','夜半衾裯冷，孤眠嬾未能。',36,'全唐诗/poet.tang.22000.json','["夜半衾裯冷，孤眠嬾未能。", "籠香銷盡火，巾淚滴成冰。", "爲惜影相伴，通宵不滅燈。"]'),
('9cf12c73-a403-4d2f-bfa4-392e5c843745','寄湘靈','白居易','唐','唐诗','tang','','[]','淚眼凌寒凍不流，每經高處即迴頭。',32,'全唐诗/poet.tang.22000.json','["淚眼凌寒凍不流，每經高處即迴頭。", "遙知別後西樓上，應凭闌干獨自愁。"]'),
('609cfa44-628d-4344-91bd-ca03998bf52e','冬至宿楊梅館','白居易','唐','唐诗','tang','','[]','十一月中長至夜，三千里外遠行人。',32,'全唐诗/poet.tang.22000.json','["十一月中長至夜，三千里外遠行人。", "若爲獨宿楊梅館，冷枕單牀一病身。"]'),
('5e0d4326-adc3-4b6e-933f-a9458d1bc218','臨江送夏瞻','白居易','唐','唐诗','tang','','[]','悲君老別我霑巾，七十無家萬里身。',32,'全唐诗/poet.tang.22000.json','["悲君老別我霑巾，七十無家萬里身。", "愁見舟行風又起，白頭浪裏白頭人。"]'),
('9d9e1245-88cb-4514-92ed-cdb509610832','冬夜示敏巢','白居易','唐','唐诗','tang','','[]','爐火欲銷燈欲盡，夜長相對百憂生。',32,'全唐诗/poet.tang.22000.json','["爐火欲銷燈欲盡，夜長相對百憂生。", "他時諸處重相見，莫忘今宵燈下情。"]'),
('6c807344-e349-4e3b-a5d4-baa81b8a80b6','客中守歲','白居易','唐','唐诗','tang','','[]','守歲尊無酒，思鄉淚滿巾。',48,'全唐诗/poet.tang.22000.json','["守歲尊無酒，思鄉淚滿巾。", "始知爲客苦，不及在家貧。", "畏老偏驚節，防愁預惡春。", "故園今夜裏，應念未歸人。"]'),
('601def97-8e7b-4652-8d3a-4bd61095a324','問淮水','白居易','唐','唐诗','tang','','[]','自嗟名利客，擾擾在人間。',24,'全唐诗/poet.tang.22000.json','["自嗟名利客，擾擾在人間。", "何事長淮水，東流亦不閑。"]'),
('580ebee8-68e3-4109-8918-4f1d7dd2f629','宿樟亭驛','白居易','唐','唐诗','tang','','[]','夜半樟亭驛，愁人起望鄉。',24,'全唐诗/poet.tang.22000.json','["夜半樟亭驛，愁人起望鄉。", "月明何所見，潮水白茫茫。"]'),
('05e38f80-0b14-483a-9e1a-6965c4984106','及第後憶舊山','白居易','唐','唐诗','tang','','[]','偶獻子虛登上第，却吟招隱憶中林。',32,'全唐诗/poet.tang.22000.json','["偶獻子虛登上第，却吟招隱憶中林。", "春蘿秋桂莫惆悵，縱有浮名不繫心。"]'),
('595930ed-7fbc-4f25-b790-93648a05bc63','題李次雲窗竹','白居易','唐','唐诗','tang','','[]','不用裁爲鳴鳳管，不須截作釣魚竿。',32,'全唐诗/poet.tang.22000.json','["不用裁爲鳴鳳管，不須截作釣魚竿。", "千花百草凋零後，留向紛紛雪裏看。"]'),
('e1105b43-ccd1-443b-89e3-53c421ac386c','花下自勸酒','白居易','唐','唐诗','tang','','[]','酒醆酌來須滿滿，花枝看即落紛紛。',32,'全唐诗/poet.tang.22000.json','["酒醆酌來須滿滿，花枝看即落紛紛。", "莫言三十是年少，百歲三分已一分。"]'),
('38747045-e685-40fe-a4a4-2746764298cb','題李十一東亭','白居易','唐','唐诗','tang','','[]','相思夕上松臺立，蛩思蟬聲滿耳秋。',32,'全唐诗/poet.tang.22000.json','["相思夕上松臺立，蛩思蟬聲滿耳秋。", "惆悵東亭風月好，主人今夜在鄜州。"]'),
('6056cb61-9be4-4598-8aed-e474cdb71104','春村','白居易','唐','唐诗','tang','','[]','二月村園暖，桑間戴勝飛。',48,'全唐诗/poet.tang.22000.json','["二月村園暖，桑間戴勝飛。", "農夫舂舊穀，蠶妾擣新衣。", "牛馬因風遠，雞豚過社稀。", "黃昏林下路，鼓笛賽神歸。"]'),
('84a7d924-e13f-4a58-8ace-df9a24a5ea26','題施山人野居','白居易','唐','唐诗','tang','','[]','得道應無著，謀生亦不妨。',36,'全唐诗/poet.tang.22000.json','["得道應無著，謀生亦不妨。", "春泥秧稻暖，夜火焙茶香。", "水巷風塵少，松齋日月長。"]'),
('55824cb3-1454-4a9f-b201-6fa551f8dddc','翰林中送獨孤二十七起居罷職出院','白居易','唐','唐诗','tang','','[]','碧落留雲住，青冥放鶴還。',24,'全唐诗/poet.tang.22000.json','["碧落留雲住，青冥放鶴還。", "銀臺向南路，從此到人間。"]'),
('7783948d-a789-4a9c-956d-1bc29dcd4eb8','重尋杏園','白居易','唐','唐诗','tang','','[]','忽憶芳時頻酩酊，却尋醉處重裴回。',32,'全唐诗/poet.tang.22000.json','["忽憶芳時頻酩酊，却尋醉處重裴回。", "杏花結子春深後，誰解多情又獨來。"]'),
('f967f283-a5d7-4c4c-be64-5a2d4c49d162','曲江獨行','白居易','唐','唐诗','tang','','[]','獨來獨去何人識，廐馬朝衣野客心。',32,'全唐诗/poet.tang.22000.json','["獨來獨去何人識，廐馬朝衣野客心。", "閑愛無風水邊坐，楊花不動樹陰陰。"]'),
('43a45a77-20d2-406c-9684-e79cc3b86352','同李十一醉憶元九','白居易','唐','唐诗','tang','','["\u601d\u5ff5", "\u53cb\u60c5"]','花時同醉破春愁，醉折花枝當酒籌。',32,'全唐诗/poet.tang.22000.json','["花時同醉破春愁，醉折花枝當酒籌。", "忽憶故人天際去，計程今日到涼州。"]'),
('304f8683-291a-4cf7-b016-597fe2693367','同錢員外題絕糧僧巨川','白居易','唐','唐诗','tang','','[]','三十年來坐對山，唯將無事化人間。',32,'全唐诗/poet.tang.22000.json','["三十年來坐對山，唯將無事化人間。", "齋時往往聞鐘笑，一食何如不食閑。"]'),
('ccd01643-9cd7-4802-9cd4-c980d30b22bb','絕句代書贈錢員外','白居易','唐','唐诗','tang','','[]','欲尋秋景閑行去，君病多慵我興孤。',32,'全唐诗/poet.tang.22000.json','["欲尋秋景閑行去，君病多慵我興孤。", "可惜今朝山最好，強能騎馬出來無。"]'),
('93ebcf21-bc20-41cb-98f5-d2852b7d84cf','晚秋有懷鄭中舊隱','白居易','唐','唐诗','tang','','[]','天高風嫋嫋，鄉思繞關河。',72,'全唐诗/poet.tang.22000.json','["天高風嫋嫋，鄉思繞關河。", "寥落歸山夢，殷勤采蕨歌。", "病添心寂寞，愁人鬢蹉跎。", "晚樹蟬鳴少，秋階日上多。", "長閑羨雲鶴，久別媿煙蘿。", "其奈丹墀上，君恩未報何。"]'),
('9e60181d-a16b-4261-89b7-a3814a52a107','禁中九日對菊花酒憶元九','白居易','唐','唐诗','tang','','[]','賜酒盈杯誰共持，宮花滿把獨相思。',32,'全唐诗/poet.tang.22000.json','["賜酒盈杯誰共持，宮花滿把獨相思。", "相思只傍花邊立，盡日吟君詠菊詩。"]'),
('9211f33e-c2d8-4c9a-850e-f148d5b6ec63','送王十八歸山寄題仙遊寺','白居易','唐','唐诗','tang','','[]','曾於太白峰前住，數到仙遊寺裏來。',64,'全唐诗/poet.tang.22000.json','["曾於太白峰前住，數到仙遊寺裏來。", "黑水澄時潭底出，白雲破處洞門開。", "林間暖酒燒紅葉，石上題詩埽綠苔。", "惆悵舊遊那復到，菊花時節羨君迴。"]'),
('ad6d44e4-08d7-4507-bc67-513d33273aed','荅張籍因以代書','白居易','唐','唐诗','tang','','[]','憐君馬瘦衣裘薄，許到江東訪鄙夫。',32,'全唐诗/poet.tang.22000.json','["憐君馬瘦衣裘薄，許到江東訪鄙夫。", "今日正閑天又暖，可能扶病暫來無。"]'),
('810e7992-aaa0-4676-9848-1b7ff4a07333','曲江早春','白居易','唐','唐诗','tang','','[]','曲江柳條漸無力，杏園伯勞初有聲。',32,'全唐诗/poet.tang.22000.json','["曲江柳條漸無力，杏園伯勞初有聲。", "可憐春淺遊人少，好傍池邊下馬行。"]'),
('66c455d9-b0a8-44fb-9d34-df66edb1171e','見元九悼亡詩因以此寄','白居易','唐','唐诗','tang','','[]','夜淚闇銷明月幌，春腸遙斷牡丹庭。',32,'全唐诗/poet.tang.22000.json','["夜淚闇銷明月幌，春腸遙斷牡丹庭。", "人間此病治無藥，唯有楞伽四卷經。"]'),
('d1e20b02-4a0a-4864-acbf-7eb7e2fab11b','寒食夜','白居易','唐','唐诗','tang','','[]','無月無燈寒食夜，夜深猶立闇花前。',32,'全唐诗/poet.tang.22000.json','["無月無燈寒食夜，夜深猶立闇花前。", "忽因時節驚年幾，四十如今欠一年。"]'),
('dc148eac-89de-40b6-bdd3-3fae742bb536','杏園花落時招錢員外同醉','白居易','唐','唐诗','tang','','[]','花園欲去去應遲，正是風吹狼藉時。',32,'全唐诗/poet.tang.22000.json','["花園欲去去應遲，正是風吹狼藉時。", "近西數樹猶堪醉，半落春風半在枝。"]'),
('5d69e95a-6ee3-49b9-9d30-a00d03946158','重題西明寺牡丹','白居易','唐','唐诗','tang','','[]','往年君向東都去，曾歎花時君未迴。',48,'全唐诗/poet.tang.22000.json','["往年君向東都去，曾歎花時君未迴。", "今年況作江陵別，惆悵花前又獨來。", "只愁離別長如此，不道明年花不開。"]'),
('237abf24-3eae-42ff-8635-fe4328a75036','同錢員外禁中夜直','白居易','唐','唐诗','tang','','[]','宮漏三聲知半夜，好風涼月滿松筠。',32,'全唐诗/poet.tang.22000.json','["宮漏三聲知半夜，好風涼月滿松筠。", "此時閑坐寂無語，藥樹影中唯兩人。"]'),
('d1269f80-9c23-43de-a977-5d35cc637c95','禁中夜作書與元九','白居易','唐','唐诗','tang','','[]','心緒萬端書兩紙，欲封重讀意遲遲。',32,'全唐诗/poet.tang.22000.json','["心緒萬端書兩紙，欲封重讀意遲遲。", "五聲宮漏初鳴夜，一點窗燈欲滅時。"]'),
('d7a3e012-1956-42e6-ab05-24207d568992','八月十五日夜禁中獨直對月憶元九','白居易','唐','唐诗','tang','','[]','銀臺金闕夕沈沈，獨宿相思在翰林。',64,'全唐诗/poet.tang.22000.json','["銀臺金闕夕沈沈，獨宿相思在翰林。", "三五夜中新月色，二千里外故人心。", "渚宮東面煙波冷，浴殿西頭鐘漏深。", "猶恐清光不同見，江陵卑濕足秋陰。"]'),
('bb03ba1f-cc1e-445d-b75e-e8858f7cc432','寄陳式五兄','白居易','唐','唐诗','tang','','[]','年來白髮兩三莖，憶別君時髭未生。',32,'全唐诗/poet.tang.22000.json','["年來白髮兩三莖，憶別君時髭未生。", "惆悵料君應滿鬢，當初是我十年兄。"]'),
('60813964-f20e-4f14-82cd-61da369ce91b','庾順之以紫霞綺遠贈以詩荅之','白居易','唐','唐诗','tang','','[]','千里故人心鄭重，一端香綺紫氛氳。',64,'全唐诗/poet.tang.22000.json','["千里故人心鄭重，一端香綺紫氛氳。", "開緘日映晚霞色，滿幅風生秋水紋。", "爲褥欲裁憐葉破，製裘將翦惜花分。", "不如縫作合歡被，寤寐相思如對君。"]'),
('1f618883-3dab-44ee-8ed4-aba84facac67','送元八歸鳳翔','白居易','唐','唐诗','tang','','[]','莫道岐州三日程，其如風雪一身行。',32,'全唐诗/poet.tang.22000.json','["莫道岐州三日程，其如風雪一身行。", "與君況是經年別，暫到城來又出城。"]'),
('3dd3f276-ac7e-4025-aba2-0df7fab25f24','雨雪放朝因懷微之','白居易','唐','唐诗','tang','','[]','歸騎紛紛滿九衢，放朝三日爲泥塗。',32,'全唐诗/poet.tang.22000.json','["歸騎紛紛滿九衢，放朝三日爲泥塗。", "不知雨雪江陵府，今日排衙得免無。"]'),
('0e295054-0f2f-4982-aaec-366ca9202f5a','詠懷','白居易','唐','唐诗','tang','','[]','歲去年來塵土中，眼看變作白頭翁。',32,'全唐诗/poet.tang.22000.json','["歲去年來塵土中，眼看變作白頭翁。", "如何辦得歸山計，兩頃村田一畝宮。"]'),
('58f17350-f21c-4d9e-948e-43b46bd16ff8','聞微之江陵臥病以大通中散碧腴垂雲膏寄之因題四韻','白居易','唐','唐诗','tang','','[]','已題一帖紅消散，又封一合碧雲英。',64,'全唐诗/poet.tang.22000.json','["已題一帖紅消散，又封一合碧雲英。", "憑人寄向江陵去，道路迢迢一月程。", "未必能治江上瘴，且圖遙慰病中情。", "到時想得君拈得，枕上開看眼暫明。"]'),
('168419ec-0b03-4000-90f7-1c43149728b8','酬錢員外雪中見寄','白居易','唐','唐诗','tang','','[]','松雪無塵小院寒，閉門不似住長安。',32,'全唐诗/poet.tang.22000.json','["松雪無塵小院寒，閉門不似住長安。", "煩君想我看心坐，報道心空無可看。"]'),
('0cc4af70-5655-44db-8511-53517c42fc7f','重酬錢員外','白居易','唐','唐诗','tang','','[]','雪中重寄雪山偈，問荅殷勤四句中。',32,'全唐诗/poet.tang.22000.json','["雪中重寄雪山偈，問荅殷勤四句中。", "本立空名緣破妄，若能無妄亦無空。"]'),
('2afa5cca-9319-411f-ad72-11e5a11e97c9','獨酌憶微之','白居易','唐','唐诗','tang','','[]','獨酌花前醉憶君，與君春別又逢春。',32,'全唐诗/poet.tang.22000.json','["獨酌花前醉憶君，與君春別又逢春。", "惆悵銀杯來處重，不曾盛酒勸閑人。"]'),
('80edff94-1b97-4690-b151-cb189f6dc5d2','微之宅殘牡丹','白居易','唐','唐诗','tang','','[]','殘紅零落無人賞，雨打風摧花不全。',32,'全唐诗/poet.tang.22000.json','["殘紅零落無人賞，雨打風摧花不全。", "諸處見時猶悵望，況當元九小亭前。"]'),
('3aa297dc-1cd5-42cf-816f-c6aab12dc017','新磨鏡','白居易','唐','唐诗','tang','','[]','衰容常晚櫛，秋鏡偶新磨。',48,'全唐诗/poet.tang.22000.json','["衰容常晚櫛，秋鏡偶新磨。", "一與清光對，方知白髮多。", "鬢毛從幻化，心地付頭陀。", "任意渾成雪，其如似夢何。"]'),
('c073e464-17fb-4dd6-8ccc-f35b4e08a873','感髮落','白居易','唐','唐诗','tang','','[]','昔日愁頭白，誰知未白衰。',24,'全唐诗/poet.tang.22000.json','["昔日愁頭白，誰知未白衰。", "眼看應落盡，無可變成絲。"]'),
('061aed4b-2f05-4e1d-9ab1-ac0b57b8eece','八月十五日夜聞崔大員外翰林獨直對酒玩月因懷禁中清景偶題是詩','白居易','唐','唐诗','tang','','[]','秋月高懸空碧外，仙郎靜玩禁闈間。',64,'全唐诗/poet.tang.22000.json','["秋月高懸空碧外，仙郎靜玩禁闈間。", "歲中唯有今宵好，海內無如此地閑。", "皓色分明雙闕牓，清光深到九門關。", "遙聞獨醉還惆悵，不見金波照玉山。"]'),
('f020464b-af2d-427b-b387-c5bd01b9cd25','酬王十八見寄','白居易','唐','唐诗','tang','','[]','秋思太白峰頭雪，晴憶仙遊洞口雲。',32,'全唐诗/poet.tang.22000.json','["秋思太白峰頭雪，晴憶仙遊洞口雲。", "未報皇恩歸未得，慙君爲寄北山文。"]'),
('f9ca7e25-5fb0-40ed-a1ff-8d35cc5bf2e4','立春日酬錢員外曲江同行見贈','白居易','唐','唐诗','tang','','[]','下直遇春日，垂鞭出禁闈。',60,'全唐诗/poet.tang.22000.json','["下直遇春日，垂鞭出禁闈。", "兩人攜手語，十里看山歸。", "柳色早黃淺，水文新綠微。", "風光向晚好，車馬近南稀。", "機盡笑相顧，不驚鷗鷺飛。"]'),
('1e155564-60d5-46eb-9b84-f03368126ec5','和錢員外青龍寺上方望舊山','白居易','唐','唐诗','tang','','[]','舊峰松雪舊溪雲，悵望今朝遙屬君。',32,'全唐诗/poet.tang.22000.json','["舊峰松雪舊溪雲，悵望今朝遙屬君。", "共道使臣非俗吏，南山莫動北山文。"]'),
('0c64ae43-ddd2-48e6-8869-a1ba18943260','宴周皓大夫光福宅','白居易','唐','唐诗','tang','','[]','何處風光最可憐？妓堂階下砌臺前。',64,'全唐诗/poet.tang.22000.json','["何處風光最可憐？妓堂階下砌臺前。", "軒車擁路光照地，絲管入門聲沸天。", "綠蕙不香饒桂酒，紅櫻無色讓花鈿。", "野人不敢求他事，唯借泉聲伴醉眠。"]'),
('05fb5739-287d-4a55-9fc3-3c857d72392d','晚秋夜','白居易','唐','唐诗','tang','','[]','碧空溶溶月華靜，月裏愁人弔孤影。',64,'全唐诗/poet.tang.22000.json','["碧空溶溶月華靜，月裏愁人弔孤影。", "花開殘菊傍疎籬，葉下衰桐落寒井。", "塞鴻飛急覺秋盡，鄰雞鳴遲知夜永。", "凝情不語空所思，風吹白露衣裳冷。"]'),
('e83e9a4d-282b-4ef9-bda7-c727c4060380','惜牡丹花二首 一','白居易','唐','唐诗','tang','','[]','惆悵階前紅牡丹，晚來唯有兩枝殘。',32,'全唐诗/poet.tang.22000.json','["惆悵階前紅牡丹，晚來唯有兩枝殘。", "明朝風起應吹盡，夜惜衰紅把火看。"]'),
('71d54a43-afd1-4ac2-8e8b-573056da74b4','惜牡丹花二首 二','白居易','唐','唐诗','tang','','[]','寂寞萎紅低向雨，離披破豔散隨風。',32,'全唐诗/poet.tang.22000.json','["寂寞萎紅低向雨，離披破豔散隨風。", "晴明落地猶惆悵，何況飄零泥土中。"]'),
('678d05bd-b9e7-4ecc-be6e-91dc7b26f5d7','荅元奉禮同宿見贈','白居易','唐','唐诗','tang','','[]','相逢俱歎不閑身，直日常多齋日頻。',32,'全唐诗/poet.tang.22000.json','["相逢俱歎不閑身，直日常多齋日頻。", "曉鼓一聲分散去，明朝風景屬何人。"]'),
('2749a3bb-d308-4291-838d-3e98da7d4d18','荅馬侍御見贈','白居易','唐','唐诗','tang','','[]','謬入金門侍玉除，煩君問我意何如。',64,'全唐诗/poet.tang.22000.json','["謬入金門侍玉除，煩君問我意何如。", "蟠木詎堪明主用，籠禽徒與故人疎。", "苑花似雪同隨輦，宮月如眉伴直廬。", "淺薄求賢思自代，嵇康莫寄絕交書。"]'),
('a2a7ff16-70cf-41c1-9c92-98d72b43c6db','上巳日恩賜曲江宴會即事','白居易','唐','唐诗','tang','','[]','賜歡仍許醉，此會興如何。',48,'全唐诗/poet.tang.22000.json','["賜歡仍許醉，此會興如何。", "翰苑主恩重，曲江春意多。", "花低羞豔妓，鶯散讓清歌。", "共道升平樂，元和勝永和。"]'),
('1ed8894d-ed56-44de-a0f9-3808db91c8b9','夜惜禁中桃花因懷錢員外','白居易','唐','唐诗','tang','','[]','前日歸時花正紅，今夜宿時枝半空。',32,'全唐诗/poet.tang.22000.json','["前日歸時花正紅，今夜宿時枝半空。", "坐惜殘芳君不見，風吹狼藉月明中。"]'),
('c0b9984d-eb82-4994-9aeb-dd578cf8b3c1','和錢員外早冬玩禁中新菊','白居易','唐','唐诗','tang','','[]','禁署寒氣遲，孟冬菊初坼。',120,'全唐诗/poet.tang.22000.json','["禁署寒氣遲，孟冬菊初坼。", "新黃間繁綠，爛若金照碧。", "仙郎小隱日，心似陶彭澤。", "秋憐潭上看，日慣籬邊摘。", "今來此地賞，野意潛自適。", "金馬門內花，玉山峰下客。", "寒芳引清句，吟玩煙景夕。", "賜酒色偏宜，握蘭香不敵。", "淒淒百卉死，歲晚冰霜積。", "唯有此花開，殷勤助君惜。"]'),
('c21e797c-469b-4909-80cf-f6fe2458feda','荅劉戒之早秋別墅見寄','白居易','唐','唐诗','tang','','[]','涼風木槿籬，暮雨槐花枝。',48,'全唐诗/poet.tang.22000.json','["涼風木槿籬，暮雨槐花枝。", "幷起新秋思，爲得故人詩。", "避地鳥擇木，升朝魚在池。", "城中與山下，喧靜闇相思。"]'),
('31dd1e86-b1d5-4d84-ad33-ebde3ef0797b','涼夜有懷','白居易','唐','唐诗','tang','','[]','念別感時節，早蛩聞一聲。',48,'全唐诗/poet.tang.22000.json','["念別感時節，早蛩聞一聲。", "風簾夜涼入，露簟秋意生。", "燈盡夢初罷，月斜天未明。", "闇凝無限思，起傍藥闌行。"]'),
('1e68e524-df00-42f5-b814-57d93ec727fc','秋思','白居易','唐','唐诗','tang','','[]','病眠夜少夢，閑立秋多思。',48,'全唐诗/poet.tang.22000.json','["病眠夜少夢，閑立秋多思。", "寂寞餘雨晴，蕭條早寒至。", "鳥棲紅葉樹，月照青苔地。", "何況鏡中年，又過三十二。"]'),
('b900a74d-2082-4cf9-aee9-c41bb05d5bff','禁中聞蛩','白居易','唐','唐诗','tang','','[]','悄悄禁門閉，夜深無月明。',24,'全唐诗/poet.tang.22000.json','["悄悄禁門閉，夜深無月明。", "西窗獨闇坐，滿耳新蛩聲。"]'),
('541e3c1f-effb-4dbb-ab37-04ce524a2c63','秋蟲','白居易','唐','唐诗','tang','','[]','切切闇窗下，喓喓深草裏。',24,'全唐诗/poet.tang.22000.json','["切切闇窗下，喓喓深草裏。", "秋天思婦心，雨夜愁人耳。"]'),
('46926d08-c875-4ec0-9046-b6d92348be06','贈別宣上人','白居易','唐','唐诗','tang','','[]','上人處世界，清淨何所似。',72,'全唐诗/poet.tang.22000.json','["上人處世界，清淨何所似。", "似彼白蓮花，在水不著水。", "性真悟泡幻，行潔離塵滓。", "修道來幾時，身心俱到此。", "嗟余牽世網，不得長依止。", "離念與碧雲，秋來朝夕起。"]'),
('8a090e29-02a0-4fcb-bf13-81f883cc0333','春夜喜雪有懷王二十二','白居易','唐','唐诗','tang','','[]','夜雪有佳趣，幽人出書帷。',72,'全唐诗/poet.tang.22000.json','["夜雪有佳趣，幽人出書帷。", "微寒生枕席，輕素對階墀。", "坐罷楚弦曲，起吟班扇詩。", "明宜滅燭後，淨愛褰簾時。", "窗引曙色早，庭銷春氣遲。", "山陰應有興，不臥待徽之。"]'),
('1c3d1b9e-3000-479f-b207-767d3b454a49','酬和元九東川路詩十二首 駱口驛舊題詩','白居易','唐','唐诗','tang','','[]','拙詩在壁無人愛，鳥汙苔侵文字殘。',32,'全唐诗/poet.tang.22000.json','["拙詩在壁無人愛，鳥汙苔侵文字殘。", "唯有多情元侍御，繡衣不惜拂塵看。"]'),
('61191841-79c3-4581-b277-e245d174330a','酬和元九東川路詩十二首 南秦雪','白居易','唐','唐诗','tang','','[]','往歲曾爲西邑吏，慣從駱口到南秦。',64,'全唐诗/poet.tang.22000.json','["往歲曾爲西邑吏，慣從駱口到南秦。", "三時雲冷多飛雪，二月山寒少有春。", "我思舊事猶惆悵，君作初行定苦辛。", "任賴愁猨寒不叫，若聞猨叫更愁人。"]'),
('34e6c28b-edf5-40c5-83ff-2fd911f2b82d','酬和元九東川路詩十二首 山枇杷花二首 一','白居易','唐','唐诗','tang','','[]','萬重青嶂蜀門口，一樹紅花山頂頭。',32,'全唐诗/poet.tang.22000.json','["萬重青嶂蜀門口，一樹紅花山頂頭。", "春盡憶家歸未得，低紅如解替君愁。"]'),
('3175c3bc-7ec2-40fc-bd98-793d82d2a756','酬和元九東川路詩十二首 山枇杷花二首 二','白居易','唐','唐诗','tang','','[]','葉如帬色碧綃淺，花似芙蓉紅粉輕。',32,'全唐诗/poet.tang.22000.json','["葉如帬色碧綃淺，花似芙蓉紅粉輕。", "若使此花兼解語，推囚御史定違程。"]'),
('477251d1-3976-40b6-9608-17f02f63f982','酬和元九東川路詩十二首 江樓月','白居易','唐','唐诗','tang','','["\u601d\u5ff5", "\u6708\u4eae", "\u8d60\u7b54", "\u53cb\u60c5"]','嘉陵江曲曲江池，明月雖同人別離。',64,'全唐诗/poet.tang.22000.json','["嘉陵江曲曲江池，明月雖同人別離。", "一宵光景潛相憶，兩地陰晴遠不知。", "誰料江邊懷我夜，正當池畔望君時。", "今朝共語方同悔，不解多情先寄詩。"]'),
('672dab59-f65f-41c4-9164-4625eaf02569','酬和元九東川路詩十二首 亞枝花','白居易','唐','唐诗','tang','','[]','山郵花木似平陽，愁殺多情驄馬郎。',32,'全唐诗/poet.tang.22000.json','["山郵花木似平陽，愁殺多情驄馬郎。", "還似升平池畔坐，低頭向水自看妝。"]'),
('29ad18a2-cbb9-4fbe-97ea-690c9ca3edd0','酬和元九東川路詩十二首 江上笛','白居易','唐','唐诗','tang','','[]','江上何人夜吹笛，聲聲似憶故園春。',32,'全唐诗/poet.tang.22000.json','["江上何人夜吹笛，聲聲似憶故園春。", "此時聞者堪頭白，況是多愁少睡人。"]'),
('67256052-e19b-4ad7-a021-14d4cffec23d','酬和元九東川路詩十二首 嘉陵夜有懷二首 一','白居易','唐','唐诗','tang','','[]','露濕牆花春意深，西廊月上半牀陰。',32,'全唐诗/poet.tang.22000.json','["露濕牆花春意深，西廊月上半牀陰。", "憐君獨臥無言語，唯我知君此夜心。"]'),
('3ef7a0df-7c1d-4967-9141-b5d8f7e9a888','酬和元九東川路詩十二首 嘉陵夜有懷二首 二','白居易','唐','唐诗','tang','','[]','不明不暗朧朧月，不暖不寒慢慢風。',32,'全唐诗/poet.tang.22000.json','["不明不暗朧朧月，不暖不寒慢慢風。", "獨臥空牀好天氣，平明閑事到心中。"]'),
('646d1c95-6805-4ab4-8bed-2ddb7166b852','酬和元九東川路詩十二首 夜深行','白居易','唐','唐诗','tang','','[]','百牢關外夜行客，三殿角頭宵直人。',32,'全唐诗/poet.tang.22000.json','["百牢關外夜行客，三殿角頭宵直人。", "莫道近臣勝遠使，其如同是不閑身。"]'),
('9a37babb-d94a-4b9c-8aeb-1d5245acfcf7','酬和元九東川路詩十二首 望驛臺','白居易','唐','唐诗','tang','','["\u601d\u5ff5", "\u548c\u8bd7"]','靖安宅裏當窗柳，望驛臺前撲地花。',32,'全唐诗/poet.tang.22000.json','["靖安宅裏當窗柳，望驛臺前撲地花。", "兩處春光同日盡，居人思客客思家。"]'),
('d18a2679-38bc-4848-9947-d7e1d00d1177','酬和元九東川路詩十二首 江岸棃花','白居易','唐','唐诗','tang','','[]','棃花有思緣和葉，一樹江頭惱殺君。',32,'全唐诗/poet.tang.22000.json','["棃花有思緣和葉，一樹江頭惱殺君。", "最似孀閨少年婦，白妝素袖碧紗帬。"]'),
('6b6dd3c8-5a26-42e9-b7b9-6e76417d272e','荅謝家最小偏憐女','白居易','唐','唐诗','tang','','[]','嫁得梁鴻六七年，耽書愛酒日高眠。',64,'全唐诗/poet.tang.22000.json','["嫁得梁鴻六七年，耽書愛酒日高眠。", "雨荒春圃唯生草，雪壓朝廚未有煙。", "身病憂來緣女少，家貧忘却爲夫賢。", "誰知厚俸今無分，枉向秋風吹紙錢。"]'),
('cb1e8fc9-d00c-4345-9b84-026690c754a8','荅騎馬入空臺','白居易','唐','唐诗','tang','','[]','君入空臺去，朝往暮還來。',48,'全唐诗/poet.tang.22000.json','["君入空臺去，朝往暮還來。", "我入泉臺去，泉門無復開。", "鰥夫任繫職，穉女未勝哀。", "寂寞咸陽道，家人覆墓迴。"]'),
('962a4569-cf4c-46d6-9c9b-eab27dd17a82','荅山驛夢','白居易','唐','唐诗','tang','','[]','入君旅夢來千里，閉我幽魂欲二年。',32,'全唐诗/poet.tang.22000.json','["入君旅夢來千里，閉我幽魂欲二年。", "莫忘平生行坐處，後堂階下竹叢前。"]'),
('dbe56a89-b1ec-4a18-b330-e2dfd68fec8d','和元九與呂二同宿話舊感贈','白居易','唐','唐诗','tang','','[]','見君新贈呂君詩，憶得同年行樂時。',64,'全唐诗/poet.tang.22000.json','["見君新贈呂君詩，憶得同年行樂時。", "爭入杏園齊馬首，潛過柳曲鬬蛾眉。", "八人雲散俱遊宦，七度花開盡別離。", "聞道秋娘猶且在，至今時復問微之。"]'),
('aec0c03f-0f29-48f2-b0c2-8f50a3e5e02a','憶元九','白居易','唐','唐诗','tang','','[]','渺渺江陵道，相思遠不知。',24,'全唐诗/poet.tang.22000.json','["渺渺江陵道，相思遠不知。", "近來文卷裏，半是憶君詩。"]'),
('545f574e-4691-4405-bc8d-5c9adda64210','蕭員外寄新蜀茶','白居易','唐','唐诗','tang','','[]','蜀茶寄到但驚新，渭水煎來始覺珍。',32,'全唐诗/poet.tang.22000.json','["蜀茶寄到但驚新，渭水煎來始覺珍。", "滿甌似乳堪持玩，況是春深酒渴人。"]'),
('dacdc367-9262-445f-a5a5-634a588f4b0a','寄上大兄','白居易','唐','唐诗','tang','','[]','秋鴻過盡無書信，病戴紗巾強出門。',32,'全唐诗/poet.tang.22000.json','["秋鴻過盡無書信，病戴紗巾強出門。", "獨上荒臺東北望，日西愁立到黃昏。"]'),
('ea2ed339-839d-42c8-8308-40cdb8b81340','病中哭金鑾子','白居易','唐','唐诗','tang','','[]','豈料吾方病，飜悲汝不全。',96,'全唐诗/poet.tang.22000.json','["豈料吾方病，飜悲汝不全。", "臥驚從枕上，扶哭就燈前。", "有女誠爲累，無兒豈免憐。", "病來纔十日，養得已三年。", "慈淚隨聲迸，悲腸遇物牽。", "故衣猶架上，殘藥尚頭邊。", "送出深村巷，看封小墓田。", "莫言三里地，此別是終天。"]'),
('4fe5fc01-e66d-47f3-a2d8-56a2852b71f3','寄內','白居易','唐','唐诗','tang','','[]','條桑初綠即爲別，柿葉半紅猶未歸。',32,'全唐诗/poet.tang.22000.json','["條桑初綠即爲別，柿葉半紅猶未歸。", "不如村婦知時節，解爲田夫秋擣衣。"]'),
('757aa868-d91a-4848-8cee-0e4ec35309f2','病氣','白居易','唐','唐诗','tang','','[]','自知氣發每因情，情在何由氣得平。',32,'全唐诗/poet.tang.22000.json','["自知氣發每因情，情在何由氣得平。", "若問病根深與淺，此身應與病齊生。"]'),
('7bb58119-41a8-4c01-a673-ceeb9c5ed42e','歎元九','白居易','唐','唐诗','tang','','[]','不入城門來五載，同時班列盡官高。',32,'全唐诗/poet.tang.22000.json','["不入城門來五載，同時班列盡官高。", "何人牢落猶依舊，唯有江陵元士曹。"]'),
('855553e3-68e3-444a-b89a-b687b71b0bd5','眼暗','白居易','唐','唐诗','tang','','[]','早年勤倦看書苦，晚歲悲傷出淚多。',64,'全唐诗/poet.tang.22000.json','["早年勤倦看書苦，晚歲悲傷出淚多。", "眼損不知都自取，病成方悟欲如何。", "夜昏乍似燈將滅，朝闇長疑鏡未磨。", "千藥萬方治不得，唯應閉目學頭陀。"]'),
('81b32163-af3c-4af8-a7dc-45f931a0b7f4','得袁相書','白居易','唐','唐诗','tang','','[]','穀苗深處一農夫，面黑頭斑手把鋤。',32,'全唐诗/poet.tang.22000.json','["穀苗深處一農夫，面黑頭斑手把鋤。", "何意使人猶識我，就田來送相公書。"]'),
('ab8d7d5d-64a8-4cf5-82b3-f1aa59a12555','病中作','白居易','唐','唐诗','tang','','[]','病來城裏諸親故，厚薄親疎心總知。',32,'全唐诗/poet.tang.22000.json','["病來城裏諸親故，厚薄親疎心總知。", "唯有蔚章於我分，深於同在翰林時。"]'),
('9a9d07b6-8d5c-47b6-a3ce-4f4a27c8e054','感化寺見元九劉三十二題名處','白居易','唐','唐诗','tang','','[]','微之謫去千餘里，太白無來十一年。',32,'全唐诗/poet.tang.22000.json','["微之謫去千餘里，太白無來十一年。", "今日見名如見面，塵埃壁上破窗前。"]'),
('bdedbda3-e775-4341-a995-c2f712ef2fa0','遊悟貞寺迴山下別張殷衡','白居易','唐','唐诗','tang','','[]','世緣未了治不得，孤負青山心共知。',32,'全唐诗/poet.tang.22000.json','["世緣未了治不得，孤負青山心共知。", "愁君又入都門去，即是紅塵滿眼時。"]'),
('c2dacec8-ad5a-4397-93f6-9be8b148ed88','村居寄張殷衡','白居易','唐','唐诗','tang','','[]','金氏村中一病夫，生涯濩落性靈迂。',64,'全唐诗/poet.tang.22000.json','["金氏村中一病夫，生涯濩落性靈迂。", "唯看老子五千字，不蹋長安十二衢。", "藥銚夜傾殘酒煖，竹牀寒取舊氈鋪。", "聞君欲發江東去，能到茅菴訪別無。"]'),
('c1ffddc0-f4f6-4aa0-921d-e644cd8586a9','病中得樊大書','白居易','唐','唐诗','tang','','[]','荒村破屋經年臥，寂絕無人問病身。',32,'全唐诗/poet.tang.22000.json','["荒村破屋經年臥，寂絕無人問病身。", "唯有東都樊著作，至今書信尚殷勤。"]'),
('0d9b8943-8400-4fa7-8554-bdad9369db40','開元九詩書卷','白居易','唐','唐诗','tang','','[]','紅牋白紙兩三束，半是君詩半是書。',32,'全唐诗/poet.tang.22000.json','["紅牋白紙兩三束，半是君詩半是書。", "經年不展緣身病，今日開看生蠹魚。"]'),
('04a7b4e6-59dd-4023-8018-466431aaebb0','晝臥','白居易','唐','唐诗','tang','','[]','抱枕無言語，空房獨悄然。',24,'全唐诗/poet.tang.22000.json','["抱枕無言語，空房獨悄然。", "誰知盡日臥，非病亦非眠。"]'),
('18690e89-2a93-496e-aa8e-954c8c17641b','夜坐','白居易','唐','唐诗','tang','','[]','庭前盡日立到夜，燈下有時坐徹明。',32,'全唐诗/poet.tang.22000.json','["庭前盡日立到夜，燈下有時坐徹明。", "此情不語何人會，時復長吁一兩聲。"]'),
('e2630277-c246-4a08-8bc4-7e1db4695059','暮立','白居易','唐','唐诗','tang','','[]','黃昏獨立佛堂前，滿地槐花滿樹蟬。',32,'全唐诗/poet.tang.22000.json','["黃昏獨立佛堂前，滿地槐花滿樹蟬。", "大抵四時心總苦，就中腸斷是秋天。"]'),
('f8f0943a-9e1e-4606-93c0-9763779182f7','有感','白居易','唐','唐诗','tang','','[]','絕弦與斷絲，猶有却續時。',24,'全唐诗/poet.tang.22000.json','["絕弦與斷絲，猶有却續時。", "唯有衷腸斷，應無續得期。"]'),
('18715080-bdbd-43eb-9fea-f560bbbeef89','荅友問','白居易','唐','唐诗','tang','','[]','似玉童顏盡，如霜病鬢新。',24,'全唐诗/poet.tang.22000.json','["似玉童顏盡，如霜病鬢新。", "莫驚身頓老，心更老於身。"]'),
('a96bc1fc-868d-474d-abca-1b025afdb009','村夜','白居易','唐','唐诗','tang','','["\u4e61\u6751", "\u5199\u666f", "\u519c\u6751"]','霜草蒼蒼蟲切切，村南村北行人絕。',32,'全唐诗/poet.tang.22000.json','["霜草蒼蒼蟲切切，村南村北行人絕。", "獨出前門望野田，月明蕎麥花如雪。"]'),
('316b68e4-1b43-4f0c-8ec2-ed129d5c9c50','聞蟲','白居易','唐','唐诗','tang','','["\u79cb\u5929", "\u52a8\u7269"]','暗蟲唧唧夜緜緜，況是秋陰欲雨天。',32,'全唐诗/poet.tang.22000.json','["暗蟲唧唧夜緜緜，況是秋陰欲雨天。", "猶恐愁人暫得睡，聲聲移近臥牀前。"]'),
('0fe6a34b-55c3-4fde-bcdc-7288d9ad79dc','寒食夜有懷','白居易','唐','唐诗','tang','','[]','寒食非長非短夜，春風不熱不寒天。',32,'全唐诗/poet.tang.22000.json','["寒食非長非短夜，春風不熱不寒天。", "可憐時節堪相憶，何況無燈各早眠。"]'),
('eeb942b6-d854-4a2b-bcee-a40f98f6edef','贈內','白居易','唐','唐诗','tang','','[]','漠漠闇苔新雨地，微微涼露欲秋天。',32,'全唐诗/poet.tang.22000.json','["漠漠闇苔新雨地，微微涼露欲秋天。", "莫對月明思往事，損君顏色減君年。"]'),
('cf51e6fa-a589-4cfc-a7da-8f061e486a7a','得錢舍人書問眼疾','白居易','唐','唐诗','tang','','[]','春來眼闇少心情，點盡黃連尚未平。',32,'全唐诗/poet.tang.22000.json','["春來眼闇少心情，點盡黃連尚未平。", "唯得君書勝得藥，開緘未讀眼先明。"]'),
('5108300b-1703-4db4-82c5-35ef128de98e','還李十一馬','白居易','唐','唐诗','tang','','[]','傳語李君勞寄馬，病來唯著杖扶身。',32,'全唐诗/poet.tang.22000.json','["傳語李君勞寄馬，病來唯著杖扶身。", "縱擬強騎無出處，却將牽與趁朝人。"]'),
('3e373015-8104-41e0-b4ee-d72649428998','九日寄行簡','白居易','唐','唐诗','tang','','[]','摘得菊花攜得酒，繞村騎馬思悠悠。',32,'全唐诗/poet.tang.22000.json','["摘得菊花攜得酒，繞村騎馬思悠悠。", "下邽田地平如掌，何處登髙望梓州。"]'),
('c64e239f-b458-4bee-b583-cf0dab072906','夜坐','白居易','唐','唐诗','tang','','[]','斜月入前楹，迢迢夜坐情。',48,'全唐诗/poet.tang.22000.json','["斜月入前楹，迢迢夜坐情。", "梧桐上階影，蟋蟀近牀聲。", "曙傍窗間至，秋從簟上生。", "感時因憶事，不寢到雞鳴。"]'),
('e6846795-96aa-42c2-b51d-d0a3ce349f37','村居二首 一','白居易','唐','唐诗','tang','','[]','田園莽蒼經春早，籬落蕭條盡日風。',32,'全唐诗/poet.tang.22000.json','["田園莽蒼經春早，籬落蕭條盡日風。", "若問經過談笑者，不過田舍白頭翁。"]'),
('62a6abfc-070a-40ac-8e3a-e4678b9661e1','村居二首 二','白居易','唐','唐诗','tang','','[]','門閉仍逢雪，廚寒未起煙。',24,'全唐诗/poet.tang.22000.json','["門閉仍逢雪，廚寒未起煙。", "貧家重寥落，半爲日高眠。"]'),
('56434984-cb41-42c9-977e-9d030b9dd7c3','早春','白居易','唐','唐诗','tang','','["\u5199\u96ea", "\u6292\u60c5", "\u6101\u7eea", "\u96ea"]','雪散因和氣，冰開得暖光。',24,'全唐诗/poet.tang.22000.json','["雪散因和氣，冰開得暖光。", "春銷不得處，唯有鬢邊霜。"]'),
('1c084d0f-76cc-4294-bd80-4e8672338d39','和夢遊春詩一百韻','白居易','唐','唐诗','tang','','[]','昔君夢遊春，夢遊仙山曲。',288,'全唐诗/poet.tang.22000.json','["昔君夢遊春，夢遊仙山曲。", "怳若有所遇，似愜平生欲。", "因尋菖蒲水，漸入桃花谷。", "到一紅樓家，愛之看不足。", "池流渡清泚，草嫩蹋綠蓐。", "門柳闇全低，檐櫻紅半熟。", "轉行深深院，過盡重重屋。", "烏龍臥不驚，青鳥飛相逐。", "漸聞玉珮響，始辨珠履躅。", "遙見窗下人，娉婷十五六。", "霞光抱明月，蓮豔開初旭。", "縹緲雲雨仙，氛氳蘭麝馥。", "風流薄梳洗，時世寬妝束。", "袖輭異文綾，裾輕單絲縠。", "裙腰銀線壓，梳掌金筐蹙。", "帶襭紫蒲萄，袴花紅石竹。", "凝情都未語，付意微相矚。", "眉斂遠山青，鬟低片雲綠。", "帳牽翡翠帶，被解鴛鴦襆。", "秀色似堪餐，穠華如可掬。", "半卷錦頭席，斜鋪繡腰褥。", "朱脣素指勻，粉汗紅緜撲。", "心驚睡易覺，夢斷魂難續。", "籠委獨棲禽，劒分連理木。"]'),
('1705bb19-c6ff-40e2-be8f-4a9475b2ffc0','王昭君二首 一','白居易','唐','唐诗','tang','','[]','滿面胡沙滿鬢風，眉銷殘黛臉銷紅。',32,'全唐诗/poet.tang.22000.json','["滿面胡沙滿鬢風，眉銷殘黛臉銷紅。", "愁苦辛勤顦顇盡，如今却似畫圖中。"]'),
('5a3a31d1-2ebc-47b3-ba5b-38a6553a68d1','王昭君二首 二','白居易','唐','唐诗','tang','','[]','漢使却回憑寄語，黃金何日贖蛾眉。',32,'全唐诗/poet.tang.22000.json','["漢使却回憑寄語，黃金何日贖蛾眉。", "君王若問妾顏色，莫道不知宮裏時。"]'),
('a2fcac42-d89b-45b0-ad1b-a785a9b9a9cf','渭村退居寄禮部崔侍郎翰林錢舍人詩一百韻','白居易','唐','唐诗','tang','','[]','聖代元和歲，閑居渭水陽。',288,'全唐诗/poet.tang.22000.json','["聖代元和歲，閑居渭水陽。", "不才甘命舛，多幸遇時康。", "朝野分倫序，賢愚定否臧。", "重文疎卜式，尚少棄馮唐。", "由是推天運，從茲樂性場。", "籠禽放高翥，霧豹得深藏。", "世慮休相擾，身謀且自強。", "猶須務衣食，未免事農桑。", "薙草通三徑，開田占一坊。", "晝扉扃白版，夜碓埽黃粱。", "隙地治場圃，閑時糞土疆。", "枳籬編刺夾，薤壟擘科秧。", "穡力嫌身病，農心願歲穰。", "朝衣典杯酒，佩劒博牛羊。", "困倚栽松鍤，飢提采蕨筐。", "引泉來後澗，移竹下前岡。", "生計雖勤苦，家資甚渺茫。", "塵埃常滿甑，錢帛少盈囊。", "弟病仍扶杖，妻愁不出房。", "傳衣念繿縷，舉案笑糟糠。", "犬吠村胥鬧，蟬鳴織婦忙。", "納租看縣貼，輸粟問軍倉。", "夕歇攀村樹，秋行繞野塘。", "雲容陰慘澹，月色冷悠揚。"]'),
('3aabefe5-fd34-4382-a15f-2af4412f7749','酬盧祕書二十韻','白居易','唐','唐诗','tang','','[]','謬歷文場選，慙非翰苑才。',240,'全唐诗/poet.tang.22000.json','["謬歷文場選，慙非翰苑才。", "雲霄高暫致，毛羽弱先摧。", "識分忘軒冕，知歸返草萊。", "杜陵書積蠹，豐獄劒生苔。", "晦厭鳴雞雨，春驚震蟄雷。", "舊恩收墜履，新律動寒灰。", "鳳詔容徐起，鵷行許重陪。", "衰顏雖拂拭，蹇步尚低徊。", "睡少鐘偏警，行遲漏苦摧。", "風霜趁朝去，泥雪拜陵迴。", "上感君猶念，傍慙友或推。", "石頑鐫費匠，女醜嫁勞媒。", "倏忽青春度，奔波白日頹。", "性將時共背，病與老俱來。", "聞有蓬壺客，知懷杞梓材。", "世家標甲第，官職滯麟臺。", "筆盡鉛黃點，詩成錦繡堆。", "嘗思豁雲霧，忽喜訪塵埃。", "心爲論文合，眉因勸善開。", "不勝珍重意，滿袖寫瓊瓌。"]'),
('9df347d9-fda4-43fc-bd6d-285d8e325cba','題盧祕書夏日新栽竹二十韻','白居易','唐','唐诗','tang','','[]','湘竹初封植，盧生此考槃。',240,'全唐诗/poet.tang.22000.json','["湘竹初封植，盧生此考槃。", "久持霜節苦，新託露根難。", "等度須當砌，疎稠要滿闌。", "買憐分薄俸，栽稱作閑官。", "葉翦藍羅碎，莖抽玉琯端。", "幾聲清淅瀝，一簇綠檀欒。", "未夜青嵐入，先秋白露團。", "拂肩搖翡翠，熨手弄琅玕。", "韻透窗風起，陰鋪砌月殘。", "炎天聞覺冷，窄地見疑寬。", "梢動勝搖扇，枝低好挂冠。", "碧籠煙幕幕，珠灑雨珊珊。", "晚籜晴雲展，陰芽蟄虺蟠。", "愛從抽馬策，惜未截魚竿。", "松韻徒煩聽，桃夭不足觀。", "梁慙當家杏，臺陋本司蘭。", "撐撥詩人興，勾牽酒客歡。", "靜連蘆簟滑，涼拂葛衣單。", "豈止消時暑，應能保歲寒。", "莫同凡草木，一種夏中看。"]'),
('0f44a8e5-f5ba-4ad8-804f-5114b0e5f317','渭村酬李二十見寄','白居易','唐','唐诗','tang','','[]','百里音書何太遲，暮秋把得暮春詩。',64,'全唐诗/poet.tang.22000.json','["百里音書何太遲，暮秋把得暮春詩。", "柳條綠日君相憶，棃葉紅時我始知。", "莫歎學官貧冷落，猶勝村客病支離。", "形容意緒遙看取，不似華陽觀裏時。"]'),
('6d144f4c-3df5-42d7-962c-bdae024e261d','初授贊善大夫早朝寄李二十助教','白居易','唐','唐诗','tang','','[]','病身初謁青宮日，衰貌新垂白髮年。',64,'全唐诗/poet.tang.22000.json','["病身初謁青宮日，衰貌新垂白髮年。", "寂莫曹司非熱地，蕭條風雪是寒天。", "遠坊早起常侵鼓，瘦馬行遲苦費鞭。", "一種共君官職冷，不如猶得日高眠。"]'),
('39aaa65d-42e4-46cd-af9e-2e9b2d956802','欲與元八卜鄰先有是贈','白居易','唐','唐诗','tang','','[]','平生心迹最相親，欲隱牆東不爲身。',64,'全唐诗/poet.tang.22000.json','["平生心迹最相親，欲隱牆東不爲身。", "明月好同三徑夜，綠楊宜作兩家春。", "每因暫出猶思伴，豈得安居不擇鄰。", "何獨終身數相見，子孫長作隔牆人。"]'),
('607e1f98-5d6e-4c0f-81de-f309b22c882f','遊城南留元九李二十晚歸','白居易','唐','唐诗','tang','','[]','老遊春飲莫相違，不獨花稀人亦稀。',32,'全唐诗/poet.tang.22000.json','["老遊春飲莫相違，不獨花稀人亦稀。", "更勸殘杯看日影，猶應趁得鼓聲歸。"]'),
('d5ea6abb-206b-4ae2-8b7a-88e8f30e5343','廣宣上人以應制詩見示因以贈之詔許上人居安國寺紅樓院以詩供奉','白居易','唐','唐诗','tang','','[]','道林談論惠休詩，一到人天便作師。',64,'全唐诗/poet.tang.22000.json','["道林談論惠休詩，一到人天便作師。", "香積筵承紫泥詔，昭陽歌唱碧雲詞。", "紅樓許住請銀鑰，翠輦陪行蹋玉墀。", "惆悵甘泉曾侍從，與君前後不同時。"]'),
('7e5a55aa-7cdd-4002-8a69-6869754f5e7f','重過祕書舊房因題長句','白居易','唐','唐诗','tang','','[]','閣前下馬思裴回，第二房門手自開。',64,'全唐诗/poet.tang.22000.json','["閣前下馬思裴回，第二房門手自開。", "昔爲白面書郎去，今作蒼鬚贊善來。", "吏人不識多新補，松竹相親是舊栽。", "應有題牆名姓在，試將衫袖拂塵埃。"]'),
('26796388-eb6e-4c32-8fa4-6519c9064033','重到城七絕句 見元九','白居易','唐','唐诗','tang','','[]','容貌一日減一日，心情十分無九分。',32,'全唐诗/poet.tang.22000.json','["容貌一日減一日，心情十分無九分。", "每逢陌路猶嗟歎，何況今朝是見君。"]'),
('5b97e361-0652-4cef-85d3-043181f3b9f0','重到城七絕句 高相宅','白居易','唐','唐诗','tang','','[]','青苔故里懷恩地，白髮新生抱病身。',32,'全唐诗/poet.tang.22000.json','["青苔故里懷恩地，白髮新生抱病身。", "涕淚雖多無哭處，永寧門館屬他人。"]'),
('5224e822-abba-4f9d-888e-de26a4b8b3cc','重到城七絕句 張十八','白居易','唐','唐诗','tang','','[]','諫垣幾見遷遺補，憲府頻聞轉殿監。',32,'全唐诗/poet.tang.22000.json','["諫垣幾見遷遺補，憲府頻聞轉殿監。", "獨有詠詩張太祝，十年不改舊官銜。"]'),
('8bb4d0cf-8849-4ca7-9089-15bac9ba3267','重到城七絕句 劉家花','白居易','唐','唐诗','tang','','[]','劉家牆上花還發，李十門前草又春。',32,'全唐诗/poet.tang.22000.json','["劉家牆上花還發，李十門前草又春。", "處處傷心心始悟，多情不及少情人。"]'),
('ebc3d85d-39f0-4519-b71c-260cb78b733c','重到城七絕句 裴五','白居易','唐','唐诗','tang','','[]','莫怪相逢無笑語，感今思舊戟門前。',32,'全唐诗/poet.tang.22000.json','["莫怪相逢無笑語，感今思舊戟門前。", "張家伯仲偏相似，每見清揚一惘然。"]'),
('4ec3d679-67c2-440a-aa7f-aab38ac6c3e3','重到城七絕句 仇家酒','白居易','唐','唐诗','tang','','[]','年年老去歡情少，處處春來感事深。',32,'全唐诗/poet.tang.22000.json','["年年老去歡情少，處處春來感事深。", "時到仇家非愛酒，醉時心勝醒時心。"]'),
('1ffc5c7d-1092-4b09-b831-14792b437fc4','重到城七絕句 恆寂師','白居易','唐','唐诗','tang','','[]','舊遊分散人零落，如此傷心事幾條。',32,'全唐诗/poet.tang.22000.json','["舊遊分散人零落，如此傷心事幾條。", "會逐禪師坐禪去，一時滅盡定中消。"]'),
('5644e203-bc2c-4dba-a58a-d29d0e5be78a','靖安北街贈李二十','白居易','唐','唐诗','tang','','[]','榆莢拋錢柳展眉，兩人竝馬語行遲。',32,'全唐诗/poet.tang.22000.json','["榆莢拋錢柳展眉，兩人竝馬語行遲。", "還似往年安福寺，共君私試却迴時。"]'),
('4a5451f4-2641-4c07-97cd-c7a8b2afb972','重傷小女子','白居易','唐','唐诗','tang','','[]','學人言語凭牀行，嫩似花房脆似瓊。',64,'全唐诗/poet.tang.22000.json','["學人言語凭牀行，嫩似花房脆似瓊。", "纔知恩愛迎三歲，未辨東西過一生。", "汝異下殤應殺禮，吾非上聖詎忘情。", "傷心自歎鳩巢拙，長墮春雛養不成。"]'),
('ba717d99-48a7-4d9c-890f-384c0dafd39d','過顏處士墓','白居易','唐','唐诗','tang','','[]','向墳道徑沒荒榛，滿室詩書積闇塵。',64,'全唐诗/poet.tang.22000.json','["向墳道徑沒荒榛，滿室詩書積闇塵。", "長夜肯教黃壤曉，悲風不許白楊春。", "簞瓢顏子生仍促，布被黔婁死更貧。", "未會悠悠上天意，惜將富壽與何人。"]'),
('812d6cfd-a411-41d1-8ddd-8ba9a3251f5b','題周皓大夫新亭子二十二韻','白居易','唐','唐诗','tang','','[]','東道常爲主，南亭別待賓。',264,'全唐诗/poet.tang.22000.json','["東道常爲主，南亭別待賓。", "規模何日創，景致一時新。", "廣砌羅紅藥，疎窗蔭綠筠。", "鎖開賓閣曉，梯上妓樓春。", "置醴寧三爵，加籩過八珍。", "茶香飄紫筍，膾縷落紅鱗。", "輝赫車輿鬧，珍奇鳥獸馴。", "獼猴看櫪馬，鸚鵡喚家人。", "錦額簾高卷，銀花醆慢巡。", "勸嘗光祿酒，許看洛川神。", "斂翠凝歌黛，流香動舞巾。", "帬飜繡鸂鶒，梳陷鈿麒麟。", "笛怨音含楚，箏嬌語帶秦。", "侍兒催畫燭，醉客吐文茵。", "投轄多連夜，鳴珂便達晨。", "入朝紆紫綬，待漏擁朱輪。", "貴介交三事，光榮照四鄰。", "甘濃將奉客，穩暖不緣身。", "十載歌鐘地，三朝節鉞臣。", "愛才心倜儻，敦舊禮殷勤。", "門以招賢盛，家因好事貧。", "始知豪傑意，富貴爲交親。"]'),
('bae6fbfb-b1e6-4b06-b31d-1f378bba403c','賦得聽邊鴻','白居易','唐','唐诗','tang','','[]','驚風吹起塞鴻羣，半拂平沙半入雲。',32,'全唐诗/poet.tang.22000.json','["驚風吹起塞鴻羣，半拂平沙半入雲。", "爲問昭君月下聽，何如蘇武雪中聞。"]'),
('76457d1c-1c6c-4004-b360-99264de9b6d4','見楊弘貞詩賦因題絕句以自諭','白居易','唐','唐诗','tang','','[]','賦句詩章妙入神，未年三十即無身。',32,'全唐诗/poet.tang.22000.json','["賦句詩章妙入神，未年三十即無身。", "常嗟薄命形顦顇，若比弘貞是幸人。"]'),
('12df34cd-e7ce-4f04-9a1c-bccbdf2beea7','病中早春','白居易','唐','唐诗','tang','','[]','今朝枕上覺頭輕，強起階前試脚行。',64,'全唐诗/poet.tang.22000.json','["今朝枕上覺頭輕，強起階前試脚行。", "羶膩斷來無氣力，風痰惱得少心情。", "暖消霜瓦津初合，寒減冰渠凍不成。", "唯有愁人鬢間雪，不隨春盡逐春生。"]'),
('5b896001-80aa-4294-b01e-9cb59262e700','送人貶信州判官','白居易','唐','唐诗','tang','','[]','地僻山深古上饒，土風貧薄道程遙。',64,'全唐诗/poet.tang.22000.json','["地僻山深古上饒，土風貧薄道程遙。", "不唯遷客須恓屑，見說居人也寂寥。", "溪畔毒沙藏水弩，城頭枯樹下山魈。", "若於此郡爲卑吏，刺史廳前又折腰。"]'),
('16e30743-0747-4459-8d32-6e2ec5973494','曲江醉後贈諸親故','白居易','唐','唐诗','tang','','[]','郭東丘墓何年客，江畔風光幾日春。',64,'全唐诗/poet.tang.22000.json','["郭東丘墓何年客，江畔風光幾日春。", "只合殷勤逐杯酒，不須疎索向交親。", "中天或有長生藥，下界應無不死人。", "除却醉來開口笑，世間何事更關身。"]'),
('876c276a-c0db-410a-a509-6df178ef8a97','和元八侍御升平新居四絕句 看花屋','白居易','唐','唐诗','tang','','[]','忽驚映樹新開屋，却似當檐故種花。',32,'全唐诗/poet.tang.22000.json','["忽驚映樹新開屋，却似當檐故種花。", "可惜年年紅似火，今春始得屬元家。"]'),
('7b85263b-b9a1-4cbd-b6ce-90d33cda12da','和元八侍御升平新居四絕句 累土山','白居易','唐','唐诗','tang','','[]','堆土漸高山意出，終南移入戶庭間。',32,'全唐诗/poet.tang.22000.json','["堆土漸高山意出，終南移入戶庭間。", "玉峰藍水應惆悵，恐見新山望舊山。"]'),
('3814f20d-965f-415d-8448-3eab7b3f51a6','和元八侍御升平新居四絕句 高亭','白居易','唐','唐诗','tang','','[]','亭脊太高君莫拆，東家留取當西山。',32,'全唐诗/poet.tang.22000.json','["亭脊太高君莫拆，東家留取當西山。", "好看落日斜銜處，一片春嵐映半環。"]'),
('bc73dcdb-5250-4285-8365-0308f3060100','和元八侍御升平新居四絕句 松樹','白居易','唐','唐诗','tang','','[]','白金換得青松樹，君既先栽我不栽。',32,'全唐诗/poet.tang.22000.json','["白金換得青松樹，君既先栽我不栽。", "幸有西風易憑仗，夜深偷送好聲來。"]'),
