('74e567ab-47ef-4b3e-9aba-77cbee35aa1b','重寄','白居易','唐','唐诗','tang','','[]','蕭散弓驚雁，分飛劒化龍。',24,'全唐诗/poet.tang.22000.json','["蕭散弓驚雁，分飛劒化龍。", "悠悠天地內，不死會相逢。"]'),
('36a04dff-fd44-4c7d-bab2-77bd86f46c1c','李十一舍人松園飲小酎酒得元八侍御詩敘云在臺中推院有鞫獄之苦即事書懷因酬四韻','白居易','唐','唐诗','tang','','[]','愛酒舍人開小酌，能文御史寄新詩。',64,'全唐诗/poet.tang.22000.json','["愛酒舍人開小酌，能文御史寄新詩。", "亂松園裏醉相憶，古柏廳前忙不知。", "早夏我當逃暑日，晚衙君是慮囚時。", "唯應清夜無公事，新草亭中好一期。"]'),
('cd09198f-11df-4dab-8977-8c545b4db39e','重到華陽觀舊居','白居易','唐','唐诗','tang','','[]','憶昔初年三十二，當時秋思已難堪。',32,'全唐诗/poet.tang.22000.json','["憶昔初年三十二，當時秋思已難堪。", "若爲重入華陽院，病鬢愁心四十三。"]'),
('555b326c-f465-4210-b4f0-526c5491a05e','荅勸酒','白居易','唐','唐诗','tang','','[]','莫怪近來都不飲，幾迴因醉却霑巾。',32,'全唐诗/poet.tang.22000.json','["莫怪近來都不飲，幾迴因醉却霑巾。", "誰料平生狂酒客，如今變作酒悲人。"]'),
('14ce8e49-2d68-4543-b72d-e4bd7ecb3987','題王侍御池亭','白居易','唐','唐诗','tang','','[]','朱門深鎖春池滿，岸落薔薇水浸莎。',32,'全唐诗/poet.tang.22000.json','["朱門深鎖春池滿，岸落薔薇水浸莎。", "畢竟林塘誰是主，主人來少客來多。"]'),
('5d8d628f-c08e-4f0d-982c-95efe6a40a3c','聽水部吳員外新詩因贈絕句','白居易','唐','唐诗','tang','','[]','朱紱仙郎白雪歌，和人雖少愛人多。',32,'全唐诗/poet.tang.22000.json','["朱紱仙郎白雪歌，和人雖少愛人多。", "明朝說與詩人道，水部如今不姓何。"]'),
('baaa3909-b38d-4757-bfea-d031fa0e37d1','雨夜憶元九','白居易','唐','唐诗','tang','','[]','天陰一日便堪愁，何況連宵雨不休。',32,'全唐诗/poet.tang.22000.json','["天陰一日便堪愁，何況連宵雨不休。", "一種雨中君最苦，偏梁閣道向通州。"]'),
('bd8372bf-08e2-42bf-9aff-7e3b5d0399af','雨中攜元九詩訪元八侍御','白居易','唐','唐诗','tang','','[]','微之詩卷憶同開，假日多應不入臺。',32,'全唐诗/poet.tang.22000.json','["微之詩卷憶同開，假日多應不入臺。", "好句無人堪共詠，衝泥蹋水就君來。"]'),
('f0808cd5-9fd9-49d1-af58-6df17fa5802b','贈楊祕書巨源','白居易','唐','唐诗','tang','','[]','早聞一箭取遼城，相識雖新有故情。',64,'全唐诗/poet.tang.22000.json','["早聞一箭取遼城，相識雖新有故情。", "清句三朝誰是敵，白鬚四海半爲兄。", "貧家薙草時時入，瘦馬尋花處處行。", "不用更教詩過好，折君官職是聲名。"]'),
('3ecfca2c-c5d5-4829-8fb4-63903ba66297','和武相公感韋令公舊池孔雀','白居易','唐','唐诗','tang','','[]','索莫少顏色，池邊無主禽。',48,'全唐诗/poet.tang.22000.json','["索莫少顏色，池邊無主禽。", "難收帶泥翅，易結著人心。", "頂毳落殘碧，尾花銷闇金。", "放歸飛不得，雲海故巢深。"]'),
('233af831-6f24-48c0-bc3c-0f44459ef85f','寄生衣與微之因題封上','白居易','唐','唐诗','tang','','[]','淺色縠衫輕似霧，紡花紗袴薄於雲。',32,'全唐诗/poet.tang.22000.json','["淺色縠衫輕似霧，紡花紗袴薄於雲。", "莫嫌輕薄但知著，猶恐通州熱殺君。"]'),
('554c469d-b686-4278-81ef-850108c3a453','白牡丹','白居易','唐','唐诗','tang','','[]','白花冷澹無人愛，亦占芳名道牡丹。',32,'全唐诗/poet.tang.22000.json','["白花冷澹無人愛，亦占芳名道牡丹。", "應似東宮白贊善，被人還喚作朝官。"]'),
('bf33f5b7-bdc3-4aaf-b3a1-090b9ebc0089','夢舊','白居易','唐','唐诗','tang','','[]','別來老大苦修道，鍊得離心成死灰。',32,'全唐诗/poet.tang.22000.json','["別來老大苦修道，鍊得離心成死灰。", "平生憶念消磨盡，昨夜因何入夢來。"]'),
('743667f0-25db-4081-9794-1cb81a5b649c','戲題盧祕書新移薔薇','白居易','唐','唐诗','tang','','[]','風動翠條腰嫋娜，露垂紅萼淚闌干。',32,'全唐诗/poet.tang.22000.json','["風動翠條腰嫋娜，露垂紅萼淚闌干。", "移他到此須爲主，不別花人莫使看。"]'),
('0fec5b0d-3a4d-4609-bc87-cdb36657c54f','曲江夜歸聞元八見訪','白居易','唐','唐诗','tang','','[]','自入臺來見面稀，班中遙得揖容輝。',32,'全唐诗/poet.tang.22000.json','["自入臺來見面稀，班中遙得揖容輝。", "早知相憶來相訪，悔待江頭明月歸。"]'),
('e8dae3d5-aa36-4911-b3ae-6609da96e5b4','苦熱題恆寂師禪室','白居易','唐','唐诗','tang','','[]','人人避暑走如狂，獨有禪師不出房。',32,'全唐诗/poet.tang.22000.json','["人人避暑走如狂，獨有禪師不出房。", "可是禪房無熱到，但能心靜即身涼。"]'),
('4af04ec2-4fde-4a22-8847-3ee2dcb3f527','微之到通州日授館未安見塵壁間有數行字讀之即僕舊詩其落句云淥水紅蓮一朵開千花百草無顏色然不知題者何人也微之吟歎不足因綴一章兼錄僕詩本同寄省其詩乃十五年前初及第時贈長安妓人阿輭絕句緬思往事杳若夢中懷舊感今因酬長句','白居易','唐','唐诗','tang','','[]','十五年前似夢遊，曾將詩句結風流。',64,'全唐诗/poet.tang.22000.json','["十五年前似夢遊，曾將詩句結風流。", "偶助笑歌嘲阿輭，可知傳誦到通州。", "昔教紅袖佳人唱，今遣青衫司馬愁。", "惆悵又聞題處所，雨淋江館破牆頭。"]'),
('484da055-ac5b-43ad-97a2-d5158c9c8ab5','得微之到官後書備知通州之事悵然有感因成四章 一','白居易','唐','唐诗','tang','','[]','來書子細說通州，州在山根峽岸頭。',64,'全唐诗/poet.tang.22000.json','["來書子細說通州，州在山根峽岸頭。", "四面千重火雲合，中心一道瘴江流。", "蟲蛇白晝攔官道，蚊蚋黃昏撲郡樓。", "何罪遣君居此地，天高無處問來由。"]'),
('fd3baf45-b68c-4f2e-89d4-d2b7ba85afc1','得微之到官後書備知通州之事悵然有感因成四章 二','白居易','唐','唐诗','tang','','[]','匼匝巔山萬仞餘，人家應似甑中居。',64,'全唐诗/poet.tang.22000.json','["匼匝巔山萬仞餘，人家應似甑中居。", "寅年籬下多逢虎，亥日沙頭始賣魚。", "衣斑梅雨長須熨，米澀畬田不解鉏。", "努力安心過三考，已曾愁殺李尚書。"]'),
('469541fc-798f-4e96-841d-7805ad3d392b','得微之到官後書備知通州之事悵然有感因成四章 三','白居易','唐','唐诗','tang','','[]','人稀地僻醫巫少，夏旱秋霖瘴瘧多。',64,'全唐诗/poet.tang.22000.json','["人稀地僻醫巫少，夏旱秋霖瘴瘧多。", "老去一身須愛惜，別來四體得如何。", "侏儒飽笑東方朔，薏苡讒憂馬伏波。", "莫遣沈愁結成病，時時一唱濯纓歌。"]'),
('0e1d8586-038c-4508-929a-ba1e4d98a13b','得微之到官後書備知通州之事悵然有感因成四章 四','白居易','唐','唐诗','tang','','[]','通州海內恓惶地，司馬人間冗長官。',64,'全唐诗/poet.tang.22000.json','["通州海內恓惶地，司馬人間冗長官。", "傷鳥有弦驚不定，臥龍無水動應難。", "劒埋獄底誰深掘，松偃霜中盡冷看。", "舉目爭能不惆悵，高車大馬滿長安。"]'),
('c7b84bd0-de0c-4392-b5b6-8290dc25767e','病中荅招飲者','白居易','唐','唐诗','tang','','[]','顧我鏡中悲白髮，盡君花下醉青春。',32,'全唐诗/poet.tang.22000.json','["顧我鏡中悲白髮，盡君花下醉青春。", "不緣眼痛兼身病，可是尊前第二人。"]'),
('d25f80d3-39e0-4a22-9f6a-ea6cec174c6b','燕子樓三首 一','白居易','唐','唐诗','tang','','[]','滿窗明月滿簾霜，被冷燈殘拂臥牀。',32,'全唐诗/poet.tang.22000.json','["滿窗明月滿簾霜，被冷燈殘拂臥牀。", "燕子樓中霜月夜，秋來只爲一人長。"]'),
('970f15b9-e204-4847-b3a3-b041bea2b444','燕子樓三首 二','白居易','唐','唐诗','tang','','[]','鈿暈羅衫色似煙，幾回欲著即潸然。',32,'全唐诗/poet.tang.22000.json','["鈿暈羅衫色似煙，幾回欲著即潸然。", "自從不舞霓裳曲，疊在空箱十一年。"]'),
('38813485-6cdd-48ca-8620-11f4dcc822d6','燕子樓三首 三','白居易','唐','唐诗','tang','','[]','今春有客洛陽回，曾到尚書墓上來。',32,'全唐诗/poet.tang.22000.json','["今春有客洛陽回，曾到尚書墓上來。", "見說白楊堪作柱，爭教紅粉不成灰。"]'),
('dc768485-8f28-4ee8-84ef-a30d3505fd7e','初貶官過望秦嶺','白居易','唐','唐诗','tang','','[]','草草辭家憂後事，遲遲去國問前途。',32,'全唐诗/poet.tang.22000.json','["草草辭家憂後事，遲遲去國問前途。", "望秦嶺上回頭立，無限秋風吹白鬚。"]'),
('82bdecb5-27a0-48a0-88d9-6b128e770299','藍橋驛見元九詩','白居易','唐','唐诗','tang','','[]','藍橋春雪君歸日，秦嶺秋風我去時。',32,'全唐诗/poet.tang.22000.json','["藍橋春雪君歸日，秦嶺秋風我去時。", "每到驛亭先下馬，循牆繞柱覓君詩。"]'),
('cc5fad98-8394-480c-8b1d-676f55559fc7','韓公堆寄元九','白居易','唐','唐诗','tang','','[]','韓公堆北澗西頭，冷雨涼風拂面秋。',32,'全唐诗/poet.tang.22000.json','["韓公堆北澗西頭，冷雨涼風拂面秋。", "努力南行少惆悵，江州猶似勝通州。"]'),
('5843202c-c124-495f-a81b-85c0226f4b40','發商州','白居易','唐','唐诗','tang','','[]','商州館裏停三日，待得妻孥相逐行。',32,'全唐诗/poet.tang.22000.json','["商州館裏停三日，待得妻孥相逐行。", "若比李三猶自勝，兒啼婦哭不聞聲。"]'),
('e2a9164c-f186-4e8a-8636-4701c19e897f','武關南見元九題山石榴見寄','白居易','唐','唐诗','tang','','[]','往來同路不同時，前後相思兩不知。',32,'全唐诗/poet.tang.22000.json','["往來同路不同時，前後相思兩不知。", "行過關門三四里，榴花不見見君詩。"]'),
('517ff7ae-a930-4c4d-a3fc-5798c75ad570','紅鸚鵡','白居易','唐','唐诗','tang','','[]','安南遠進紅鸚鵡，色似桃花語似人。',32,'全唐诗/poet.tang.22000.json','["安南遠進紅鸚鵡，色似桃花語似人。", "文章辯慧皆如此，籠檻何年出得身。"]'),
('03ccdb12-fd90-45ac-a7d1-ef8fbbb24465','題四皓廟','白居易','唐','唐诗','tang','','[]','臥逃秦亂起安劉，舒卷如雲得自由。',32,'全唐诗/poet.tang.22000.json','["臥逃秦亂起安劉，舒卷如雲得自由。", "若有精靈應笑我，不成一事謫江州。"]'),
('1256f876-e915-400b-b306-4c323bfc390c','罷藥','白居易','唐','唐诗','tang','','[]','自學坐禪休服藥，從他時復病沈沈。',32,'全唐诗/poet.tang.22000.json','["自學坐禪休服藥，從他時復病沈沈。", "此身不要全彊健，彊健多生人我心。"]'),
('6ad923b7-896f-4ea6-8440-bb231d4c2bf7','白鷺','白居易','唐','唐诗','tang','','[]','人生四十未全衰，我爲愁多白髮垂。',32,'全唐诗/poet.tang.22000.json','["人生四十未全衰，我爲愁多白髮垂。", "何故水邊雙白鷺，無愁頭上亦垂絲。"]'),
('ae9f57d5-a953-4d5a-b947-11f178c56f61','襄陽舟夜','白居易','唐','唐诗','tang','','[]','下馬襄陽郭，移舟漢陰驛。',36,'全唐诗/poet.tang.22000.json','["下馬襄陽郭，移舟漢陰驛。", "秋風截江起，寒浪連天白。", "本是多愁人，復此風波夕。"]'),
('777a91d8-7915-4cdb-8065-40d1fa6321cd','江夜舟行','白居易','唐','唐诗','tang','','[]','煙澹月濛濛，舟行夜色中。',48,'全唐诗/poet.tang.22000.json','["煙澹月濛濛，舟行夜色中。", "江鋪滿槽水，帆展半檣風。", "叫曙嗸嗸鴈，啼秋唧唧蟲。", "只應催北客，早作白鬚翁。"]'),
('c60ee1e8-110c-421f-aa00-72ca7a28a06a','紅藤杖','白居易','唐','唐诗','tang','','[]','交親過滻別，車馬到江迴。',24,'全唐诗/poet.tang.22000.json','["交親過滻別，車馬到江迴。", "唯有紅藤杖，相隨萬里來。"]'),
('5fff15ec-8eef-48d6-99a4-84994e6772b1','江上吟元八絕句','白居易','唐','唐诗','tang','','[]','大江深處月明時，一夜吟君小律詩。',32,'全唐诗/poet.tang.22000.json','["大江深處月明時，一夜吟君小律詩。", "應有水仙潛出聽，飜將唱作步虛詞。"]'),
('9ae94144-f199-4464-b862-817581348b97','途中感秋','白居易','唐','唐诗','tang','','[]','節物行搖落，年顏坐變衰。',48,'全唐诗/poet.tang.22000.json','["節物行搖落，年顏坐變衰。", "樹初黃葉日，人欲白頭時。", "鄉國程程遠，親朋處處辭。", "唯殘病與老，一步不相離。"]'),
('b972cf6a-7e01-4f8e-aa5c-d1316da5539e','登郢州白雪樓','白居易','唐','唐诗','tang','','[]','白雪樓中一望鄉，青山蔟蔟水茫茫。',32,'全唐诗/poet.tang.22000.json','["白雪樓中一望鄉，青山蔟蔟水茫茫。", "朝來渡口逢京使，說道煙塵近洛陽。"]'),
('db5b6d45-ab39-4b33-b2ed-2125c122d067','舟夜贈內','白居易','唐','唐诗','tang','','[]','三聲猨後垂鄉淚，一葉舟中載病身。',32,'全唐诗/poet.tang.22000.json','["三聲猨後垂鄉淚，一葉舟中載病身。", "莫凭水窗南北望，月明月闇總愁人。"]'),
('1cd654f7-70ac-4753-8418-81a90134313f','逢舊','白居易','唐','唐诗','tang','','[]','我梳白髮添新恨，君埽青蛾減舊容。',32,'全唐诗/poet.tang.22000.json','["我梳白髮添新恨，君埽青蛾減舊容。", "應被傍人怪惆悵，少年離別老相逢。"]'),
('67b018ec-37ca-4b68-a8d5-2f2fbc6c26ff','臼口阻風十日','白居易','唐','唐诗','tang','','[]','洪濤白浪塞江津，處處邅迴事事迍。',64,'全唐诗/poet.tang.22000.json','["洪濤白浪塞江津，處處邅迴事事迍。", "世上方爲失途客，江頭又作阻風人。", "魚鰕遇雨腥盈鼻，蚊蚋和煙癢滿身。", "老大光陰能幾日，等閑臼口坐經旬。"]'),
('f79e1d06-86ce-4cba-b906-b0623d9dfc3e','浦中夜泊','白居易','唐','唐诗','tang','','[]','暗上江隄還獨立，水風霜氣夜稜稜。',32,'全唐诗/poet.tang.22000.json','["暗上江隄還獨立，水風霜氣夜稜稜。", "回看深浦停舟處，蘆荻花中一點燈。"]'),
('ad55996e-9419-4dc2-bb37-05ea1b3287b7','盧侍御與崔評事爲予於黃鶴樓置宴宴罷同望','白居易','唐','唐诗','tang','','["\u9ec4\u9e64\u697c"]','江邊黃鶴古時樓，勞置華筵待我遊。',64,'全唐诗/poet.tang.22000.json','["江邊黃鶴古時樓，勞置華筵待我遊。", "楚思淼茫雲水冷，商聲清脆管弦秋。", "白花浪濺頭陀寺，紅葉林籠鸚鵡洲。", "總是平生未行處，醉來堪賞醒堪愁。"]'),
('1b7dec59-a467-4fc6-878a-ff0a992d7d96','舟中讀元九詩','白居易','唐','唐诗','tang','','["\u601d\u5ff5", "\u5173\u5207"]','把君詩卷燈前讀，詩盡燈殘天未明。',32,'全唐诗/poet.tang.22000.json','["把君詩卷燈前讀，詩盡燈殘天未明。", "眼痛滅燈猶闇坐，逆風吹浪打船聲。"]'),
('867c046c-575c-428c-a034-a9419a366e7b','舟行阻風寄李十一舍人','白居易','唐','唐诗','tang','','[]','扁舟厭泊煙波上，輕策閑尋浦嶼間。',64,'全唐诗/poet.tang.22000.json','["扁舟厭泊煙波上，輕策閑尋浦嶼間。", "虎蹋青泥稠似印，風吹白浪大於山。", "且愁江郡何時到，敢望京都幾歲還。", "今日料君朝退後，迎寒新酎煖開顏。"]'),
('f89f42e3-e2f0-4867-aa33-29d72d2d8500','雨中題衰柳','白居易','唐','唐诗','tang','','[]','濕屈青條折，寒飄黃葉多。',24,'全唐诗/poet.tang.22000.json','["濕屈青條折，寒飄黃葉多。", "不知秋雨意，更遣欲如何。"]'),
('dd254f96-ea36-492d-b8e6-07546d6a4d28','題王處士郊居','白居易','唐','唐诗','tang','','[]','半依雲渚半依山，愛此令人不欲還。',64,'全唐诗/poet.tang.22000.json','["半依雲渚半依山，愛此令人不欲還。", "負郭田園八九頃，向陽茅屋兩三間。", "寒松縱老風標在，野鶴雖飢飲啄閑。", "一臥江村來早晚，著書盈帙鬢毛斑。"]'),
('b482a2e4-0daa-4a28-80a4-f7e6e16e5745','歲晚旅望','白居易','唐','唐诗','tang','','[]','朝來暮去星霜換，陰慘陽舒氣序牽。',64,'全唐诗/poet.tang.22000.json','["朝來暮去星霜換，陰慘陽舒氣序牽。", "萬物秋霜能壞色，四時冬日最凋年。", "煙波半露新沙地，鳥雀羣飛欲雪天。", "向晚蒼蒼南北望，窮陰旅思兩無邊。"]'),
('14d6613e-6558-477f-9415-4d691d219dd9','晏坐閑吟','白居易','唐','唐诗','tang','','[]','昔爲京洛聲華客，今作江湖潦倒翁。',64,'全唐诗/poet.tang.22000.json','["昔爲京洛聲華客，今作江湖潦倒翁。", "意氣銷磨羣動裏，形骸變化百年中。", "霜侵殘鬢無多黑，酒伴衰顏只暫紅。", "願學禪門非想定，千愁萬念一時空。"]'),
('d2d5b055-2f5a-4631-baa6-74eb744700c4','題李山人','白居易','唐','唐诗','tang','','[]','廚無煙火室無妻，籬落蕭條屋舍低。',32,'全唐诗/poet.tang.22000.json','["廚無煙火室無妻，籬落蕭條屋舍低。", "每日將何療飢渴，井華雲粉一刀圭。"]'),
('2b83af6f-0b1f-43d0-b664-67cbef1642ef','讀莊子','白居易','唐','唐诗','tang','','[]','去國辭家謫異方，中心自怪少憂傷。',32,'全唐诗/poet.tang.22000.json','["去國辭家謫異方，中心自怪少憂傷。", "爲尋莊子知歸處，認得無何是本鄉。"]'),
('7b0dce36-e643-47de-acc6-df63e99861b9','江樓偶宴贈同座','白居易','唐','唐诗','tang','','[]','南浦閑行罷，西樓小宴時。',48,'全唐诗/poet.tang.22000.json','["南浦閑行罷，西樓小宴時。", "望湖凭檻久，待月放杯遲。", "江果嘗盧橘，山歌聽竹枝。", "相逢且同樂，何必舊相知。"]'),
('a78362c6-61cc-441c-9320-bcdfffe1d0ed','放言五首 一','白居易','唐','唐诗','tang','','["\u6292\u60c5"]','朝真暮僞何人辨，古往今來底事無。',64,'全唐诗/poet.tang.22000.json','["朝真暮僞何人辨，古往今來底事無。", "但愛臧生能詐聖，可知甯子解佯愚。", "草螢有耀終非火，荷露雖團豈是珠。", "不取燔柴兼照乘，可憐光彩亦何殊。"]'),
('75b50ace-279b-494d-b782-d12543f86edb','放言五首 二','白居易','唐','唐诗','tang','','["\u54f2\u7406"]','世途倚伏都無定，塵網牽纏卒未休。',64,'全唐诗/poet.tang.22000.json','["世途倚伏都無定，塵網牽纏卒未休。", "禍福回還車轉轂，榮枯反覆手藏鉤。", "龜靈未免刳腸患，馬失應無折足憂。", "不信君看弈棊者，輸贏須待局終頭。"]'),
('ed302103-1459-4cc9-9890-4b4bccf19aa9','放言五首 三','白居易','唐','唐诗','tang','','["\u54f2\u7406"]','贈君一法決狐疑，不用鑽龜與祝蓍。',64,'全唐诗/poet.tang.22000.json','["贈君一法決狐疑，不用鑽龜與祝蓍。", "試玉要燒三日滿，辨材須待七年期。", "周公恐懼流言後，王莽謙恭未篡時。", "向使當初身便死，一生真僞復誰知。"]'),
('9edc43ff-921b-4811-8014-f37f828889aa','放言五首 四','白居易','唐','唐诗','tang','','["\u54f2\u7406"]','誰家第宅成還破，何處親賓哭復歌。',64,'全唐诗/poet.tang.22000.json','["誰家第宅成還破，何處親賓哭復歌。", "昨日屋頭堪炙手，今朝門外好張羅。", "北邙未省留閑地，東海何曾有定波。", "莫笑賤貧誇富貴，共成枯骨兩如何。"]'),
('34f06c40-fce8-496a-b80d-2a5f2fa28ec3','放言五首 五','白居易','唐','唐诗','tang','','["\u6cf0\u5c71", "\u54f2\u7406"]','泰山不要欺毫末，顏子無心羨老彭。',64,'全唐诗/poet.tang.22000.json','["泰山不要欺毫末，顏子無心羨老彭。", "松樹千年終是朽，槿花一日自爲榮。", "何須戀世常憂死，亦莫嫌身漫厭生。", "生去死來都是幻，幻人哀樂繫何情。"]'),
('28016a81-cd5b-4bc8-b5dc-79f8f09d8d6d','歲暮道情二首 一','白居易','唐','唐诗','tang','','[]','壯日苦曾驚歲月，長年都不惜光陰。',32,'全唐诗/poet.tang.22000.json','["壯日苦曾驚歲月，長年都不惜光陰。", "爲學空門平等法，先齊老少死生心。"]'),
('ec3cc36d-6ae1-4f04-9201-1eac85d15a08','歲暮道情二首 二','白居易','唐','唐诗','tang','','[]','半故青衫半白頭，雪風吹面上江樓。',32,'全唐诗/poet.tang.22000.json','["半故青衫半白頭，雪風吹面上江樓。", "禪功自見無人覺，合是愁時亦不愁。"]'),
('30bd3981-e0aa-412a-800f-47b2580b0a3f','讀李杜詩集因題卷後','白居易','唐','唐诗','tang','','[]','翰林江左日，員外劒南時。',72,'全唐诗/poet.tang.22000.json','["翰林江左日，員外劒南時。", "不得高官職，仍逢苦亂離。", "暮年逋客恨，浮世謫仙悲。", "吟詠留千古，聲名動四夷。", "文場供秀句，樂府待新詞。", "天意君須會，人間要好詩。"]'),
('ebb2987e-120d-40f6-a187-e7f164effb7e','強酒','白居易','唐','唐诗','tang','','[]','若不坐禪銷妄想，即須行醉放狂歌。',32,'全唐诗/poet.tang.22000.json','["若不坐禪銷妄想，即須行醉放狂歌。", "不然秋月春風夜，爭那閑思往事何。"]'),
('cbbb2a7e-6754-4d24-940c-373fcd77942d','獨樹浦雨夜寄李六郎中','白居易','唐','唐诗','tang','','[]','忽憶兩家同里巷，何曾一處不追隨。',64,'全唐诗/poet.tang.22000.json','["忽憶兩家同里巷，何曾一處不追隨。", "閑遊預算分朝日，靜語多同待漏時。", "花下放狂衝黑飲，燈前起坐徹明棊。", "可知風雨孤舟夜，蘆葦叢中作此詩。"]'),
('dd535dce-eec5-463a-b2df-9118a4285f39','聽崔七妓人箏','白居易','唐','唐诗','tang','','[]','花臉雲鬟坐玉樓，十三弦裏一時愁。',32,'全唐诗/poet.tang.22000.json','["花臉雲鬟坐玉樓，十三弦裏一時愁。", "憑君向道休彈去，白盡江州司馬頭。"]'),
('42c2b2b5-f59d-46ac-8599-1c22e0b0782b','望江州','白居易','唐','唐诗','tang','','[]','江迴望見雙華表，知是潯陽西郭門。',32,'全唐诗/poet.tang.22000.json','["江迴望見雙華表，知是潯陽西郭門。", "猶去孤舟三四里，水煙沙雨欲黃昏。"]'),
('e38fdcaa-f9f2-47ca-a0dc-3c2e81c289d7','初到江州','白居易','唐','唐诗','tang','','[]','潯陽欲到思無窮，庾亮樓南湓口東。',64,'全唐诗/poet.tang.22000.json','["潯陽欲到思無窮，庾亮樓南湓口東。", "樹木凋疎山雨後，人家低濕水煙中。", "菰蔣餧馬行無力，蘆荻編房臥有風。", "遙見朱輪來出郭，相迎勞動使君公。"]'),
('1e67b292-b84e-438f-868e-cc4f80f569ed','醉後題李馬二妓','白居易','唐','唐诗','tang','','[]','行搖雲髻花鈿節，應似霓裳趁管弦。',64,'全唐诗/poet.tang.22000.json','["行搖雲髻花鈿節，應似霓裳趁管弦。", "豔動舞帬渾是火，愁凝歌黛欲生煙。", "有風縱道能迴雪，無水何由忽吐蓮。", "疑是兩般心未決，雨中神女月中仙。"]'),
('0948a7ef-e377-40db-96ad-87b06375fa92','盧侍御小妓乞詩座上留贈','白居易','唐','唐诗','tang','','[]','鬱金香汗裛歌巾，山石榴花染舞帬。',48,'全唐诗/poet.tang.22000.json','["鬱金香汗裛歌巾，山石榴花染舞帬。", "好似文君還對酒，勝於神女不歸雲。", "夢中那及覺時見，宋玉荆王應羨君。"]'),
('34d3b009-d2b6-456e-969f-8b4a0283356b','東南行一百韻寄通州元九侍御澧州李十一舍人果州崔二十二使君開州韋大員外庾三十二補闕杜十四拾遺李二十助教員外竇七校書','白居易','唐','唐诗','tang','','[]','南去經三楚，東來過五湖。',289,'全唐诗/poet.tang.22000.json','["南去經三楚，東來過五湖。", "山頭看候館，水面問征途。", "地遠窮江界，天低極海隅。", "飄零同落葉，浩蕩似乘桴。", "漸覺鄉原異，深知土產殊。", "夷音語嘲异常，蠻態笑睢盱。", "水市通闤闠，煙村混舳艫。", "吏徵漁戶稅，人納火田租。", "亥日饒鰕蟹，寅年足虎貙。", "成人男作丱，事鬼女爲巫。", "樓闇攢倡婦，隄長簇販夫。", "夜船論鋪賃，春酒斷缾酤。", "見果皆盧橘，聞禽悉鷓鴣。", "山歌猨獨叫，野哭鳥相呼。", "嶺徼雲成棧，江郊水當郛。", "月移翹柱鶴，風汎颭檣烏。", "鼇礙潮無信，蛟驚浪不虞。", "鼉鳴江擂鼓，蜃氣海浮圖。", "樹裂山魈穴，沙含水弩樞。", "喘牛犂紫芋，羸馬放青菰。", "繡面誰家婢，鵶頭幾歲奴。", "泥中采菱芡，燒後拾樵蘇。", "鼎膩愁烹鼈，盤腥厭膾鱸。", "鍾儀徒戀楚，張翰浪思吳。"]'),
('649dafe4-d336-4479-b2ce-27ab240fecda','謫居','白居易','唐','唐诗','tang','','[]','面瘦頭斑四十四，遠謫江州爲郡史。',64,'全唐诗/poet.tang.22000.json','["面瘦頭斑四十四，遠謫江州爲郡史。", "逢時棄置從不才，未老衰羸爲何事。", "火燒寒澗松爲燼，霜降春林花委地。", "遭時榮悴一時間，豈是昭昭上天意。"]'),
('e24c83fd-e7b9-4f64-a389-cd65d2c62fe1','初到江州寄翰林張李杜三學士','白居易','唐','唐诗','tang','','[]','早攀霄漢上天衢，晚落風波委世途。',64,'全唐诗/poet.tang.22000.json','["早攀霄漢上天衢，晚落風波委世途。", "雨露施恩無厚薄，蓬蒿隨分有榮枯。", "傷禽側翅驚弓箭，老婦低顏事舅姑。", "碧落三仙曾識面，年深記得姓名無。"]'),
('4d284c4a-e2d7-4e1f-af06-624fbc49c46d','庾樓曉望','白居易','唐','唐诗','tang','','["\u601d\u4e61", "\u5199\u666f", "\u767b\u9ad8"]','獨憑朱檻立凌晨，山色初明水色新。',64,'全唐诗/poet.tang.22000.json','["獨憑朱檻立凌晨，山色初明水色新。", "竹霧曉籠銜嶺月，蘋風暖送過江春。", "子城陰處猶殘雪，衙鼓聲前未有塵。", "三百年來庾樓上，曾經多少望鄉人。"]'),
('5f0933ba-9551-4ad7-b16f-29fb99bd8ac7','宿西林寺','白居易','唐','唐诗','tang','','[]','木落天晴山翠開，愛山騎馬入山來。',32,'全唐诗/poet.tang.22000.json','["木落天晴山翠開，愛山騎馬入山來。", "心知不及柴桑令，一宿西林便却回。"]'),
('9a473fe7-7454-428d-aeca-40b7687f2369','江樓宴別','白居易','唐','唐诗','tang','','[]','樓中別曲催離酌，燈下紅裙間綠袍。',64,'全唐诗/poet.tang.22000.json','["樓中別曲催離酌，燈下紅裙間綠袍。", "縹緲楚風羅綺薄，錚鏦越調管弦高。", "寒流帶月澄如鏡，夕吹和霜利似刀。", "尊酒未空歡未盡，舞腰歌袖莫辭勞。"]'),
('bb590847-46a4-470e-8737-d33e5060b4f4','題山石榴花','白居易','唐','唐诗','tang','','[]','一叢千朵壓闌干，翦碎紅綃却作團。',64,'全唐诗/poet.tang.22000.json','["一叢千朵壓闌干，翦碎紅綃却作團。", "風嫋舞腰香不盡，露銷妝臉淚新乾。", "薔薇帶刺攀應嬾，菡萏生泥玩亦難。", "爭及此花檐戶下，任人采弄盡人看。"]'),
('e90f1c87-f2a3-4976-a582-5a87d2f8395b','代春贈','白居易','唐','唐诗','tang','','[]','山吐晴嵐水放光，辛夷花白柳梢黃。',32,'全唐诗/poet.tang.22000.json','["山吐晴嵐水放光，辛夷花白柳梢黃。", "但知莫作江西意，風景何曾異帝鄉。"]'),
('d753d2ef-7e1e-40da-bc18-403648638967','荅春','白居易','唐','唐诗','tang','','[]','草煙低重水花明，從道風光似帝京。',32,'全唐诗/poet.tang.22000.json','["草煙低重水花明，從道風光似帝京。", "其奈山猨江上叫，故鄉無此斷腸聲。"]'),
('97365e6d-4417-496a-aa71-7f8eaa2d5d4b','櫻桃花下歎白髮','白居易','唐','唐诗','tang','','[]','逐處花皆好，隨年貌自衰。',48,'全唐诗/poet.tang.22000.json','["逐處花皆好，隨年貌自衰。", "紅櫻滿眼日，白髮半頭時。", "倚樹無言久，攀條欲放遲。", "臨風兩堪歎，如雪復如絲。"]'),
('9da82c6a-2569-45f5-a4be-8349b15f0f16','惜落花贈崔二十四','白居易','唐','唐诗','tang','','[]','漠漠紛紛不奈何，狂風急雨兩相和。',32,'全唐诗/poet.tang.22000.json','["漠漠紛紛不奈何，狂風急雨兩相和。", "晚來悵望君知否，枝上稀疎地上多。"]'),
('9b84882b-af34-43dd-9fbc-ef1b90a30d81','移山櫻桃','白居易','唐','唐诗','tang','','[]','亦知官舍非吾宅，且斸山櫻滿院栽。',32,'全唐诗/poet.tang.22000.json','["亦知官舍非吾宅，且斸山櫻滿院栽。", "上佐近來多五考，少應四度見花開。"]'),
('de92b5a4-8307-4276-ac61-ea696a0cc371','官舍閑題','白居易','唐','唐诗','tang','','[]','職散優閑地，身慵老大時。',48,'全唐诗/poet.tang.22000.json','["職散優閑地，身慵老大時。", "送春唯有酒，銷日不過棊。", "祿米麞牙稻，園蔬鴨脚葵。", "飽餐仍晏起，餘暇弄龜兒。"]'),
('5d7ba7de-93e0-4c2f-99d9-976f3a9dea12','晚春登大雲寺南樓贈常禪師','白居易','唐','唐诗','tang','','[]','花盡頭新白，登樓意若何。',48,'全唐诗/poet.tang.22000.json','["花盡頭新白，登樓意若何。", "歲時春日少，世界苦人多。", "愁醉非因酒，悲吟不是歌。", "求師治此病，唯勸讀楞伽。"]'),
('ef511321-15f2-4807-89b4-07ce8e225543','北樓送客歸上都','白居易','唐','唐诗','tang','','[]','憑高眺遠一悽悽，却下朱闌即解攜。',64,'全唐诗/poet.tang.22000.json','["憑高眺遠一悽悽，却下朱闌即解攜。", "京路人歸天直北，江樓客散日平西。", "長津欲度迴渡尾，殘酒重傾簇馬蹄。", "不獨別君須強飲，窮愁自要醉如泥。"]'),
('3dfb6d47-40e9-49e6-a368-5dc717e425e9','北亭招客','白居易','唐','唐诗','tang','','[]','疎散郡丞同野客，幽閑官舍抵山家。',64,'全唐诗/poet.tang.22000.json','["疎散郡丞同野客，幽閑官舍抵山家。", "春風北戶千莖竹，晚日東園一樹花。", "小醆吹醅嘗冷酒，深爐敲火炙新茶。", "能來近日觀棊否，太守知慵放晚衙。"]'),
('a7315b56-63ed-443a-a7f3-ef4cfe11b84d','宿西林寺早赴東林滿上人之會因寄崔二十二員外','白居易','唐','唐诗','tang','','["\u5e90\u5c71"]','謫辭魏闕鵷鸞隔，老入廬山麋鹿隨。',64,'全唐诗/poet.tang.22000.json','["謫辭魏闕鵷鸞隔，老入廬山麋鹿隨。", "薄暮蕭條投寺宿，凌晨清淨與僧期。", "雙林我起聞鐘後，隻日君趨入閣時。", "鵬鷃高低分皆定，莫勞心力遠相思。"]'),
('e29eca4b-cb3d-41f1-81e5-5d3afe9ab97d','遊寶稱寺','白居易','唐','唐诗','tang','','[]','竹寺初晴日，花塘欲曉春。',48,'全唐诗/poet.tang.22000.json','["竹寺初晴日，花塘欲曉春。", "野猨疑弄客，山鳥似呼人。", "酒嫩傾金液，茶新碾玉塵。", "可憐幽靜地，堪寄老慵身。"]'),
('64b01261-1b4c-40d2-b981-8a8b560ff933','早春聞提壺鳥因題鄰家','白居易','唐','唐诗','tang','','[]','厭聽秋猨催下淚，喜聞春鳥勸提壺。',64,'全唐诗/poet.tang.22000.json','["厭聽秋猨催下淚，喜聞春鳥勸提壺。", "誰家紅樹先花發，何處青樓有酒酤。", "進士麄豪尋靜盡，拾遺風采近都無。", "欲期明日東鄰醉，變作騰騰一俗夫。"]'),
('6521c6e2-28fc-49ff-8845-93d307ae1be3','見紫薇花憶微之','白居易','唐','唐诗','tang','','[]','一叢暗澹將何比，淺碧籠帬襯紫巾。',32,'全唐诗/poet.tang.22000.json','["一叢暗澹將何比，淺碧籠帬襯紫巾。", "除却微之見應愛，人間少有別花人。"]'),
('3814a671-10ee-40d9-95e0-d1e2d48fe54e','薔薇花一叢獨死不知其故因有是篇','白居易','唐','唐诗','tang','','[]','柯條未嘗損，根蕟不曾移。',72,'全唐诗/poet.tang.22000.json','["柯條未嘗損，根蕟不曾移。", "同類今齊茂，孤芳忽獨萎。", "仍憐委地日，正是帶花時。", "碎碧初凋葉，燋紅尚戀枝。", "乾坤無厚薄，草木自榮衰。", "欲問因何事，春風亦不知。"]'),
('89cf3ac5-7bba-4442-8f1b-645cf84ac489','湖亭望水','白居易','唐','唐诗','tang','','[]','久雨南湖漲，新晴北客過。',48,'全唐诗/poet.tang.22000.json','["久雨南湖漲，新晴北客過。", "日沈紅有影，風定綠無波。", "岸沒閭閻少，灘平船舫多。", "可憐心賞處，其奈獨遊何。"]'),
('f3c8ce57-bb20-4883-bdb8-5f3b47dc24a9','閑遊','白居易','唐','唐诗','tang','','[]','外事因慵廢，中懷與靜期。',48,'全唐诗/poet.tang.22000.json','["外事因慵廢，中懷與靜期。", "尋泉上山遠，看筍出林遲。", "白石磨樵斧，青竿理釣絲。", "澄清深淺好，最愛夕陽時。"]'),
('85140ae8-d6c7-46cc-901f-fbea77c647e0','憶微之傷仲遠','白居易','唐','唐诗','tang','','[]','幽獨辭羣久，漂流去國賒。',72,'全唐诗/poet.tang.22000.json','["幽獨辭羣久，漂流去國賒。", "只將琴作伴，唯以酒爲家。", "感逝因看水，傷離爲見花。", "李三埋地底，元九謫天涯。", "舉眼青雲遠，回頭白日斜。", "可能勝賈誼，猶自滯長沙。"]'),
('c324846f-0a23-402a-b4d6-a20b9e9dbaf7','過鄭處士','白居易','唐','唐诗','tang','','[]','聞道移居村塢間，竹林多處獨開關。',32,'全唐诗/poet.tang.22000.json','["聞道移居村塢間，竹林多處獨開關。", "故來不是求他事，暫借南亭一望山。"]'),
('96acf8fa-be53-4cb8-988c-2f7924f700bd','霖雨苦多江湖暴漲塊然獨望因題北亭','白居易','唐','唐诗','tang','','[]','自作潯陽客，無如苦雨何。',72,'全唐诗/poet.tang.22000.json','["自作潯陽客，無如苦雨何。", "陰昏晴日少，閑悶睡時多。", "湖闊將天合，雲低與水和。", "籬根舟子語，巷口釣人歌。", "霧島沈黃氣，風帆蹙白波。", "門前車馬道，一宿變江河。"]'),
('822813b7-e1a1-42f1-9da0-366edd6779e3','春末夏初閑遊江郭二首 一','白居易','唐','唐诗','tang','','[]','閑出乘輕屐，徐行蹋輭沙。',72,'全唐诗/poet.tang.22000.json','["閑出乘輕屐，徐行蹋輭沙。", "觀魚傍湓浦，看竹入楊家。", "林迸穿籬筍，藤飄落水花。", "雨埋釣舟小，風颺酒旗斜。", "嫩剝青菱角，濃煎白茗芽。", "淹留不知夕，城樹欲栖鴉。"]'),
('82dab979-e2bd-43cd-b739-b487a16af571','春末夏初閑遊江郭二首 二','白居易','唐','唐诗','tang','','[]','柳影繁初合，鶯聲澀漸稀。',72,'全唐诗/poet.tang.22000.json','["柳影繁初合，鶯聲澀漸稀。", "早梅迎夏結，殘絮送春飛。", "西日韶光盡，南風暑氣微。", "展張新小簟，熨帖舊生衣。", "綠蟻杯香嫩，紅絲膾縷肥。", "故園無此味，何必苦思歸。"]'),
('8953d095-bef2-4238-ae11-19ea6b1c51a9','紅藤杖','白居易','唐','唐诗','tang','','[]','南詔紅藤杖，西江白首人。',72,'全唐诗/poet.tang.22000.json','["南詔紅藤杖，西江白首人。", "時時攜步月，處處把尋春。", "勁健孤莖直，疎圓六節勻。", "火山生處遠，瀘水洗來新。", "粗細纔盈手，高低僅過身。", "天邊望鄉客，何日拄歸秦。"]'),
('c66e55dc-4c6b-48a9-b52c-3acab7618e34','風雨中尋李十一因題船上','白居易','唐','唐诗','tang','','[]','匹馬來郊外，扁舟在水濱。',48,'全唐诗/poet.tang.22000.json','["匹馬來郊外，扁舟在水濱。", "可憐衝雨客，來訪阻風人。", "小榼酤清醑，行廚煮白鱗。", "停杯看柳色，各憶故園春。"]'),
('5011d7b2-a92c-4901-a71a-2bb58e33a369','題廬山山下湯泉','白居易','唐','唐诗','tang','','["\u5e90\u5c71"]','一眼湯泉流向東，浸泥澆草煖無功。',32,'全唐诗/poet.tang.22000.json','["一眼湯泉流向東，浸泥澆草煖無功。", "驪山溫水因何事，流入金鋪玉甃中。"]'),
('7b956b3c-61ae-4a70-8e58-e2af55cc0509','寄蘄州簟與元九因題六韻','白居易','唐','唐诗','tang','','[]','笛竹出蘄春，霜刀劈翠筠。',72,'全唐诗/poet.tang.22000.json','["笛竹出蘄春，霜刀劈翠筠。", "織成雙鎖簟，寄與獨眠人。", "卷作筒中信，舒爲席上珍。", "滑如鋪薤葉，冷似臥龍鱗。", "清潤宜乘露，鮮華不受塵。", "通州炎瘴地，此物最關身。"]'),
('e61250b0-0ed9-4eac-ae61-b9fc8a0f7684','秋熱','白居易','唐','唐诗','tang','','[]','西江風候接南威，暑氣常多秋氣微。',32,'全唐诗/poet.tang.22000.json','["西江風候接南威，暑氣常多秋氣微。", "猶道江州最涼冷，至今九月著生衣。"]'),
('985bd20d-1941-42d2-bf84-5303635f7a75','題元八谿居','白居易','唐','唐诗','tang','','[]','溪嵐漠漠樹重重，水檻山窗次第逢。',64,'全唐诗/poet.tang.22000.json','["溪嵐漠漠樹重重，水檻山窗次第逢。", "晚葉尚開紅躑躅，秋芳初結白芙蓉。", "聲來枕上千年鶴，影落杯中五老峰。", "更媿殷勤留客意，魚鮮飯細酒香濃。"]'),
('6bd3f25c-d4fb-4f43-9555-e942d29e8261','晚出西郊','白居易','唐','唐诗','tang','','[]','散吏閑如客，貧州冷似村。',48,'全唐诗/poet.tang.22000.json','["散吏閑如客，貧州冷似村。", "早涼湖北岸，殘照郭西門。", "嬾鑷從鬚白，休治任眼昏。", "老來何所用，少興不多言。"]'),
('d3759322-e75e-443c-a2f9-0a15daa8b91a','階下蓮','白居易','唐','唐诗','tang','','[]','葉展影飜當砌月，花開香散入簾風。',32,'全唐诗/poet.tang.22000.json','["葉展影飜當砌月，花開香散入簾風。", "不如種在天池上，猶勝生於野水中。"]'),
('9804a6d5-93a6-4454-86db-a1b1969c13c5','端居詠懷','白居易','唐','唐诗','tang','','[]','賈生俟罪心相似，張翰思歸事不如。',64,'全唐诗/poet.tang.22000.json','["賈生俟罪心相似，張翰思歸事不如。", "斜日早知驚鵩鳥，秋風悔不憶鱸魚。", "胷襟曾貯匡時策，懷袖猶殘諫獵書。", "從此萬緣都擺落，欲攜妻子買山居。"]'),
('bf4bac13-4f98-45fc-b2d5-f433b3fa698e','夜宿江浦聞元八改官因寄此什','白居易','唐','唐诗','tang','','[]','君遊丹陛已三遷，我汎滄浪欲二年。',64,'全唐诗/poet.tang.22000.json','["君遊丹陛已三遷，我汎滄浪欲二年。", "劒珮曉趨雙鳳闕，煙波夜宿一漁船。", "交親盡在青雲上，鄉國遙拋白日邊。", "若報生涯應笑殺，結茅栽芋種畬田。"]'),
('2d96c1ac-e222-4afa-aefa-34b42da5895c','百花亭','白居易','唐','唐诗','tang','','[]','朱檻在空虛，涼風八月初。',48,'全唐诗/poet.tang.22000.json','["朱檻在空虛，涼風八月初。", "山形如峴首，江色似桐廬。", "佛寺乘船入，人家枕水居。", "高亭仍有月，今夜宿何如。"]'),
('b2110d36-8655-441b-83fb-63a32e6f0fdc','江樓早秋','白居易','唐','唐诗','tang','','["\u5e90\u5c71"]','南國雖多熱，秋來亦不遲。',72,'全唐诗/poet.tang.22000.json','["南國雖多熱，秋來亦不遲。", "湖光朝霽後，竹氣晚涼時。", "樓閣宜佳客，江山入好詩。", "清風水蘋葉，白露木蘭枝。", "欲作雲泉計，須營伏臘資。", "匡廬一步地，官滿更何之。"]'),
('b02709aa-dd6b-4764-b600-67b1d97e2a58','送客之湖南','白居易','唐','唐诗','tang','','[]','年年漸見南方物，事事堪傷北客情。',64,'全唐诗/poet.tang.22000.json','["年年漸見南方物，事事堪傷北客情。", "山鬼趫跳唯一足，峽猿哀怨過三聲。", "帆開青草湖中去，衣濕黃梅雨裏行。", "別後雙魚難定寄，近來潮不到湓城。"]'),
('a621ca83-2def-47f5-807c-713d40ac2b0a','百花亭晚望夜歸','白居易','唐','唐诗','tang','','[]','百花亭上晚裴回，雲影陰晴掩復開。',64,'全唐诗/poet.tang.22000.json','["百花亭上晚裴回，雲影陰晴掩復開。", "日色悠揚暎山盡，雨聲蕭颯渡江來。", "鬢毛遇病雙如雪，心緒逢秋一似灰。", "向夜欲歸愁未了，滿湖明月小船迴。"]'),
('add5658a-0e8c-4ac2-b8b6-d86467bac247','西樓','白居易','唐','唐诗','tang','','[]','小郡大江邊，危樓夕照前。',48,'全唐诗/poet.tang.22000.json','["小郡大江邊，危樓夕照前。", "青蕪卑濕地，白露泬寥天。", "鄉國此時阻，家書何處傳？", "仍聞陳蔡戍，轉戰已三年。"]'),
('4337c15b-4c7e-4b6e-8a84-0e0c1806f484','尋李道士山居兼呈元明府','白居易','唐','唐诗','tang','','[]','盡日行還歇，遲遲獨上山。',48,'全唐诗/poet.tang.22000.json','["盡日行還歇，遲遲獨上山。", "攀藤老筋力，照水病容顏。", "陶巷招居住，茅家許往還。", "飽諳榮辱事，無意戀人間。"]'),
('e4550960-ded7-4ff2-b699-d62fccfe5357','四十五','白居易','唐','唐诗','tang','','["\u5e90\u5c71"]','行年四十五，兩鬢半蒼蒼。',48,'全唐诗/poet.tang.22000.json','["行年四十五，兩鬢半蒼蒼。", "清瘦詩成癖，粗豪酒放狂。", "老來尤委命，安處即爲鄉。", "或擬廬山下，來春結草堂。"]'),
('d748ec83-83cd-4ff8-8af6-bf6b5f22ca09','寄李相公崔侍郎錢舍人','白居易','唐','唐诗','tang','','[]','曾陪鶴馭兩三仙，親侍龍輿四五年。',64,'全唐诗/poet.tang.22000.json','["曾陪鶴馭兩三仙，親侍龍輿四五年。", "天上歡華春有限，世間漂泊海無邊。", "榮枯事過都成夢，憂喜心忘便是禪。", "官滿更歸何處去，香爐峰在宅門前。"]'),
('97ca629b-5875-4f77-b7cf-bcb0bc45dd91','廳前桂','白居易','唐','唐诗','tang','','[]','天台嶺上凌霜樹，司馬廳前委地叢。',32,'全唐诗/poet.tang.22000.json','["天台嶺上凌霜樹，司馬廳前委地叢。", "一種不生明月裏，山中猶校勝塵中。"]'),
('761a0ac6-307d-421f-a18a-66997697b098','尋王道士藥堂因有題贈','白居易','唐','唐诗','tang','','[]','行行覓路緣松嶠，步步尋花到杏壇。',64,'全唐诗/poet.tang.22000.json','["行行覓路緣松嶠，步步尋花到杏壇。", "白石先生小有洞，黃芽姹女大還丹。", "常悲東郭千家冢，欲乞西山五色丸。", "但恐長生須有籍，仙臺試爲檢名看。"]'),
('401dd560-9b66-4829-93db-1442d928b863','秋晚','白居易','唐','唐诗','tang','','[]','籬菊花稀砌桐落，樹陰離離日色薄。',64,'全唐诗/poet.tang.22000.json','["籬菊花稀砌桐落，樹陰離離日色薄。", "單幕疎簾貧寂莫，涼風冷露秋蕭索。", "光陰流轉忽已晚，顏色凋殘不如昨。", "萊妻臥病月明時，不擣寒衣空擣藥。"]'),
('6bc1faaf-76a2-4868-8938-ea3423f1a2b7','南浦歲暮對酒送王十五歸京','白居易','唐','唐诗','tang','','["\u5e90\u5c71"]','臘後冰生覆湓水，夜來雲闇失廬山。',64,'全唐诗/poet.tang.22000.json','["臘後冰生覆湓水，夜來雲闇失廬山。", "風飄細雪落如米，索索蕭蕭蘆葦間。", "此地二年留我住，今朝一酌送君還。", "相看漸老無過醉，聚散窮通總是閑。"]'),
('93922b94-1754-4664-8857-5e6f0485996a','除夜','白居易','唐','唐诗','tang','','[]','薄晚支頤坐，中宵枕臂眠。',48,'全唐诗/poet.tang.22000.json','["薄晚支頤坐，中宵枕臂眠。", "一從身去國，再見日周天。", "老度江南歲，春拋渭北田。", "潯陽來早晚，明日是三年。"]'),
('ee496564-ffbe-4860-b970-8759ce180734','聞李十一出牧澧州崔二十二出牧果州因寄絕句','白居易','唐','唐诗','tang','','[]','平生相見即眉開，靜念無如李與崔。',32,'全唐诗/poet.tang.22000.json','["平生相見即眉開，靜念無如李與崔。", "各是天涯爲刺史，緣何不覓九江來。"]'),
('77178613-d04c-4d95-8bb3-434254cf03a3','元和十三年淮寇未平詔停歲仗憤然有感率爾成章','白居易','唐','唐诗','tang','','[]','聞停歲仗軫皇情，應爲淮西寇未平。',64,'全唐诗/poet.tang.22000.json','["聞停歲仗軫皇情，應爲淮西寇未平。", "不分氣從歌裏發，無明心向酒中生。", "愚計忽思飛短檄，狂心便欲請長纓。", "從來妄動多如此，自笑何曾得事成。"]'),
('cd3cff71-eb8f-496c-bc0e-5d58fe074c51','庾樓新歲','白居易','唐','唐诗','tang','','[]','歲時銷旅貌，風景觸鄉愁。',24,'全唐诗/poet.tang.22000.json','["歲時銷旅貌，風景觸鄉愁。", "牢落江湖意，新年上庾樓。"]'),
('cfd94a1e-4ae4-4b98-8a08-bc0c1058dcb5','上香爐峰','白居易','唐','唐诗','tang','','["\u5e90\u5c71"]','倚石攀籮歇病身，青笻竹仗白紗巾。',32,'全唐诗/poet.tang.22000.json','["倚石攀籮歇病身，青笻竹仗白紗巾。", "他時畫出廬山障，便是香爐峰上人。"]'),
('2d1fb2ec-f105-4bfa-a2e2-8aa70642b24a','憶微之','白居易','唐','唐诗','tang','','[]','與君何日出屯蒙，魚戀江湖鳥厭籠。',64,'全唐诗/poet.tang.22000.json','["與君何日出屯蒙，魚戀江湖鳥厭籠。", "分手各拋滄海畔，折腰俱老綠衫中。", "三年隔闊音塵斷，兩地飄零氣味同。", "又被新年勸相憶，柳條黃輭欲春風。"]'),
('80e0ff2c-8ed6-493f-9cd5-361663872092','雨夜贈元十八','白居易','唐','唐诗','tang','','[]','卑濕沙頭宅，連陰雨夜天。',48,'全唐诗/poet.tang.22000.json','["卑濕沙頭宅，連陰雨夜天。", "共聽檐溜滴，心事兩悠然。", "把酒循環飲，移牀曲尺眠。", "莫言非故舊，相識已三年。"]'),
('f9616ecd-6e76-4055-a4d0-cf043c07240f','寒食江畔','白居易','唐','唐诗','tang','','[]','草香沙暖水雲晴，風景令人憶帝京。',64,'全唐诗/poet.tang.22000.json','["草香沙暖水雲晴，風景令人憶帝京。", "還似往年春氣味，不宜今日病心情。", "聞鶯樹下沈吟立，信馬江頭取次行。", "忽見紫桐花悵望，下邽明日是清明。"]'),
('b9c46473-4b70-4183-8b3e-2780334ff0f6','三月三日登庾樓寄庾三十二','白居易','唐','唐诗','tang','','[]','三日歡遊辭曲水，二年愁臥在長沙。',32,'全唐诗/poet.tang.22000.json','["三日歡遊辭曲水，二年愁臥在長沙。", "每登高處長相憶，何況茲樓屬庾家。"]'),
('a326ca3e-4c74-4a79-9d10-624d0d4801dc','聞李六景儉自河東令授唐鄧行軍司馬以詩賀之','白居易','唐','唐诗','tang','','[]','誰能淮上靜風波，聞道河東應此科。',64,'全唐诗/poet.tang.22000.json','["誰能淮上靜風波，聞道河東應此科。", "不獨文詞供奏記，定將談笑解兵戈。", "泥埋劒戟終難久，水借蛟龍可在多。", "四十著緋軍司馬，男兒官職未蹉跎。"]'),
('a29e44cd-00b6-47f3-9257-4318fff30637','石榴樹','白居易','唐','唐诗','tang','','[]','可憐顏色好陰涼，葉翦紅牋花撲霜。',66,'全唐诗/poet.tang.22000.json','["可憐顏色好陰涼，葉翦紅牋花撲霜。", "繖蓋低垂金翡翠，熏籠亂搭繡衣裳。", "春芽細炷千燈燄，夏蘂濃焚百[和]香。", "見說上林無此樹，只教桃柳占年芳。"]'),
('f5f726ac-2edd-44c1-bebf-1cc8476fad4c','大林寺桃花','白居易','唐','唐诗','tang','','["\u82b1", "\u5199\u666f", "\u5199\u82b1", "\u690d\u7269"]','人間四月芳菲盡，山寺桃花始盛開。',32,'全唐诗/poet.tang.22000.json','["人間四月芳菲盡，山寺桃花始盛開。", "長恨春歸無覓處，不知轉入此中來。"]'),
('4439ea65-172e-424a-9bb3-68b0959fae15','詠懷','白居易','唐','唐诗','tang','','[]','自從委順任浮沈，漸覺年多功用深。',64,'全唐诗/poet.tang.22000.json','["自從委順任浮沈，漸覺年多功用深。", "面上減除憂喜色，胷中消盡是非心。", "妻兒不問唯耽酒，冠蓋皆慵只抱琴。", "長笑靈均不知命，江蘺叢畔苦悲吟。"]'),
('e5e2484e-2a17-4351-88db-e9684d3573d1','早發楚城驛','白居易','唐','唐诗','tang','','[]','雨過塵埃滅，沿江道徑平。',72,'全唐诗/poet.tang.22000.json','["雨過塵埃滅，沿江道徑平。", "月乘殘夜出，人趁早涼行。", "寂歷閑吟動，冥濛暗思生。", "荷塘飜露氣，稻壟瀉泉聲。", "宿犬聞鈴起，栖禽見火驚。", "曨曨煙樹色，十里始天明。"]'),
('f6b6b4ec-58de-4278-8c78-417834559331','箬峴東池','白居易','唐','唐诗','tang','','[]','箬峴亭東有小池，早荷新荇綠參差。',32,'全唐诗/poet.tang.22000.json','["箬峴亭東有小池，早荷新荇綠參差。", "中宵把火行人發，驚起雙栖白鷺鷥。"]'),
('0195efd1-4268-4383-9e06-67f45793a6ad','建昌江','白居易','唐','唐诗','tang','','[]','建昌江水縣門前，立馬教人喚渡船。',32,'全唐诗/poet.tang.22000.json','["建昌江水縣門前，立馬教人喚渡船。", "忽似往年歸蔡渡，草風沙雨渭河邊。"]'),
('76ccf07b-b4d6-410b-bcd2-f8b6cb98e59e','哭從弟','白居易','唐','唐诗','tang','','[]','傷心一尉便終身，叔母年高新婦貧。',32,'全唐诗/poet.tang.22000.json','["傷心一尉便終身，叔母年高新婦貧。", "一片綠衫消不得，腰金拖紫是何人。"]'),
('3f7279df-ad05-428c-be89-b8824385a416','香爐峰下新卜山居草堂初成偶題東壁','白居易','唐','唐诗','tang','','[]','五架三間新草堂，石階桂柱竹編牆。',64,'全唐诗/poet.tang.22000.json','["五架三間新草堂，石階桂柱竹編牆。", "南檐納日冬天暖，北戶迎風夏月涼。", "灑砌飛泉纔有點，拂窗斜竹不成行。", "來春更葺東廂屋，紙閣蘆簾著孟光。"]'),
('e3883ce5-26ed-4db9-a263-2dddf4de4ba8','重題 一','白居易','唐','唐诗','tang','','[]','喜入山林初息影，厭趨朝市久勞生。',64,'全唐诗/poet.tang.22000.json','["喜入山林初息影，厭趨朝市久勞生。", "早年薄有煙霞志，歲晚深諳世俗情。", "已許虎溪雲裏臥，不爭龍尾道前行。", "從茲耳界應清淨，免見啾啾毀譽聲。"]'),
('f9d19db4-eb31-4e16-aa78-a3ebf6b89aa5','重題 二','白居易','唐','唐诗','tang','','[]','長松樹下小溪頭，班鹿胎巾白布裘。',64,'全唐诗/poet.tang.22000.json','["長松樹下小溪頭，班鹿胎巾白布裘。", "藥圃茶園爲產業，野麋林鶴是交遊。", "雲生澗戶衣裳潤，嵐隱山廚火燭幽。", "最愛一泉新引得，清泠屈曲繞階流。"]'),
('15c0f584-e3f4-413e-a6c2-5bb40a2b737f','重題 三','白居易','唐','唐诗','tang','','["\u5e90\u5c71"]','日高睡足猶慵起，小閣重衾不怕寒。',64,'全唐诗/poet.tang.22000.json','["日高睡足猶慵起，小閣重衾不怕寒。", "遺愛寺鐘欹枕聽，香爐峰雪撥簾看。", "匡廬便是逃名地，司馬仍爲送老官。", "心泰身寧是歸處，故鄉何獨在長安。"]'),
('bbcd667c-130c-4d4e-9a13-ab045b73bad2','重題 四','白居易','唐','唐诗','tang','','[]','宦途自此心長別，世事從今口不言。',64,'全唐诗/poet.tang.22000.json','["宦途自此心長別，世事從今口不言。", "豈止形骸同土木，兼將壽夭任乾坤。", "胷中壯氣猶須遣，身外浮榮何足論。", "還有一條遺恨事，高家門館未酬恩。"]'),
('470a3c60-1f44-4fed-8cc0-3e990c21c080','山中問月','白居易','唐','唐诗','tang','','[]','爲問長安月，誰教不相離。',72,'全唐诗/poet.tang.22000.json','["爲問長安月，誰教不相離。", "昔隨飛蓋處，今照入山時。", "借助秋懷曠，留連夜臥遲。", "如歸舊鄉國，似對好親知。", "松下行爲伴，谿頭坐有期。", "千巖將萬壑，無處不相隨。"]'),
('c6b08353-3068-494d-a351-933db9ae3a7b','正月十五日夜東林寺學禪偶懷藍田楊主簿因呈智禪師','白居易','唐','唐诗','tang','','[]','新年三五東林夕，星漢迢迢鐘梵遲。',64,'全唐诗/poet.tang.22000.json','["新年三五東林夕，星漢迢迢鐘梵遲。", "花縣當君行樂夜，松房是我坐禪時。", "忽看月滿還相憶，始歎春來自不知。", "不覺定中微念起，明朝更問鴈門師。"]'),
('e3c3ba91-4636-4863-b8a9-de9910bada57','臨水坐','白居易','唐','唐诗','tang','','[]','昔爲東掖垣中客，今作西方社內人。',32,'全唐诗/poet.tang.22000.json','["昔爲東掖垣中客，今作西方社內人。", "手把楊枝臨水坐，閑思往事似前身。"]'),
('f3045218-2fe6-49ec-a26a-bfce9dc3a26b','山居','白居易','唐','唐诗','tang','','[]','山齋方獨往，塵事莫相仍。',48,'全唐诗/poet.tang.22000.json','["山齋方獨往，塵事莫相仍。", "藍轝辭鞍馬，緇徒換友朋。", "朝餐唯藥菜，夜伴只紗燈。", "除却青衫在，其餘便是僧。"]'),
('7f2706a9-bfe1-4618-ab0d-c50b32c10350','遺愛寺','白居易','唐','唐诗','tang','','["\u6292\u60c5", "\u5199\u666f"]','弄日臨谿坐，尋花繞寺行。',24,'全唐诗/poet.tang.22000.json','["弄日臨谿坐，尋花繞寺行。", "時時聞鳥語，處處是泉聲。"]'),
('dbbfdddd-99af-47b4-bf51-3dd025bc3797','山中與元九書因題書後','白居易','唐','唐诗','tang','','["\u5e90\u5c71"]','憶昔封書與君夜，金鑾殿後欲明天。',48,'全唐诗/poet.tang.22000.json','["憶昔封書與君夜，金鑾殿後欲明天。", "今夜封書在何處，廬山庵裏晚燈前。", "籠鳥檻猿俱未死，人間相見是何年。"]'),
('5629f4fe-8e88-4d38-8e2f-bd6770e9ee96','黃石巖下作','白居易','唐','唐诗','tang','','[]','久別鵷鸞侶，深隨鳥獸羣。',36,'全唐诗/poet.tang.22000.json','["久別鵷鸞侶，深隨鳥獸羣。", "教他遠親故，何處覓知聞？", "昔日青雲意，今移向白雲。"]'),
('7515bda6-96de-416e-b3ea-691e9648df25','戲贈李十三判官','白居易','唐','唐诗','tang','','["\u5e90\u5c71"]','垂鞭相送醉醺醺，遙見廬山指似君。',32,'全唐诗/poet.tang.22000.json','["垂鞭相送醉醺醺，遙見廬山指似君。", "想君初覺從軍樂，未愛香爐峰上雲。"]'),
('147e96f5-0fc7-4b4d-ad78-3c36fbc88cbc','醉中戲贈鄭使君','白居易','唐','唐诗','tang','','[]','密座移紅毯，酡顏照淥杯。',48,'全唐诗/poet.tang.22000.json','["密座移紅毯，酡顏照淥杯。", "雙娥留且住，五馬任先迴。", "醉耳歌催醒，愁眉笑引開。", "平生少年興，臨老暫重來。"]'),
('524f548b-de66-4b9d-95cb-34f50c1d3135','江亭夕望','白居易','唐','唐诗','tang','','[]','憑高望遠思悠哉，晚上江亭夜未迴。',64,'全唐诗/poet.tang.22000.json','["憑高望遠思悠哉，晚上江亭夜未迴。", "日欲沒時紅浪沸，月初生處白煙開。", "辭枝雪蘂將春去，滿鑷霜毛送老來。", "爭敢三年作歸計，心知不及賈生才。"]'),
('77e25ac8-1e34-4634-bc11-e5e9f75fb67d','酬元員外三月三十日慈恩寺相憶見寄','白居易','唐','唐诗','tang','','[]','悵望慈恩三月盡，紫桐花落鳥關關。',64,'全唐诗/poet.tang.22000.json','["悵望慈恩三月盡，紫桐花落鳥關關。", "誠知曲水春相憶，其奈長沙老未還。", "赤嶺猨聲催白首，黃茅瘴色換朱顏。", "誰言南國無霜雪，盡在愁人鬢髮間。"]'),
('bd8a7069-64a9-4ada-855d-b083598328ae','偶然二首 一','白居易','唐','唐诗','tang','','[]','楚懷邪亂靈均直，放棄合宜何惻惻。',64,'全唐诗/poet.tang.22000.json','["楚懷邪亂靈均直，放棄合宜何惻惻。", "漢文明聖賈生賢，謫向長沙堪歎息。", "人事多端何足怪，天文至信猶差忒。", "月離于畢合滂沱，有時不雨何能測。"]'),
('a7724db5-6f4a-4481-bebb-d1f23b35ac16','偶然二首 二','白居易','唐','唐诗','tang','','[]','火發城頭魚水裏，救火竭池魚失水。',66,'全唐诗/poet.tang.22000.json','["火發城頭魚水裏，救火竭池魚失水。", "乖龍藏在牛[領]中，雷擊龍來牛枉死。", "人道蓍神龜骨靈，試卜魚牛那至此。", "六十四卦七十鑽，畢竟不能知所以。"]'),
('2502008f-3e3f-44be-b6b0-ca781fd515be','中秋月','白居易','唐','唐诗','tang','','[]','萬里清光不可思，添愁益恨繞天涯。',64,'全唐诗/poet.tang.22000.json','["萬里清光不可思，添愁益恨繞天涯。", "誰人隴外久征戍，何處庭前新別離？", "失寵故姬歸院夜，沒蕃老將上樓時。", "照他幾許人腸斷，玉兔銀蟾遠不知。"]'),
('3e2a6b80-7713-4eb1-af64-67bfd3f1d705','謝李六郎中寄新蜀茶','白居易','唐','唐诗','tang','','[]','故情周匝向交親，新茗分張及病身。',64,'全唐诗/poet.tang.22000.json','["故情周匝向交親，新茗分張及病身。", "紅紙一封書後信，綠芽十片火前春。", "湯添勺水煎魚眼，末下刀圭攪麴塵。", "不寄他人先寄我，應緣我是別茶人。"]'),
('68907371-e59e-4d7e-9f18-77259b825333','攜諸山客同上香爐峰遇雨而還霑濡狼籍互相笑謔題此解嘲','白居易','唐','唐诗','tang','','[]','蕭灑登山去，龍鍾遇雨迴。',48,'全唐诗/poet.tang.22000.json','["蕭灑登山去，龍鍾遇雨迴。", "磴危攀薜荔，石滑踐莓苔。", "韤汙君相謔，鞵穿我自咍。", "莫欺泥土脚，曾蹋玉階來。"]'),
('94dae647-be26-47ee-8f87-376641b86951','彭蠡湖晚歸','白居易','唐','唐诗','tang','','["\u6292\u60c5", "\u666f\u70b9"]','彭蠡湖天晚，桃花水氣春。',48,'全唐诗/poet.tang.22000.json','["彭蠡湖天晚，桃花水氣春。", "鳥飛千白點，日沒半紅輪。", "何必爲遷客，無勞是病身。", "但來臨此望，少有不愁人。"]'),
('b84ab8ee-824c-4e77-9fa1-3bd3337d21a5','酬贈李鍊師見招','白居易','唐','唐诗','tang','','[]','幾年司諫直承明，今日求真禮上清。',64,'全唐诗/poet.tang.22000.json','["幾年司諫直承明，今日求真禮上清。", "曾犯龍鱗容不死，欲騎鶴背覓長生。", "劉綱有婦仙同得，伯道無兒累更輕。", "若許移家相近住，便驅雞犬上層城。"]'),
('13ab9d59-6814-44f8-ad21-5772015ddb32','西河雨夜送客','白居易','唐','唐诗','tang','','[]','雲黑雨翛翛，江昏水闇流。',48,'全唐诗/poet.tang.22000.json','["雲黑雨翛翛，江昏水闇流。", "有風催解纜，無月伴登樓。", "酒罷無多興，帆開不少留。", "唯看一點火，遙認是行舟。"]'),
('8809aae3-6d96-42a6-8ce0-c87c3913afb4','登西樓憶行簡','白居易','唐','唐诗','tang','','[]','每因樓上西南望，始覺人間道路長。',64,'全唐诗/poet.tang.22000.json','["每因樓上西南望，始覺人間道路長。", "礙日暮山青蔟蔟，漫天秋水白茫茫。", "風波不見三年面，書信難傳萬里腸。", "早晚東歸來下峽，穩乘船舫過瞿唐。"]'),
('81271a1a-24ce-4c02-a61c-f656db67a430','羅子','白居易','唐','唐诗','tang','','[]','有女名羅子，生來纔兩春。',48,'全唐诗/poet.tang.22000.json','["有女名羅子，生來纔兩春。", "我今年已長，日夜二毛新。", "顧念嬌啼面，思量老病身。", "直應頭似雪，始得見成人。"]'),
('de6fe581-6600-41a0-a22e-727abd365047','讀僧靈徹詩','白居易','唐','唐诗','tang','','[]','東林寺裏西廊下，石片鐫題數首詩。',32,'全唐诗/poet.tang.22000.json','["東林寺裏西廊下，石片鐫題數首詩。", "言句怪來還校別，看名知是老湯師。"]'),
('81e97a91-4e6d-434b-9e34-b96dfb28bfa2','聽李士良琵琶','白居易','唐','唐诗','tang','','[]','聲似胡兒彈舌語，愁如塞月恨邊雲。',32,'全唐诗/poet.tang.22000.json','["聲似胡兒彈舌語，愁如塞月恨邊雲。", "閑人暫聽猶眉斂，可使和蕃公主聞。"]'),
('1c37d3b2-f990-4cee-b255-893e9be92b47','昭君怨','白居易','唐','唐诗','tang','','[]','明妃風貌最娉婷，合在椒房應四星。',64,'全唐诗/poet.tang.22000.json','["明妃風貌最娉婷，合在椒房應四星。", "只得當年備宮掖，何曾專夜奉幃屏。", "見疎從道迷圖畫，知屈那教配虜庭。", "自是君恩薄如紙，不須一向恨丹青。"]'),
('18922750-0af6-4fd1-bc1c-8e3a8b93d757','閑吟','白居易','唐','唐诗','tang','','[]','自從苦學空門法，銷盡平生種種心。',32,'全唐诗/poet.tang.22000.json','["自從苦學空門法，銷盡平生種種心。", "唯有詩魔降未得，每逢風月一閑吟。"]'),
('98bbb2c1-4961-44e7-a1ae-0934d4f0662f','戲問山石榴','白居易','唐','唐诗','tang','','[]','小樹山榴近砌栽，半含紅萼帶花來。',32,'全唐诗/poet.tang.22000.json','["小樹山榴近砌栽，半含紅萼帶花來。", "爭知司馬夫人妬，移到庭前便不開。"]'),
('77500c0a-0e78-4401-a15c-0c74f3bfe67a','編集拙詩成一十五卷因題卷末戲贈元九李二十','白居易','唐','唐诗','tang','','["\u6292\u6000", "\u53cb\u60c5"]','一篇長恨有風情，十首秦吟近正聲。',64,'全唐诗/poet.tang.22000.json','["一篇長恨有風情，十首秦吟近正聲。", "每被老元偷格律，苦教短李伏歌行。", "世間富貴應無分，身後文章合有名。", "莫怪氣粗言語大，新排十五卷詩成。"]'),
('6c87cd7a-1cf9-4eb9-8e3e-4681ff1b8605','湖上閑望','白居易','唐','唐诗','tang','','[]','藤花浪拂紫茸條，菰葉風飜綠剪刀。',32,'全唐诗/poet.tang.22000.json','["藤花浪拂紫茸條，菰葉風飜綠剪刀。", "閑弄水芳生楚思，時時合眼詠離騷。"]'),
('774b34e7-eef6-4332-9a27-1d3bc457a4f9','江南謫居十韻','白居易','唐','唐诗','tang','','[]','自哂沈冥客，曾爲獻納臣。',120,'全唐诗/poet.tang.22000.json','["自哂沈冥客，曾爲獻納臣。", "壯心徒許國，薄命不如人。", "纔展凌雲翅，俄成失水鱗。", "葵枯猶向日，蓬斷即辭春。", "澤畔長愁地，天邊欲老身。", "蕭條殘活計，冷落舊交親。", "草合門無徑，煙消甑有塵。", "憂方知酒聖，貧始覺錢神。", "虎尾難容足，羊腸易覆輪。", "行藏與通塞，一切任陶鈞。"]'),
('844c38f2-4b10-43c2-bab9-b2d20fb39b30','江樓夜吟元九律詩成三十韻','白居易','唐','唐诗','tang','','[]','昨夜江樓上，吟君數十篇。',288,'全唐诗/poet.tang.22000.json','["昨夜江樓上，吟君數十篇。", "詞飄朱檻底，韻墮淥江前。", "清楚音諧律，精微思入玄。", "收將白雪麗，奪盡碧雲妍。", "寸截金爲句，雙雕玉作聯。", "八風淒間發，五彩爛相宣。", "冰扣聲聲冷，珠排字字圓。", "文頭交比繡，筋骨軟於綿。", "澒湧同波浪，錚鏦過管弦。", "醴泉流出地，鈞樂下從天。", "神鬼聞如泣，魚龍聽似禪。", "星迴疑聚集，月落爲留連。", "雁感無鳴者，猨愁亦悄然。", "交流遷客淚，停住賈人船。", "闇被歌姬乞，潛聞思婦傳。", "斜行題粉壁，短卷寫紅箋。", "肉味經時忘，頭風當日痊。", "老張知定伏，短李愛應顛。", "道屈才方振，身閑業始專。", "天教聲烜赫，理合命迍邅。", "顧我文章劣，知他氣力全。", "工夫雖共到，巧拙尚相懸。", "各有詩千首，俱拋海一邊。", "白頭吟處變，青眼望中穿。"]'),
('c126b307-a5b5-4ca5-8bf0-f2dc281d193c','潯陽歲晚寄元八郎中庾三十二員外','白居易','唐','唐诗','tang','','[]','閱水年將暮，燒金道未成。',120,'全唐诗/poet.tang.22000.json','["閱水年將暮，燒金道未成。", "丹砂不肯死，白髮自須生。", "病肺慙杯滿，衰顏忌鏡明。", "春深舊鄉夢，歲晚故交情。", "一別浮雲散，雙瞻列宿榮。", "螭頭階下立，龍尾道前行。", "封事頻聞奏，除書數見名。", "虛懷事僚友，平步取公卿。", "漏盡雞人報，朝迴幼女迎。", "可憐白司馬，老大在湓城。"]'),
('08afd58f-844d-4862-9dc7-1bd76827b0db','元九以綠絲布白輕褣見寄製成衣服以詩報知','白居易','唐','唐诗','tang','','[]','綠絲文布素輕褣，珍重京華手自封。',64,'全唐诗/poet.tang.22000.json','["綠絲文布素輕褣，珍重京華手自封。", "貧友遠勞君寄附，病妻親爲我裁縫。", "袴花白似秋雲薄，衫色青於春草濃。", "欲著却休知不稱，折腰無復舊形容。"]'),
('1e7bba2d-b113-4e16-a249-d88b1d8fbd6f','清明日送韋侍御貶虔州','白居易','唐','唐诗','tang','','[]','寂寞清明日，蕭條司馬家。',48,'全唐诗/poet.tang.22000.json','["寂寞清明日，蕭條司馬家。", "留餳和冷粥，出火煮新茶。", "欲別能無酒，相留亦有花。", "南遷更何處，此地已天涯。"]'),
('876758ef-70c7-4fcd-8747-1df2849f3340','九江春望','白居易','唐','唐诗','tang','','[]','淼茫積水非吾土，飄泊浮萍自我身。',64,'全唐诗/poet.tang.22000.json','["淼茫積水非吾土，飄泊浮萍自我身。", "身外信緣爲活計，眼前隨事覓交親。", "鑪煙豈異終南色，湓草寧殊渭北春。", "此地何妨便終老，譬如元是九江人。"]'),
('99ed4dc5-b915-4fc3-829b-9bbe9c484337','晚題東林寺雙池','白居易','唐','唐诗','tang','','[]','向晚雙池好，初晴百物新。',48,'全唐诗/poet.tang.22000.json','["向晚雙池好，初晴百物新。", "褭枝翻翠羽，濺水躍紅鱗。", "萍汎同遊子，蓮開當麗人。", "臨流一惆悵，還憶曲江春。"]'),
('14197d9d-151b-407c-8999-9ffd8f0bbac5','贈內子','白居易','唐','唐诗','tang','','[]','白髮長興歎，青娥亦伴愁。',48,'全唐诗/poet.tang.22000.json','["白髮長興歎，青娥亦伴愁。", "寒衣補燈下，小女戲牀頭。", "闇澹屏幃故，淒涼枕席秋。", "貧中有等級，猶勝嫁黔婁。"]'),
('f577eb9b-cee3-459c-944d-234d43061766','送客春遊嶺南二十韻','白居易','唐','唐诗','tang','','[]','已訝遊何遠，仍嗟別太頻。',240,'全唐诗/poet.tang.22000.json','["已訝遊何遠，仍嗟別太頻。", "離容君蹙促，贈語我殷勤。", "迢遰天南面，蒼茫海北漘。", "訶陵國分界，交趾郡爲鄰。", "蓊鬱三光晦，溫暾四氣勻。", "陰晴變寒暑，昏曉錯星辰。", "瘴地難爲老，蠻陬不易馴。", "土民稀白首，洞主盡黃巾。", "戰艦猶驚浪，戎車未息塵。", "紅旗圍卉服，紫綬裹文身。", "麪苦桄榔裛，漿酸橄欖新。", "牙檣迎海舶，銅鼓賽江神。", "不凍貪泉暖，無霜毒草春。", "雲煙蟒蛇氣，刀劒鰐魚鱗。", "路足羈棲客，官多謫逐臣。", "天黃生颶母，雨黑長楓人。", "迴使先傳語，征軒早返輪。", "須防杯裏蠱，莫愛橐中珍。", "北與南殊俗，身將貨孰親。", "嘗聞君子誡，憂道不憂貧。"]'),
('14ee2327-fdd6-4c71-91d1-08367b5b96a1','自題','白居易','唐','唐诗','tang','','[]','功名宿昔人多許，寵辱斯須自不如。',64,'全唐诗/poet.tang.22000.json','["功名宿昔人多許，寵辱斯須自不如。", "一旦失恩先左降，三年隨例未量移。", "馬頭覓角生何日，石火敲光住幾時。", "前事是身俱若此，空門不去欲何之。"]'),
('9bc0118e-9f8e-4778-815b-0190138c80b0','自悲','白居易','唐','唐诗','tang','','[]','火宅煎熬地，霜松摧折身。',24,'全唐诗/poet.tang.22000.json','["火宅煎熬地，霜松摧折身。", "因知羣動內，易死不過人。"]'),
('3ba839ae-d335-462b-980a-b1584012051b','尋郭道士不遇','白居易','唐','唐诗','tang','','[]','郡中乞假來相訪，洞裏朝元去不逢。',64,'全唐诗/poet.tang.22000.json','["郡中乞假來相訪，洞裏朝元去不逢。", "看院祗留雙白鶴，入門惟見一青松。", "藥爐有火丹應伏，雲碓無人水自舂。", "欲問參同契中事，更期何日得從容。"]'),
('7e4a33e3-9369-45e2-a358-92489a952703','潯陽春三首 春生','白居易','唐','唐诗','tang','','[]','春生何處闇周遊，海角天涯徧始休。',64,'全唐诗/poet.tang.22000.json','["春生何處闇周遊，海角天涯徧始休。", "先遣和風報消息，續教啼鳥說來由。", "展張草色長河畔，點綴花房小樹頭。", "若到故園應覓我，爲傳淪落在江州。"]'),
('9af4579c-e4a0-41ff-b22a-123f8908bafb','潯陽春三首 春來','白居易','唐','唐诗','tang','','[]','春來觸地故鄉情，忽見風光憶兩京。',64,'全唐诗/poet.tang.22000.json','["春來觸地故鄉情，忽見風光憶兩京。", "金谷蹋花香騎入，曲江碾草鈿車行。", "誰家綠酒歡連夜，何處紅樓睡失明。", "獨有不眠不醉客，經春冷坐古湓城。"]'),
('ab2ffc31-ab68-4178-88b1-bd317a490331','潯陽春三首 春去','白居易','唐','唐诗','tang','','[]','一從澤畔爲遷客，兩度江頭送暮春。',64,'全唐诗/poet.tang.22000.json','["一從澤畔爲遷客，兩度江頭送暮春。", "白髮更添今日鬢，青衫不改去年身。", "百川未有迴流水，一老終無却少人。", "四十六時三月盡，送春爭得不殷勤。"]'),
('02add0b5-8fe7-4920-8f97-ff81b24c4fa2','夢微之','白居易','唐','唐诗','tang','','[]','晨起臨風一惆悵，通川湓水斷相聞。',32,'全唐诗/poet.tang.22000.json','["晨起臨風一惆悵，通川湓水斷相聞。", "不知憶我因何事，昨夜三迴夢見君。"]'),
('824ed317-d044-40fc-8811-b6ab635716f8','贈韋鍊師','白居易','唐','唐诗','tang','','[]','潯陽遷客爲居士，身似浮雲心似灰。',48,'全唐诗/poet.tang.22000.json','["潯陽遷客爲居士，身似浮雲心似灰。", "上界女仙無嗜欲，何因相顧兩裴回。", "共疑過去人間世，曾作誰家夫婦來。"]'),
('9972f7bb-ae5b-49e4-87df-381386af66b6','問劉十九','白居易','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u4e94\u8a00\u7edd\u53e5", "\u751f\u6d3b", "\u996e\u9152", "\u53cb\u60c5"]','綠螘新醅酒，紅泥小火壚。',24,'全唐诗/poet.tang.22000.json','["綠螘新醅酒，紅泥小火壚。", "晚來天欲雪，能飲一杯無。"]'),
('7e871507-9990-491c-a177-798d6094c020','得行簡書聞欲下峽先以詩寄','白居易','唐','唐诗','tang','','["\u957f\u6c5f"]','朝來又得東川信，欲取春初發梓州。',64,'全唐诗/poet.tang.22000.json','["朝來又得東川信，欲取春初發梓州。", "書報九江聞暫喜，路經三峽想還愁。", "瀟湘瘴霧加餐飯，灩澦驚波穩泊舟。", "欲寄兩行迎爾淚，長江不肯向西流。"]'),
('97897a5d-9917-4e93-a4f4-89e4270e9025','南湖早春','白居易','唐','唐诗','tang','','["\u63cf\u5199\u6c34", "\u6625\u5929", "\u5199\u666f", "\u6292\u60c5", "\u5199\u6c34"]','風迴雲斷雨初晴，返照湖邊暖復明。',64,'全唐诗/poet.tang.22000.json','["風迴雲斷雨初晴，返照湖邊暖復明。", "亂點碎紅山杏發，平鋪新綠水蘋生。", "翅低白雁飛仍重，舌澀黃鸝語未成。", "不道江南春不好，年年衰病減心情。"]'),
('f636bb45-eda9-4f6f-be18-8ec5f82ea72f','元十八從事南海欲出廬山臨別舊居有戀泉聲之什因以投和兼伸別情','白居易','唐','唐诗','tang','','["\u5e90\u5c71"]','賢侯辟士禮從容，莫戀泉聲問所從。',64,'全唐诗/poet.tang.22000.json','["賢侯辟士禮從容，莫戀泉聲問所從。", "雨露初承黃紙詔，煙霞欲別紫霄峰。", "傷弓未息新驚鳥，得水難留久臥龍。", "我正退藏君變化，一杯可易得相逢。"]'),
('5883f045-1f80-4c5a-8570-960a997c61c8','題韋家泉池','白居易','唐','唐诗','tang','','[]','泉落青山出白雲，縈村繞郭幾家分。',32,'全唐诗/poet.tang.22000.json','["泉落青山出白雲，縈村繞郭幾家分。", "自從引作池中水，深淺方圓一任君。"]'),
('25d13241-414a-4a80-a9aa-7d4c41e8dd64','醉中對紅葉','白居易','唐','唐诗','tang','','[]','臨風杪秋樹，對酒長年人。',24,'全唐诗/poet.tang.22000.json','["臨風杪秋樹，對酒長年人。", "醉貌如霜葉，雖紅不是春。"]'),
('7bf37dca-3495-4cbf-b831-30d9a048d499','遣懷','白居易','唐','唐诗','tang','','[]','羲和走馭趂年光，不許人間日月長。',64,'全唐诗/poet.tang.22000.json','["羲和走馭趂年光，不許人間日月長。", "遂使四時都似電，爭教兩鬢不成霜。", "榮銷枯去無非命，壯盡衰來亦是常。", "已共身心要約定，窮通生死不驚忙。"]'),
('e0ad553b-a42b-4e76-b0f6-87bde5294748','點額魚','白居易','唐','唐诗','tang','','[]','龍門點額意何如，紅尾青鬐却返初。',32,'全唐诗/poet.tang.22000.json','["龍門點額意何如，紅尾青鬐却返初。", "見說在天行雨苦，爲龍未必勝爲魚。"]'),
('50b4f3d6-41a5-410b-b73a-2fcd3ace71ee','聞龜兒詠詩','白居易','唐','唐诗','tang','','[]','憐渠已解詠詩章，搖膝支頤學二郎。',32,'全唐诗/poet.tang.22000.json','["憐渠已解詠詩章，搖膝支頤學二郎。", "莫學二郎吟太苦，纔年四十鬢如霜。"]'),
('fa33260e-61e3-4cf1-87d1-972857cfd177','對酒','白居易','唐','唐诗','tang','','[]','未濟卦中休卜命，參同契裏莫勞心。',32,'全唐诗/poet.tang.22000.json','["未濟卦中休卜命，參同契裏莫勞心。", "無如飲此銷愁物，一餉愁消直萬金。"]'),
('f7695bbf-bb09-493a-b5ed-ce267733efdb','東牆夜合樹去秋爲風雨所摧今年花時悵然有感','白居易','唐','唐诗','tang','','[]','碧荑紅縷今何在，風雨飄將去不回。',32,'全唐诗/poet.tang.22000.json','["碧荑紅縷今何在，風雨飄將去不回。", "惆悵去年牆下地，今春唯有薺花開。"]'),
('15c70067-d772-491a-8a1c-f1cc09a40c68','病起','白居易','唐','唐诗','tang','','[]','病不出門無限時，今朝強出與誰期。',32,'全唐诗/poet.tang.22000.json','["病不出門無限時，今朝強出與誰期。", "經年不上江樓醉，勞動春風颺酒旗。"]'),
('6306f2e4-9344-4dd5-b44b-7faf84c8d942','夢亡友劉太白同遊彰敬寺','白居易','唐','唐诗','tang','','[]','三千里外臥江州，十五年前哭老劉。',32,'全唐诗/poet.tang.22000.json','["三千里外臥江州，十五年前哭老劉。", "昨夜夢中彰敬寺，死生魂魄暫同遊。"]'),
('6d950cef-da89-4d32-b2bb-7667a1066141','與果上人歿時題此訣別兼簡二林僧社','白居易','唐','唐诗','tang','','[]','本結菩提香火社，爲嫌煩惱電泡身。',32,'全唐诗/poet.tang.22000.json','["本結菩提香火社，爲嫌煩惱電泡身。", "不須惆悵從師去，先請西方作主人。"]'),
('ba3acbe6-e4d9-4e33-b152-e57b43a0f089','贈寫真者','白居易','唐','唐诗','tang','','[]','子騁丹青日，予當醜老時。',48,'全唐诗/poet.tang.22000.json','["子騁丹青日，予當醜老時。", "無勞役神思，更畫病容儀。", "迢遞麒麟閣，圖功未有期。", "區區尺素上，焉用寫真爲。"]'),
('66a99fa4-5242-4372-9c99-3d5a1fac58e0','劉十九同宿','白居易','唐','唐诗','tang','','[]','紅旗破賊非吾事，黃紙除書無我名。',32,'全唐诗/poet.tang.22000.json','["紅旗破賊非吾事，黃紙除書無我名。", "唯共嵩陽劉處士，圍棊賭酒到天明。"]'),
('30ca5f9d-0e0e-4ad1-ab92-e5838694631c','十二年冬江西溫暖喜元八寄金石稜到因題此詩','白居易','唐','唐诗','tang','','[]','今冬臘候不嚴凝，暖霧溫風氣上騰。',48,'全唐诗/poet.tang.22000.json','["今冬臘候不嚴凝，暖霧溫風氣上騰。", "山脚崦中纔有雪，江流慢處亦無冰。", "欲將何藥防春瘴，只有元家金石稜。"]'),
('879b0db4-44f2-40c2-bf75-2ee5f6c7f945','閑意','白居易','唐','唐诗','tang','','[]','不爭榮耀任沈淪，日與時疎共道親。',64,'全唐诗/poet.tang.22000.json','["不爭榮耀任沈淪，日與時疎共道親。", "北省朋僚音信斷，東林長老往還頻。", "病停夜食閑如社，慵擁朝裘暖似春。", "漸老濺諳閑氣味，終身不擬作忙人。"]'),
('11c8685e-44f0-42b3-9d97-af559c8d773a','送友人上峽赴東川辟命','白居易','唐','唐诗','tang','','[]','見說瞿塘峽，斜銜灩澦根。',72,'全唐诗/poet.tang.22000.json','["見說瞿塘峽，斜銜灩澦根。", "難於尋鳥路，險過上龍門。", "羊角風頭急，桃花水色渾。", "山迴若鼇轉，舟入似鯨吞。", "岸合愁天斷，波跳恐地翻。", "憐君經此去，爲感主人恩。"]'),
('6895b115-1b41-4602-9cf5-c6b59ed8ae40','夜送孟司功','白居易','唐','唐诗','tang','','[]','潯陽白司馬，夜送孟功曹。',48,'全唐诗/poet.tang.22000.json','["潯陽白司馬，夜送孟功曹。", "江闇管弦急，樓明燈火高。", "湖波翻似箭，霜草殺如刀。", "且莫開征櫂，陰風正怒號。"]'),
('b2d2ab26-d4dd-4dc0-bb9b-40cff81eefaf','衰病','白居易','唐','唐诗','tang','','[]','老辭遊冶尋花伴，病別荒狂舊酒徒。',32,'全唐诗/poet.tang.22000.json','["老辭遊冶尋花伴，病別荒狂舊酒徒。", "更恐五年三歲後，些些譚笑亦應無。"]'),
('48542e21-ea60-4ced-829b-a9d04a4e1fa8','題詩屏風絕句','白居易','唐','唐诗','tang','','[]','相憶采君詩作障，自書自勘不辭勞。',32,'全唐诗/poet.tang.22000.json','["相憶采君詩作障，自書自勘不辭勞。", "障成定被人爭寫，從此南中紙價高。"]'),
('6b5ee9a9-e629-4f47-9787-ff75de3e5eb8','荅微之','白居易','唐','唐诗','tang','','[]','君寫我詩盈寺壁，我題君句滿屏風。',32,'全唐诗/poet.tang.22000.json','["君寫我詩盈寺壁，我題君句滿屏風。", "與君相遇知何處，兩葉浮萍大海中。"]'),
('7331c724-e098-4760-a87c-2b1fa13c2d5a','偶宴有懷','白居易','唐','唐诗','tang','','[]','遇興尋文客，因歡命酒徒。',48,'全唐诗/poet.tang.22000.json','["遇興尋文客，因歡命酒徒。", "春遊憶親故，夜會似京都。", "詩思閑仍在，鄉愁醉暫無。", "狂來欲起舞，慙見白髭鬚。"]'),
('4d5a6da0-206f-4654-ae5b-353ee86cd2cd','山中酬江州崔使君見寄','白居易','唐','唐诗','tang','','[]','眷眄情無恨，優容禮有餘。',48,'全唐诗/poet.tang.22000.json','["眷眄情無恨，優容禮有餘。", "三年爲郡吏，一半許山居。", "酒熟心相待，詩來手自書。", "庾樓春好醉，明月且回車。"]'),
('d34117d1-2a4d-47d7-96ad-4d380ffe0210','山枇杷','白居易','唐','唐诗','tang','','[]','深山老去惜年華，況對東谿野枇杷。',64,'全唐诗/poet.tang.22000.json','["深山老去惜年華，況對東谿野枇杷。", "火樹風來翻絳燄，瓊枝日出曬紅紗。", "回看桃李都無色，映得芙蓉不是花。", "爭奈結根深石底，無因移得到人家。"]'),
('3f365d15-a922-45b3-9d17-3b15984fd485','聞李尚書拜相因以長句寄賀微之','白居易','唐','唐诗','tang','','[]','憐君不久在通川，知已新提造化權。',64,'全唐诗/poet.tang.22000.json','["憐君不久在通川，知已新提造化權。", "夔卨定求才濟世，張雷應辨氣衝天。", "那知淪落天涯日，正是陶鈞海內年。", "肯向泥中拋折劒，不收重鑄作龍泉。"]'),
('5349017e-b49f-4848-8322-91c844644449','歲暮','白居易','唐','唐诗','tang','','[]','窮陰急景坐相催，壯齒韶顏去不回。',64,'全唐诗/poet.tang.22000.json','["窮陰急景坐相催，壯齒韶顏去不回。", "舊病重因年老發，新愁多是夜長來。", "膏明自爇緣多事，雁默先烹爲不才。", "禍福細尋無會處，不如且進手中杯。"]'),
('d77cd906-d59c-42b4-ae6b-7e49952fb2e6','雨中赴劉十九二林之期及到寺劉已先去因以四韻寄之','白居易','唐','唐诗','tang','','[]','雲中臺殿泥中路，既阻同遊嬾却還。',64,'全唐诗/poet.tang.22000.json','["雲中臺殿泥中路，既阻同遊嬾却還。", "將謂獨愁猶對雨，不知多興已尋山。", "纔應行到千峰裏，只校來遲半日間。", "最惜杜鵑花爛熳，春風吹盡不同攀。"]'),
('84941cd9-2bf2-459b-a86e-8da00543c303','薔薇正開春酒初熟因招劉十九張大夫崔二十四同飲','白居易','唐','唐诗','tang','','[]','甕頭竹葉經春熟，階底薔薇入夏開。',64,'全唐诗/poet.tang.22000.json','["甕頭竹葉經春熟，階底薔薇入夏開。", "似火淺深紅壓架，如餳氣味綠黏臺。", "試將詩句相招去，倘有風情或可來。", "明日早花應更好，心期同醉卯時杯。"]'),
('7c2ac815-b560-49c4-a755-362b2eecba02','李白墓','白居易','唐','唐诗','tang','','["\u5199\u4eba", "\u60bc\u4ea1"]','采石江邊李白墳，遶田無限草連雲。',48,'全唐诗/poet.tang.22000.json','["采石江邊李白墳，遶田無限草連雲。", "可憐荒壠窮泉骨，曾有驚天動地文。", "但是詩人多薄命，就中淪落不過君。"]'),
('aad436c9-6c04-497c-b925-77eb354ff204','對酒','白居易','唐','唐诗','tang','','[]','漫把參同契，難燒伏火砂。',48,'全唐诗/poet.tang.22000.json','["漫把參同契，難燒伏火砂。", "有時成白首，無處問黃芽。", "幻世如泡影，浮生抵眼花。", "唯將綠醅酒，且替紫河車。"]'),
('7158d0ec-d042-44dc-bb57-d7f9efce6247','戲荅諸少年','白居易','唐','唐诗','tang','','[]','顧我長年頭似雪，饒君壯歲氣如雲。',32,'全唐诗/poet.tang.22000.json','["顧我長年頭似雪，饒君壯歲氣如雲。", "朱顏今日雖欺我，白髮他時不放君。"]'),
('069f2deb-b4ec-4ea8-9929-edf1871e4b6d','風雨晚泊','白居易','唐','唐诗','tang','','[]','苦竹林邊蘆葦叢，停舟一望思無窮。',64,'全唐诗/poet.tang.22000.json','["苦竹林邊蘆葦叢，停舟一望思無窮。", "青苔撲地連春雨，白浪掀天盡日風。", "忽忽百年行欲半，茫茫萬事坐成空。", "此生飄蕩何時定，一縷鴻毛天地中。"]'),
('ba297457-d7c2-401e-a172-f5ff83138bbf','題崔使君新樓','白居易','唐','唐诗','tang','','[]','憂人何處可消憂，碧甕紅欄湓水頭。',32,'全唐诗/poet.tang.22000.json','["憂人何處可消憂，碧甕紅欄湓水頭。", "從此潯陽風月夜，崔公樓替庾公樓。"]'),
('aa66d71c-0527-46e9-b1cc-d08016c8cb75','山中戲問韋侍御','白居易','唐','唐诗','tang','','[]','我抱棲雲志，君懷濟世才。',24,'全唐诗/poet.tang.22000.json','["我抱棲雲志，君懷濟世才。", "常吟反招隱，那得入山來。"]'),
('812e131e-eb6a-435a-9756-f8ea5c93d54a','贈曇禪師','白居易','唐','唐诗','tang','','[]','五年不入慈恩寺，今日尋師始一來。',32,'全唐诗/poet.tang.22000.json','["五年不入慈恩寺，今日尋師始一來。", "欲知火宅焚燒苦，方寸如今化作灰。"]'),
('bb387f5d-fcb6-44db-8658-4fe9f244be58','寄微之','白居易','唐','唐诗','tang','','[]','帝城行樂日紛紛，天畔窮愁我與君。',66,'全唐诗/poet.tang.22000.json','["帝城行樂日紛紛，天畔窮愁我與君。", "秦女笑歌春不見，巴猨啼哭夜常聞。", "何處琵琶弦似語，誰家[咼]墮髻如雲。", "人生多少歡娛事，那獨千分無一分。"]'),
('0167d8b4-1f81-4c79-8d56-c1a57e4e7dbe','醉吟二首 一','白居易','唐','唐诗','tang','','[]','空王百法學未得，姹女丹砂燒即飛。',32,'全唐诗/poet.tang.22000.json','["空王百法學未得，姹女丹砂燒即飛。", "事事無成身老也，醉鄉不去欲何歸。"]'),
('b3e985fc-9090-4736-b744-27679a833c3d','醉吟二首 二','白居易','唐','唐诗','tang','','[]','兩鬢千莖新似雪，十分一醆欲如泥。',32,'全唐诗/poet.tang.22000.json','["兩鬢千莖新似雪，十分一醆欲如泥。", "酒狂又引詩魔發，日午悲吟到日西。"]'),
('8f5b9f54-8b1c-4db9-ae06-94f25c12e347','曉寢','白居易','唐','唐诗','tang','','[]','轉枕重安寢，回頭一欠伸。',48,'全唐诗/poet.tang.22000.json','["轉枕重安寢，回頭一欠伸。", "紙窗明覺曉，布被暖知春。", "莫強疎慵性，須安老大身。", "雞鳴一覺睡，不博早朝人。"]'),
('eb2928c7-b8f6-44d2-b86a-c4853b9fa6da','荅元八郎中楊十二博士','白居易','唐','唐诗','tang','','[]','身覺浮雲無所著，心同止水有何情。',64,'全唐诗/poet.tang.22000.json','["身覺浮雲無所著，心同止水有何情。", "但知瀟灑疎朝市，不要崎嶇隱姓名。", "盡日觀魚臨澗坐，有時隨鹿上山行。", "誰能拋得人間事，來共騰騰過此生。"]'),
('83283b10-324c-472e-8a17-bd6bf8e8d093','湖亭與行簡宿','白居易','唐','唐诗','tang','','[]','潯陽少有風情客，招宿湖亭盡却回。',32,'全唐诗/poet.tang.22000.json','["潯陽少有風情客，招宿湖亭盡却回。", "水檻虛涼風月好，夜深誰共阿憐來。"]'),
('1f8e55f9-e589-4bfd-8dcd-40ae58c8e4bb','八月十五日夜湓亭望月','白居易','唐','唐诗','tang','','["\u5b64\u72ec", "\u4e2d\u79cb\u8282", "\u8d2c\u8c2a", "\u4e2d\u79cb", "\u601d\u4e61"]','昔年八月十五夜，曲江池畔杏園邊。',64,'全唐诗/poet.tang.22000.json','["昔年八月十五夜，曲江池畔杏園邊。", "今年八月十五夜，湓浦沙頭水館前。", "西北望鄉何處是，東南見月幾迴圓。", "臨風一歎無人會，今夜清光似往年。"]'),
('06824978-5d50-4300-a304-63ea91fdfeca','贈江客','白居易','唐','唐诗','tang','','[]','江柳影寒新雨地，塞鴻聲急欲霜天。',32,'全唐诗/poet.tang.22000.json','["江柳影寒新雨地，塞鴻聲急欲霜天。", "愁君獨向沙頭宿，水遶蘆花月滿船。"]'),
('3a34dc8d-e6aa-4130-9616-28c12f531874','殘暑招客','白居易','唐','唐诗','tang','','[]','雲截山腰斷，風驅雨脚迴。',48,'全唐诗/poet.tang.22000.json','["雲截山腰斷，風驅雨脚迴。", "早陰江上散，殘熱日中來。", "却取生衣著，重拈竹簟開。", "誰能淘晚熱，閑飲兩三杯。"]'),
('7e197445-4c06-4b2d-9fe6-4e5217654288','潯陽秋懷贈許明府','白居易','唐','唐诗','tang','','[]','霜紅二林葉，風白九江波。',72,'全唐诗/poet.tang.22000.json','["霜紅二林葉，風白九江波。", "暝色投煙鳥，秋聲帶雨荷。", "馬閑無處出，門冷少人過。", "鹵莽還鄉夢，依稀望闕歌。", "共思除醉外，無計奈愁何。", "試問陶家酒，新篘得幾多。"]'),
('6d1db9cd-036a-4a04-896f-e07c31372726','九日醉吟','白居易','唐','唐诗','tang','','[]','有恨頭還白，無情菊自黃。',96,'全唐诗/poet.tang.22000.json','["有恨頭還白，無情菊自黃。", "一爲州司馬，三見歲重陽。", "劒匣塵埃滿，籠禽日月長。", "身從漁父笑，門任雀羅張。", "問疾因留客，聽吟偶置觴。", "歎時論倚伏，懷舊數存亡。", "奈老應無計，治愁或有方。", "無過學王績，唯以醉爲鄉。"]'),
('96897153-b390-4f61-aa6b-cbdb367eb3b6','問韋山人山甫','白居易','唐','唐诗','tang','','[]','身名身事兩蹉跎，試就先生問若何。',32,'全唐诗/poet.tang.22000.json','["身名身事兩蹉跎，試就先生問若何。", "從此神仙學得否，白鬚雖有未爲多。"]'),
('d92569af-16f9-4545-a82a-d5c2eebed9c6','送蕭鍊師步虛詞十首卷後以二絕繼之 一','白居易','唐','唐诗','tang','','[]','欲上瀛州臨別時，贈君十首步虛詞。',32,'全唐诗/poet.tang.22000.json','["欲上瀛州臨別時，贈君十首步虛詞。", "天仙若愛應相問，可道江州司馬詩。"]'),
('885da177-4564-400e-b2e0-0b248ea011b5','送蕭鍊師步虛詞十首卷後以二絕繼之 二','白居易','唐','唐诗','tang','','[]','花紙瑤緘松墨字，把將天上共誰開。',32,'全唐诗/poet.tang.22000.json','["花紙瑤緘松墨字，把將天上共誰開。", "試呈王母如堪唱，發遣雙成更取來。"]'),
('4993c67c-b791-47a1-8c18-a873b8cb399d','贈李兵馬使','白居易','唐','唐诗','tang','','[]','身得貳師餘氣概，家藏都尉舊詩章。',32,'全唐诗/poet.tang.22000.json','["身得貳師餘氣概，家藏都尉舊詩章。", "江南別有樓船將，燕頷虬鬚不姓楊。"]'),
('854c3dcd-7749-41b5-a058-92d5b6589acb','題遺愛寺前溪松','白居易','唐','唐诗','tang','','[]','偃亞長松樹，侵臨小石溪。',96,'全唐诗/poet.tang.22000.json','["偃亞長松樹，侵臨小石溪。", "靜將流水對，高共遠峰齊。", "翠蓋煙籠密，花幢雪壓低。", "與僧清影坐，借鶴穩枝棲。", "筆寫形難似，琴偷韻易迷。", "暑天風槭槭，晴夜露淒淒。", "獨契依爲舍，閑行遶作蹊。", "棟梁君莫採，留著伴幽棲。"]'),
('0a6cfaeb-5597-4192-9df1-014ddaf06389','廬山草堂夜雨獨宿寄牛二李七庾三十二員外','白居易','唐','唐诗','tang','','["\u5e90\u5c71"]','丹霄攜手三君子，白髮垂頭一病翁。',64,'全唐诗/poet.tang.22000.json','["丹霄攜手三君子，白髮垂頭一病翁。", "蘭省花時錦帳下，廬山雨夜草菴中。", "終身膠漆心應在，半路雲泥跡不同。", "唯有無生三昧觀，榮枯一照兩成空。"]'),
('5ac2a6df-2062-4923-8ff2-9cc102c5760e','聞楊十二新拜省郎遙以詩賀','白居易','唐','唐诗','tang','','[]','文昌新入有光輝，紫界宮牆白粉闈。',64,'全唐诗/poet.tang.22000.json','["文昌新入有光輝，紫界宮牆白粉闈。", "曉日雞人傳漏箭，春風侍女護朝衣。", "雪飄歌句高難和，鶴拂煙霄老慣飛。", "官職聲名俱入手，近來詩客似君稀。"]'),
('96209cc2-5434-42f4-950e-6fd6249188da','三月三日懷微之','白居易','唐','唐诗','tang','','[]','良時光景長虛擲，壯歲風情已闇銷。',32,'全唐诗/poet.tang.22000.json','["良時光景長虛擲，壯歲風情已闇銷。", "忽憶同爲校書日，每年同醉是今朝。"]'),
('c98a2e83-2d67-4e39-b6c8-4c043cd7cb9c','贈韋八','白居易','唐','唐诗','tang','','["\u5e90\u5c71"]','辭君歲久見君初，白髮驚嗟兩有餘。',64,'全唐诗/poet.tang.22000.json','["辭君歲久見君初，白髮驚嗟兩有餘。", "容鬢別來今至此，心情料取合何如。", "曾同曲水花亭醉，亦共華陽竹院居。", "豈料天南相見夜，哀猨瘴霧宿匡廬。"]'),
('4e4db3d0-3aaa-4a5d-b981-9c1e0fa3440e','春江閑步贈張山人','白居易','唐','唐诗','tang','','[]','江景又妍和，牽愁發浩歌。',72,'全唐诗/poet.tang.22000.json','["江景又妍和，牽愁發浩歌。", "晴沙金屑色，春水麴塵波。", "紅簇交枝杏，青含卷葉荷。", "藉莎憐輭暖，憩樹愛婆娑。", "書信朝賢斷，知音野老多。", "相逢不閑語，爭奈日長何。"]'),
('960e4335-105b-44d9-a388-616cacfbbe60','春聽琵琶兼簡長孫司戶','白居易','唐','唐诗','tang','','[]','四弦不似琵琶聲，亂寫真珠細撼鈴。',64,'全唐诗/poet.tang.22000.json','["四弦不似琵琶聲，亂寫真珠細撼鈴。", "指底商風悲颯颯，舌頭胡語苦醒醒。", "如言都尉思京國，似訴明妃厭虜庭。", "遷客共君想勸諫，春腸易斷不須聽。"]'),
('2fc4668d-074d-4173-ab58-099c207d6c87','吳宮辭','白居易','唐','唐诗','tang','','[]','一入吳王殿，無人覩翠娥。',48,'全唐诗/poet.tang.22000.json','["一入吳王殿，無人覩翠娥。", "樓高時見舞，宮靜夜聞歌。", "半露胷如雪，斜迴臉似波。", "妍媸各有分，誰敢妬恩多。"]'),
('cc98aeb4-a468-4903-8d47-212044d90b4f','送韋侍御量移金州司馬','白居易','唐','唐诗','tang','','[]','春歡雨露同霑澤，冬歎風霜獨滿衣。',64,'全唐诗/poet.tang.22000.json','["春歡雨露同霑澤，冬歎風霜獨滿衣。", "留滯多時如我少，遷移好處似君稀。", "臥龍雲到須先起，蟄燕雷驚尚未飛。", "莫恨東西溝水別，滄溟長短擬同歸。"]'),
('6c52b31d-acbb-4f8e-93c9-76cdc9fb511a','自到潯陽生三女子因詮真理用遣妄懷','白居易','唐','唐诗','tang','','[]','宦途本自安身拙，世累由來向老多。',64,'全唐诗/poet.tang.22000.json','["宦途本自安身拙，世累由來向老多。", "遠謫四年徒已矣，晚生三女擬如何。", "預愁嫁娶真成患，細念因緣盡是魔。", "賴學空王治苦法，須拋煩惱入頭陀。"]'),
('f41d25ac-e2d9-4de5-9369-9456cc5d5549','江西裴常侍以優禮見待又蒙贈詩輙敘鄙誠用伸感謝','白居易','唐','唐诗','tang','','[]','一從簪笏事金貂，每借溫顏放折腰。',64,'全唐诗/poet.tang.22000.json','["一從簪笏事金貂，每借溫顏放折腰。", "長覺身輕離泥滓，忽驚手重捧瓊瑤。", "馬因迴顧雖增價，桐遇知音已半焦。", "他日秉鈞如見念，壯心直氣未全銷。"]'),
('c2232345-1eea-47ab-b252-bc20d75b246f','自江州司馬授忠州刺史仰荷聖澤聊書鄙誠','白居易','唐','唐诗','tang','','[]','炎瘴拋身遠，泥塗索脚難。',72,'全唐诗/poet.tang.22000.json','["炎瘴拋身遠，泥塗索脚難。", "網初鱗撥剌，籠久翅摧殘。", "雷電頒時令，陽和變歲寒。", "遺簪承舊念，剖竹授新官。", "鄉覺前程近，心隨外事寬。", "生還應有分，西笑問長安。"]'),
('fdc39e64-a590-48f5-8959-845a39d52ec6','除忠州寄謝崔相公','白居易','唐','唐诗','tang','','[]','提拔出泥知力竭，吹噓生翅見情深。',64,'全唐诗/poet.tang.22000.json','["提拔出泥知力竭，吹噓生翅見情深。", "劒鋒缺折難衝斗，桐尾燒焦豈望琴。", "感舊兩行年老淚，酬恩一寸歲寒心。", "忠州好惡何須問，鳥得辭籠不擇林。"]'),
('5106359e-7828-4a8b-b252-46a3210cc985','初除官蒙裴常侍贈鶻銜瑞草緋袍魚袋因謝惠貺兼抒離情','白居易','唐','唐诗','tang','','[]','新授銅符未著緋，因君裝束始光輝。',64,'全唐诗/poet.tang.22000.json','["新授銅符未著緋，因君裝束始光輝。", "惠深范叔綈袍贈，榮過蘇秦佩印歸。", "魚綴白金隨步躍，鶻銜紅綬遶身飛。", "明朝戀別朱門淚，不敢多垂恐汙衣。"]'),
('918bd6c6-e5dd-400c-8373-faf39b3d1daf','洪州逢熊孺登','白居易','唐','唐诗','tang','','[]','靖安院裏辛夷下，醉笑狂吟氣最麤。',32,'全唐诗/poet.tang.22000.json','["靖安院裏辛夷下，醉笑狂吟氣最麤。", "莫問別來多少苦，低頭看取白髭鬚。"]');
